# Centralized path resolution
function Get-AppRootPath {
    if ($script:AppRootPath) { return $script:AppRootPath }
    $script:AppRootPath = if ($PSScriptRoot) {
        $PSScriptRoot | Split-Path -Parent
    } else {
        $PWD.Path
    }
    return $script:AppRootPath
}

