# Current active theme
$script:Theme = $script:DarkTheme

function Set-AppTheme {
    param([string]$ThemeName)
    if ($ThemeName -eq 'Light') {
        $script:Theme = $script:LightTheme
    } else {
        $script:Theme = $script:DarkTheme
    }

    # Persist theme preference
    Save-ThemePreference -ThemeName $ThemeName
}

function Get-AppThemeName {
    <#
    .SYNOPSIS
        Returns the name of the currently active theme ('Dark' or 'Light').
    #>
    if ($script:Theme -eq $script:LightTheme) {
        return 'Light'
    } else {
        return 'Dark'
    }
}

# ============================================================================
# THEME PERSISTENCE
# ============================================================================

function Save-ThemePreference {
    <#
    .SYNOPSIS
        Saves the user's theme preference to settings/theme.json.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$ThemeName
    )

    $scriptRoot = Get-AppRootPath
    $settingsDir = Join-Path -Path $scriptRoot -ChildPath 'settings'
    $settingsFile = Join-Path -Path $settingsDir -ChildPath 'theme.json'

    # Ensure the settings directory exists
    if (-not (Test-Path -Path $settingsDir)) {
        New-Item -Path $settingsDir -ItemType Directory -Force | Out-Null
    }

    $themeData = @{ Theme = $ThemeName } | ConvertTo-Json
    try {
        Set-Content -Path $settingsFile -Value $themeData -Encoding UTF8
    } catch {
        Write-AppLog -Message "Failed to save theme preference: $_" -Level 'WARN'
    }
}

function Load-ThemePreference {
    <#
    .SYNOPSIS
        Loads the user's saved theme preference from settings/theme.json.
        If no saved preference exists, keeps the current (default) theme.
    #>
    $scriptRoot = Get-AppRootPath
    $settingsFile = Join-Path -Path $scriptRoot -ChildPath 'settings' | Join-Path -ChildPath 'theme.json'

    if (Test-Path -Path $settingsFile) {
        try {
            $themeData = Get-Content -Path $settingsFile -Raw | ConvertFrom-Json
            if ($themeData.Theme -eq 'Light') {
                $script:Theme = $script:LightTheme
            } else {
                $script:Theme = $script:DarkTheme
            }
            Write-AppLog -Message "Loaded saved theme preference: $($themeData.Theme)" -Level 'DEBUG'
        } catch {
            Write-AppLog -Message "Failed to load theme preference: $_" -Level 'WARN'
        }
    }
}

# ============================================================================
# RECURSIVE CONTROL THEME UPDATER
# ============================================================================

function Update-ControlTheme {
    <#
    .SYNOPSIS
        Recursively walks a control tree and applies current theme colors
        to all controls based on their type and Tag property.
    .PARAMETER Control
        The root control to begin updating from. Typically the main form.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$Control
    )

    # Update the control based on its type
    switch ($Control.GetType().Name) {
        'Form' {
            $Control.BackColor = $script:Theme.Background
            $Control.ForeColor = $script:Theme.Text
        }

        'Panel' {
            # Determine panel type from Tag or current styling context
            switch ($Control.Tag) {
                'Card' {
                    $Control.BackColor = $script:Theme.CardBackground
                }
                'Nav' {
                    $Control.BackColor = $script:Theme.NavBackground
                }
                'NavSeparator' {
                    $Control.BackColor = $script:Theme.Border
                }
                'Surface' {
                    $Control.BackColor = $script:Theme.Surface
                }
                default {
                    # Check if the panel is acting as a card (has CardBackground-like padding)
                    # or a generic container; preserve transparent panels
                    if ($Control.BackColor -ne [System.Drawing.Color]::Transparent) {
                        $Control.BackColor = $script:Theme.Background
                    }
                }
            }
        }

        'GroupBox' {
            $Control.BackColor = $script:Theme.Surface
            $Control.ForeColor = $script:Theme.Text
        }

        'Label' {
            # Determine label color based on Tag
            switch ($Control.Tag) {
                'Muted' {
                    $Control.ForeColor = $script:Theme.TextMuted
                }
                'Secondary' {
                    $Control.ForeColor = $script:Theme.TextSecondary
                }
                'Primary' {
                    $Control.ForeColor = $script:Theme.Primary
                }
                'Success' {
                    $Control.ForeColor = [System.Drawing.Color]::White
                    $Control.BackColor = $script:Theme.Success
                }
                'Warning' {
                    $Control.ForeColor = [System.Drawing.Color]::White
                    $Control.BackColor = $script:Theme.Warning
                }
                'Error' {
                    $Control.ForeColor = [System.Drawing.Color]::White
                    $Control.BackColor = $script:Theme.Error
                }
                'Info' {
                    $Control.ForeColor = [System.Drawing.Color]::White
                    $Control.BackColor = $script:Theme.Accent
                }
                default {
                    $Control.ForeColor = $script:Theme.Text
                }
            }
        }

        'Button' {
            # Determine button style from Tag (set by New-StyledButton)
            switch ($Control.Tag) {
                'Primary' {
                    $Control.BackColor = $script:Theme.Primary
                    $Control.ForeColor = [System.Drawing.Color]::White
                }
                'Destructive' {
                    $Control.BackColor = $script:Theme.Error
                    $Control.ForeColor = [System.Drawing.Color]::White
                }
                'NavButton' {
                    # Nav buttons are handled separately by Set-ActiveView
                    $Control.FlatAppearance.MouseOverBackColor = $script:Theme.NavHover
                }
                default {
                    $Control.BackColor = $script:Theme.Surface
                    $Control.ForeColor = $script:Theme.Text
                }
            }
            # Update border color if the button has a flat border
            if ($Control.FlatStyle -eq [System.Windows.Forms.FlatStyle]::Flat -and
                $Control.FlatAppearance.BorderSize -gt 0) {
                $Control.FlatAppearance.BorderColor = $script:Theme.Border
            }
        }

        'TextBox' {
            $Control.BackColor = $script:Theme.InputBackground
            # If the textbox is showing placeholder text (ForeColor matches TextMuted),
            # keep it muted; otherwise use normal text color
            if ($Control.Tag -and $Control.Text -eq $Control.Tag) {
                $Control.ForeColor = $script:Theme.TextMuted
            } else {
                $Control.ForeColor = $script:Theme.Text
            }
        }

        'ComboBox' {
            $Control.BackColor = $script:Theme.InputBackground
            $Control.ForeColor = $script:Theme.Text
        }

        'CheckBox' {
            $Control.ForeColor = $script:Theme.Text
        }

        'DataGridView' {
            $dgv = $Control
            $dgv.BackgroundColor = $script:Theme.Surface
            $dgv.GridColor = $script:Theme.Border

            # Default cell style
            $dgv.DefaultCellStyle.BackColor = $script:Theme.Surface
            $dgv.DefaultCellStyle.ForeColor = $script:Theme.Text
            $dgv.DefaultCellStyle.SelectionBackColor = $script:Theme.Primary
            $dgv.DefaultCellStyle.SelectionForeColor = [System.Drawing.Color]::White

            # Column header style
            $dgv.ColumnHeadersDefaultCellStyle.BackColor = $script:Theme.NavBackground
            $dgv.ColumnHeadersDefaultCellStyle.ForeColor = $script:Theme.Text
            $dgv.ColumnHeadersDefaultCellStyle.SelectionBackColor = $script:Theme.NavBackground
            $dgv.ColumnHeadersDefaultCellStyle.SelectionForeColor = $script:Theme.Text

            # Alternating row style
            $dgv.AlternatingRowsDefaultCellStyle.BackColor = $script:Theme.CardBackground
        }
    }

    # Recurse into child controls
    foreach ($child in $Control.Controls) {
        Update-ControlTheme -Control $child
    }
}

function Write-AppLog {
    <#
    .SYNOPSIS
        Writes a timestamped log message to the DISGUISE BUDDY log file.
    .DESCRIPTION
        Appends a formatted log entry with timestamp and severity level to
        logs/disguisebuddy.log relative to the script root directory.
    .PARAMETER Message
        The log message text to write.
    .PARAMETER Level
        The severity level of the log entry. Valid values: INFO, WARN, ERROR, DEBUG.
        Defaults to INFO.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [Parameter(Mandatory = $false)]
        [ValidateSet('INFO', 'WARN', 'ERROR', 'DEBUG')]
        [string]$Level = 'INFO'
    )

    # Determine the script root directory
    # $PSScriptRoot is set when the script is dot-sourced; fall back to current directory
    $scriptRoot = Get-AppRootPath

    $logDir = Join-Path -Path $scriptRoot -ChildPath 'logs'
    $logFile = Join-Path -Path $logDir -ChildPath 'disguisebuddy.log'

    # Ensure the logs directory exists
    if (-not (Test-Path -Path $logDir)) {
        New-Item -Path $logDir -ItemType Directory -Force | Out-Null
    }

    # Log rotation - rotate if over 10MB
    if ((Test-Path $logFile) -and (Get-Item $logFile).Length -gt 10MB) {
        try {
            $archiveName = [System.IO.Path]::GetFileNameWithoutExtension($logFile)
            $archivePath = Join-Path $logDir "$archiveName-$(Get-Date -Format 'yyyyMMdd-HHmmss').log"
            Move-Item -Path $logFile -Destination $archivePath -Force
            # Keep only last 5 archives
            Get-ChildItem $logDir -Filter "$archiveName-*.log" |
                Sort-Object LastWriteTime -Descending |
                Select-Object -Skip 5 |
                Remove-Item -Force -ErrorAction SilentlyContinue
        } catch {
            # If rotation fails, continue writing to current log
        }
    }

    # Format the log entry with timestamp, level, and message
    $timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss.fff'
    $logEntry = "[$timestamp] [$Level] $Message"

    # Append the entry to the log file
    try {
        Add-Content -Path $logFile -Value $logEntry -Encoding UTF8
    } catch {
        # If logging fails, write to console as a fallback
        Write-Warning "Failed to write to log file: $_"
        Write-Warning "Log entry was: $logEntry"
    }
}

# ============================================================
# MODULE: UIComponents.ps1
# ============================================================
# UIComponents.ps1 - DISGUISE BUDDY Reusable UI Component Factories
# All functions reference $script:Theme which is set by Theme.ps1 (dot-sourced first)

function New-StyledButton {
    <#
    .SYNOPSIS
        Creates a flat-style button with theme colors and optional hover effects.
    .NOTES
        The button's Tag property is left free for callers to use (e.g., storing profile names).
        Original BackColor is captured in a closure variable for reliable MouseLeave restoration.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Text,

        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y,

        [int]$Width = 120,
        [int]$Height = 35,
        [switch]$IsPrimary,
        [switch]$IsDestructive,
        [scriptblock]$OnClick
    )

    $button = New-Object System.Windows.Forms.Button
    $button.Text = $Text
    $button.Location = New-Object System.Drawing.Point($X, $Y)
    $button.Size = New-Object System.Drawing.Size($Width, $Height)
    $button.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
    $button.FlatAppearance.BorderSize = 0
    $button.Font = New-Object System.Drawing.Font('Segoe UI', 9.5)
    $button.Cursor = [System.Windows.Forms.Cursors]::Hand
    $button.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left

    if ($IsPrimary) {
        $button.BackColor = $script:Theme.Primary
        $button.ForeColor = [System.Drawing.Color]::White
    } elseif ($IsDestructive) {
        $button.BackColor = $script:Theme.Error
        $button.ForeColor = [System.Drawing.Color]::White
    } else {
        $button.BackColor = $script:Theme.Surface
        $button.ForeColor = $script:Theme.Text
    }

    # Capture style intent for theme-safe MouseLeave restoration
    $styleIsPrimary = [bool]$IsPrimary
    $styleIsDestructive = [bool]$IsDestructive

    # Hover effects - lighten the button on mouse enter
    $button.Add_MouseEnter({
        if ($this.BackColor -eq $script:Theme.Primary) {
            $this.BackColor = $script:Theme.PrimaryLight
        } elseif ($this.BackColor -eq $script:Theme.Error) {
            $r = [Math]::Min(255, $this.BackColor.R + 20)
            $g = [Math]::Min(255, $this.BackColor.G + 20)
            $b = [Math]::Min(255, $this.BackColor.B + 20)
            $this.BackColor = [System.Drawing.Color]::FromArgb($r, $g, $b)
        } else {
            $this.BackColor = $script:Theme.SurfaceLight
        }
    })

    # Restore correct theme color based on style intent (survives theme toggles)
    $button.Add_MouseLeave({
        if ($styleIsPrimary) { $this.BackColor = $script:Theme.Primary }
        elseif ($styleIsDestructive) { $this.BackColor = $script:Theme.Error }
        else { $this.BackColor = $script:Theme.Surface }
    }.GetNewClosure())

    # Tag is intentionally NOT set here - callers are free to use it for their own data
    # (e.g., $btnQuickApply.Tag = $profileName in Dashboard.ps1)

    # Attach click handler if provided
    if ($OnClick) {
        $button.Add_Click($OnClick)
    }

    return $button
}

function New-StyledLabel {
    <#
    .SYNOPSIS
        Creates a themed label with configurable font, color, and optional word wrapping.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Text,

        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y,

        [float]$FontSize = 10,
        [switch]$IsBold,
        [switch]$IsSecondary,
        [switch]$IsMuted,
        [int]$MaxWidth = 0
    )

    $label = New-Object System.Windows.Forms.Label
    $label.Text = $Text
    $label.Location = New-Object System.Drawing.Point($X, $Y)
    $label.AutoSize = $true

    # Font style
    $fontStyle = if ($IsBold) { [System.Drawing.FontStyle]::Bold } else { [System.Drawing.FontStyle]::Regular }
    $label.Font = New-Object System.Drawing.Font('Segoe UI', $FontSize, $fontStyle)

    # Text color based on switches
    if ($IsMuted) {
        $label.ForeColor = $script:Theme.TextMuted
    } elseif ($IsSecondary) {
        $label.ForeColor = $script:Theme.TextSecondary
    } else {
        $label.ForeColor = $script:Theme.Text
    }

    # Word wrapping for constrained width
    if ($MaxWidth -gt 0) {
        $label.AutoSize = $false
        $label.Width = $MaxWidth
        $label.MaximumSize = New-Object System.Drawing.Size($MaxWidth, 0)
        $label.AutoSize = $true
    }

    return $label
}

function New-StyledTextBox {
    <#
    .SYNOPSIS
        Creates a themed text input with optional placeholder text behavior.
    .NOTES
        Placeholder text is stored in the Tag property for callers to detect.
        Callers should check: if ($textBox.Text -eq $textBox.Tag) { treat as empty }
        Or use the helper function: Get-TextBoxValue $textBox
        The placeholder shows in TextMuted color when the field is empty/unfocused,
        and disappears on focus. It reappears if the user clears the field and leaves.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y,

        [int]$Width = 250,
        [int]$Height = 28,
        [string]$PlaceholderText = ""
    )

    $textBox = New-Object System.Windows.Forms.TextBox
    $textBox.Location = New-Object System.Drawing.Point($X, $Y)
    $textBox.Size = New-Object System.Drawing.Size($Width, $Height)
    $textBox.BackColor = $script:Theme.InputBackground
    $textBox.ForeColor = $script:Theme.Text
    $textBox.Font = New-Object System.Drawing.Font('Segoe UI', 10)
    $textBox.BorderStyle = [System.Windows.Forms.BorderStyle]::FixedSingle
    $textBox.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left -bor [System.Windows.Forms.AnchorStyles]::Right

    # Placeholder text behavior
    if ($PlaceholderText -ne "") {
        $textBox.Tag = $PlaceholderText
        $textBox.Text = $PlaceholderText
        $textBox.ForeColor = $script:Theme.TextMuted

        $textBox.Add_GotFocus({
            if ($this.Text -eq $this.Tag) {
                $this.Text = ''
                $this.ForeColor = $script:Theme.Text
            }
        })

        $textBox.Add_LostFocus({
            if ($this.Text -eq '' -or $this.Text -eq $null) {
                $this.Text = $this.Tag
                $this.ForeColor = $script:Theme.TextMuted
            }
        })
    }

    return $textBox
}

function Get-TextBoxValue {
    <#
    .SYNOPSIS
        Returns the actual user-entered value from a styled text box, or empty string
        if the text box is showing placeholder text.
    .DESCRIPTION
        Use this helper to safely retrieve user input from text boxes created with
        New-StyledTextBox -PlaceholderText. It checks whether the current text matches
        the placeholder stored in the Tag property and returns empty string if so.
        This prevents placeholder text from being submitted as actual data.
    .PARAMETER TextBox
        A System.Windows.Forms.TextBox created by New-StyledTextBox.
    .EXAMPLE
        $value = Get-TextBoxValue $myTextBox
        if (-not $value) { Write-Warning "Field is empty" }
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.TextBox]$TextBox
    )

    if ($TextBox.Tag -and $TextBox.Text -eq $TextBox.Tag) {
        return ''
    }
    return $TextBox.Text
}

function New-StyledPanel {
    <#
    .SYNOPSIS
        Creates a themed panel, optionally styled as a card with padding.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y,

        [Parameter(Mandatory = $true)]
        [int]$Width,

        [Parameter(Mandatory = $true)]
        [int]$Height,

        [switch]$IsCard
    )

    $panel = New-Object System.Windows.Forms.Panel
    $panel.Location = New-Object System.Drawing.Point($X, $Y)
    $panel.Size = New-Object System.Drawing.Size($Width, $Height)
    $panel.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left -bor [System.Windows.Forms.AnchorStyles]::Right

    if ($IsCard) {
        $panel.BackColor = $script:Theme.CardBackground
        $panel.Padding = New-Object System.Windows.Forms.Padding(10)
    } else {
        $panel.BackColor = $script:Theme.Background
    }

    return $panel
}

function New-StyledCard {
    <#
    .SYNOPSIS
        Creates a card panel with a bold title label at the top, optional left accent
        border stripe, and consistent internal padding.
        The caller adds additional controls below the title.
    .PARAMETER AccentColor
        Optional accent color for a left border stripe (Material Design style).
        If not provided, no accent stripe is drawn.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Title,

        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y,

        [Parameter(Mandatory = $true)]
        [int]$Width,

        [Parameter(Mandatory = $true)]
        [int]$Height,

        [System.Drawing.Color]$AccentColor = [System.Drawing.Color]::Empty
    )

    $card = New-Object System.Windows.Forms.Panel
    $card.Location = New-Object System.Drawing.Point($X, $Y)
    $card.Size = New-Object System.Drawing.Size($Width, $Height)
    $card.BackColor = $script:Theme.CardBackground
    $card.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left -bor [System.Windows.Forms.AnchorStyles]::Right

    # Internal content offset depends on whether an accent stripe is present
    $contentLeft = 15
    $innerPaddingLeft = 15

    # Left accent border stripe (4px wide colored bar on the left edge)
    if ($AccentColor -ne [System.Drawing.Color]::Empty) {
        $accentStripe = New-Object System.Windows.Forms.Panel
        $accentStripe.Location = New-Object System.Drawing.Point(0, 0)
        $accentStripe.Size = New-Object System.Drawing.Size(4, $Height)
        $accentStripe.BackColor = $AccentColor
        $accentStripe.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left -bor [System.Windows.Forms.AnchorStyles]::Bottom
        $card.Controls.Add($accentStripe)

        # Shift content right to accommodate the accent stripe
        $contentLeft = 19
        $innerPaddingLeft = 19
    }

    # Consistent internal padding (15px on all sides, adjusted for accent)
    $card.Padding = New-Object System.Windows.Forms.Padding($innerPaddingLeft, 15, 15, 15)

    # Subtle border for visual separation (simulates rounded-corner card appearance)
    $card.Add_Paint({
        param($sender, $e)
        $borderPen = New-Object System.Drawing.Pen($script:Theme.Border, 1)
        $rect = New-Object System.Drawing.Rectangle(0, 0, ($sender.Width - 1), ($sender.Height - 1))
        $e.Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
        # Draw rounded rectangle using GraphicsPath for subtle rounded corners
        $radius = 6
        $path = New-Object System.Drawing.Drawing2D.GraphicsPath
        $path.AddArc($rect.X, $rect.Y, $radius, $radius, 180, 90)
        $path.AddArc(($rect.Right - $radius), $rect.Y, $radius, $radius, 270, 90)
        $path.AddArc(($rect.Right - $radius), ($rect.Bottom - $radius), $radius, $radius, 0, 90)
        $path.AddArc($rect.X, ($rect.Bottom - $radius), $radius, $radius, 90, 90)
        $path.CloseFigure()
        $e.Graphics.DrawPath($borderPen, $path)
        $borderPen.Dispose()
        $path.Dispose()
    })

    # Title label at the top of the card
    $titleLabel = New-Object System.Windows.Forms.Label
    $titleLabel.Text = $Title
    $titleLabel.Location = New-Object System.Drawing.Point($contentLeft, 15)
    $titleLabel.AutoSize = $true
    $titleLabel.Font = New-Object System.Drawing.Font('Segoe UI', 11, [System.Drawing.FontStyle]::Bold)
    $titleLabel.ForeColor = $script:Theme.Text

    $card.Controls.Add($titleLabel)

    return $card
}

