# ============================================================================
# BACKEND FUNCTIONS
# ============================================================================

function Test-IPAddressFormat {
    <#
    .SYNOPSIS
        Validates whether a string is a well-formed IPv4 address.
    .DESCRIPTION
        Checks format (4 dotted-decimal octets, each 0-255, no leading zeros)
        and optionally rejects reserved/invalid ranges:
          - 0.x.x.x (current network, invalid as host address)
          - 255.255.255.255 (limited broadcast)
          - 127.x.x.x (loopback - warned but allowed when -AllowReserved is set)
        Use -AllowReserved to permit loopback addresses for testing scenarios.
    .PARAMETER IP
        The string to validate.
    .PARAMETER AllowReserved
        When set, loopback (127.x.x.x) addresses produce a warning but return $true.
        Without this switch, loopback addresses return $false.
    .OUTPUTS
        [bool] $true if the string is a valid IPv4 address, $false otherwise.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$IP,

        [switch]$AllowReserved
    )

    if ([string]::IsNullOrWhiteSpace($IP)) { return $false }

    # Use the .NET parser and ensure it round-trips as IPv4
    $parsed = $null
    if ([System.Net.IPAddress]::TryParse($IP.Trim(), [ref]$parsed)) {
        # Ensure the address is IPv4 and the string representation matches
        # (rejects shorthand like "10.1" that .NET expands to "10.0.0.1")
        if ($parsed.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork) {
            $octets = $IP.Trim().Split('.')
            if ($octets.Count -eq 4) {
                foreach ($octet in $octets) {
                    # Reject leading zeros (e.g., "010") and non-numeric
                    if ($octet -notmatch '^\d{1,3}$') { return $false }
                    $val = [int]$octet
                    if ($val -lt 0 -or $val -gt 255) { return $false }
                    # Reject leading zeros (e.g., "01", "001")
                    if ($octet.Length -gt 1 -and $octet.StartsWith('0')) { return $false }
                }

                # --- Reserved / invalid range checks ---
                $firstOctet = [int]$octets[0]

                # Reject 0.x.x.x (current network / invalid as host)
                if ($firstOctet -eq 0) {
                    return $false
                }

                # Reject 255.255.255.255 (limited broadcast)
                if ($IP.Trim() -eq '255.255.255.255') {
                    return $false
                }

                # Loopback range 127.x.x.x
                if ($firstOctet -eq 127) {
                    if ($AllowReserved) {
                        Write-Warning "IP address '$IP' is in the loopback range (127.x.x.x). Allowed for testing."
                        return $true
                    }
                    return $false
                }

                return $true
            }
        }
    }
    return $false
}

function Test-SubnetMaskFormat {
    <#
    .SYNOPSIS
        Validates whether a string is a valid dotted-decimal subnet mask.
    .DESCRIPTION
        Checks that the mask is a well-formed IPv4 address AND that the binary
        representation is contiguous (a run of 1-bits followed by 0-bits only).
        Invalid / non-contiguous masks like 255.255.128.255 are rejected.
        Uses its own octet parsing rather than Test-IPAddressFormat to avoid
        the reserved-range checks that would reject valid mask octets.
    .PARAMETER Mask
        The subnet mask string (e.g., "255.255.255.0").
    .OUTPUTS
        [bool]
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Mask
    )

    if ([string]::IsNullOrWhiteSpace($Mask)) { return $false }

    # Parse as dotted-decimal: must be exactly 4 numeric octets 0-255
    $octets = $Mask.Trim().Split('.')
    if ($octets.Count -ne 4) { return $false }

    foreach ($octet in $octets) {
        if ($octet -notmatch '^\d{1,3}$') { return $false }
        $val = [int]$octet
        if ($val -lt 0 -or $val -gt 255) { return $false }
        # Reject leading zeros (e.g., "01", "001")
        if ($octet.Length -gt 1 -and $octet.StartsWith('0')) { return $false }
    }

    # Build full 32-bit binary string and verify contiguity
    $binary = ''
    foreach ($octet in $octets) {
        $binary += [Convert]::ToString([int]$octet, 2).PadLeft(8, '0')
    }

    # A valid subnet mask in binary is a contiguous run of 1s followed by 0s.
    # Reject all-zeros (0.0.0.0) as it is not a usable subnet mask.
    if ($binary -eq '00000000000000000000000000000000') { return $false }

    # The regex ensures no '1' appears after the first '0' -- i.e., contiguous.
    return ($binary -match '^1+0*$')
}

function Convert-SubnetMaskToPrefix {
    <#
    .SYNOPSIS
        Converts a dotted-decimal subnet mask to a CIDR prefix length.
    .PARAMETER SubnetMask
        The subnet mask string (e.g., "255.255.255.0").
    .OUTPUTS
        [int] The prefix length (e.g., 24).
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$SubnetMask
    )

    if (-not (Test-SubnetMaskFormat -Mask $SubnetMask)) {
        Write-Warning "Invalid subnet mask: $SubnetMask"
        return -1
    }

    $octets = $SubnetMask.Trim().Split('.')
    $binary = ''
    foreach ($octet in $octets) {
        $binary += [Convert]::ToString([int]$octet, 2).PadLeft(8, '0')
    }

    # Count the number of leading 1-bits
    return ($binary.ToCharArray() | Where-Object { $_ -eq '1' }).Count
}

function Convert-PrefixToSubnetMask {
    <#
    .SYNOPSIS
        Converts a CIDR prefix length to a dotted-decimal subnet mask.
    .PARAMETER PrefixLength
        The prefix length (0-32).
    .OUTPUTS
        [string] The dotted-decimal subnet mask (e.g., "255.255.255.0").
    #>
    param(
        [Parameter(Mandatory = $true)]
        [int]$PrefixLength
    )

    if ($PrefixLength -lt 0 -or $PrefixLength -gt 32) {
        Write-Warning "Prefix length must be between 0 and 32. Got: $PrefixLength"
        return '0.0.0.0'
    }

    $binary = ('1' * $PrefixLength).PadRight(32, '0')
    $octets = @()
    for ($i = 0; $i -lt 4; $i++) {
        $octets += [Convert]::ToInt32($binary.Substring($i * 8, 8), 2)
    }
    return ($octets -join '.')
}

function Get-SystemNetworkAdapters {
    <#
    .SYNOPSIS
        Returns all physical network adapters on the system.
    .DESCRIPTION
        Uses Get-NetAdapter (Windows only) to enumerate physical adapters,
        filtering out virtual/Hyper-V/VPN adapters. Returns an array of
        objects with adapter metadata.
    .OUTPUTS
        [array] Each element is a PSCustomObject with: Name, InterfaceIndex,
        MacAddress, Status, LinkSpeed.
    #>

    $adapters = @()

    try {
        # Get-NetAdapter is available on Windows 8+ / Server 2012+
        $raw = Get-NetAdapter -Physical -ErrorAction Stop |
            Where-Object {
                # Exclude common virtual adapter patterns
                $_.InterfaceDescription -notmatch 'Hyper-V|Virtual|VPN|Loopback|WAN Miniport|Bluetooth'
            } |
            Sort-Object -Property InterfaceIndex

        foreach ($nic in $raw) {
            $adapters += [PSCustomObject]@{
                Name           = $nic.Name
                InterfaceIndex = $nic.InterfaceIndex
                MacAddress     = $nic.MacAddress
                Status         = $nic.Status            # Up, Disconnected, etc.
                LinkSpeed      = $nic.LinkSpeed          # e.g., "1 Gbps"
                Description    = $nic.InterfaceDescription
            }
        }

        Write-AppLog -Message "Detected $($adapters.Count) physical network adapter(s)." -Level 'INFO'
    }
    catch {
        Write-AppLog -Message "Failed to enumerate network adapters: $($_.Exception.Message)" -Level 'ERROR'
        Write-Warning "Could not detect network adapters. Ensure you are running on Windows with administrator privileges."
    }

    return $adapters
}

function Get-AdapterIPConfiguration {
    <#
    .SYNOPSIS
        Gets the current IP configuration for a specific network adapter.
    .PARAMETER AdapterName
        The name of the adapter (as shown by Get-NetAdapter).
    .OUTPUTS
        [PSCustomObject] with IPAddress, SubnetPrefix, SubnetMask, Gateway,
        DNS, DHCPEnabled.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$AdapterName
    )

    $result = [PSCustomObject]@{
        IPAddress    = ''
        SubnetPrefix = 0
        SubnetMask   = ''
        Gateway      = ''
        DNS          = @()
        DHCPEnabled  = $false
    }

    try {
        # Get the adapter object to retrieve InterfaceIndex
        $adapter = Get-NetAdapter -Name $AdapterName -ErrorAction Stop

        # Retrieve the IPv4 address(es); take the first non-link-local one
        $ipInfo = Get-NetIPAddress -InterfaceIndex $adapter.InterfaceIndex `
                                   -AddressFamily IPv4 -ErrorAction SilentlyContinue |
                  Where-Object { $_.IPAddress -notlike '169.254.*' } |
                  Select-Object -First 1

        if ($ipInfo) {
            $result.IPAddress    = $ipInfo.IPAddress
            $result.SubnetPrefix = $ipInfo.PrefixLength
            $result.SubnetMask   = Convert-PrefixToSubnetMask -PrefixLength $ipInfo.PrefixLength
        }

        # Gateway
        $gwInfo = Get-NetIPConfiguration -InterfaceIndex $adapter.InterfaceIndex -ErrorAction SilentlyContinue
        if ($gwInfo -and $gwInfo.IPv4DefaultGateway) {
            $result.Gateway = $gwInfo.IPv4DefaultGateway.NextHop
        }

        # DNS servers
        $dnsInfo = Get-DnsClientServerAddress -InterfaceIndex $adapter.InterfaceIndex `
                                               -AddressFamily IPv4 -ErrorAction SilentlyContinue
        if ($dnsInfo -and $dnsInfo.ServerAddresses) {
            $result.DNS = $dnsInfo.ServerAddresses
        }

        # DHCP enabled?
        $dhcpInfo = Get-NetIPInterface -InterfaceIndex $adapter.InterfaceIndex `
                                        -AddressFamily IPv4 -ErrorAction SilentlyContinue
        if ($dhcpInfo) {
            $result.DHCPEnabled = ($dhcpInfo.Dhcp -eq 'Enabled')
        }

        Write-AppLog -Message "Retrieved IP config for adapter '$AdapterName': $($result.IPAddress)/$($result.SubnetPrefix)" -Level 'INFO'
    }
    catch {
        Write-AppLog -Message "Failed to get IP config for '$AdapterName': $($_.Exception.Message)" -Level 'ERROR'
    }

    return $result
}

function Set-AdapterStaticIP {
    <#
    .SYNOPSIS
        Configures a static IPv4 address on a network adapter.
    .DESCRIPTION
        Removes existing IPv4 addresses, sets a new static IP, optional
        gateway, and optional DNS servers.
    .PARAMETER AdapterName
        The adapter name.
    .PARAMETER IPAddress
        The IPv4 address to assign.
    .PARAMETER SubnetMask
        The subnet mask in dotted-decimal notation.
    .PARAMETER Gateway
        Optional default gateway.
    .PARAMETER DNS1
        Optional primary DNS server.
    .PARAMETER DNS2
        Optional secondary DNS server.
    .OUTPUTS
        [PSCustomObject] with Success ([bool]) and Message ([string]).
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$AdapterName,

        [Parameter(Mandatory = $true)]
        [string]$IPAddress,

        [Parameter(Mandatory = $true)]
        [string]$SubnetMask,

        [string]$Gateway = '',
        [string]$DNS1 = '',
        [string]$DNS2 = ''
    )

    # --- Validate inputs ----
    if (-not (Test-IPAddressFormat -IP $IPAddress)) {
        return [PSCustomObject]@{ Success = $false; Message = "Invalid IP address: $IPAddress" }
    }
    if (-not (Test-SubnetMaskFormat -Mask $SubnetMask)) {
        return [PSCustomObject]@{ Success = $false; Message = "Invalid subnet mask: $SubnetMask" }
    }
    if ($Gateway -and -not (Test-IPAddressFormat -IP $Gateway)) {
        return [PSCustomObject]@{ Success = $false; Message = "Invalid gateway: $Gateway" }
    }
    if ($DNS1 -and -not (Test-IPAddressFormat -IP $DNS1)) {
        return [PSCustomObject]@{ Success = $false; Message = "Invalid DNS 1: $DNS1" }
    }
    if ($DNS2 -and -not (Test-IPAddressFormat -IP $DNS2)) {
        return [PSCustomObject]@{ Success = $false; Message = "Invalid DNS 2: $DNS2" }
    }

    $prefix = Convert-SubnetMaskToPrefix -SubnetMask $SubnetMask
    if ($prefix -lt 0) {
        return [PSCustomObject]@{ Success = $false; Message = "Could not convert subnet mask to prefix length." }
    }

    try {
        $adapter = Get-NetAdapter -Name $AdapterName -ErrorAction Stop

        # Disable DHCP first so we can assign a static address
        Set-NetIPInterface -InterfaceIndex $adapter.InterfaceIndex `
                           -AddressFamily IPv4 -Dhcp Disabled -ErrorAction SilentlyContinue

        # Remove existing IPv4 addresses on this adapter
        Get-NetIPAddress -InterfaceIndex $adapter.InterfaceIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            Remove-NetIPAddress -Confirm:$false -ErrorAction SilentlyContinue

        # Remove existing gateway routes for this adapter
        Get-NetRoute -InterfaceIndex $adapter.InterfaceIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            Where-Object { $_.DestinationPrefix -eq '0.0.0.0/0' } |
            Remove-NetRoute -Confirm:$false -ErrorAction SilentlyContinue

        # Assign new IP address (with or without gateway)
        $ipParams = @{
            InterfaceIndex = $adapter.InterfaceIndex
            IPAddress      = $IPAddress
            PrefixLength   = $prefix
            AddressFamily  = 'IPv4'
            ErrorAction    = 'Stop'
        }

        if ($Gateway) {
            $ipParams['DefaultGateway'] = $Gateway
        }

        New-NetIPAddress @ipParams | Out-Null

        # Configure DNS servers
        $dnsServers = @()
        if ($DNS1) { $dnsServers += $DNS1 }
        if ($DNS2) { $dnsServers += $DNS2 }

        if ($dnsServers.Count -gt 0) {
            Set-DnsClientServerAddress -InterfaceIndex $adapter.InterfaceIndex `
                                       -ServerAddresses $dnsServers -ErrorAction Stop
        } else {
            Set-DnsClientServerAddress -InterfaceIndex $adapter.InterfaceIndex `
                                       -ResetServerAddresses -ErrorAction SilentlyContinue
        }

        $msg = "Successfully set $AdapterName to $IPAddress/$prefix"
        if ($Gateway) { $msg += " gw $Gateway" }
        Write-AppLog -Message $msg -Level 'INFO'
        return [PSCustomObject]@{ Success = $true; Message = $msg }
    }
    catch {
        $errMsg = "Failed to set static IP on '$AdapterName': $($_.Exception.Message)"
        Write-AppLog -Message $errMsg -Level 'ERROR'
        return [PSCustomObject]@{ Success = $false; Message = $errMsg }
    }
}

function Set-AdapterDHCP {
    <#
    .SYNOPSIS
        Configures a network adapter to obtain its IP address via DHCP.
    .PARAMETER AdapterName
        The adapter name.
    .OUTPUTS
        [PSCustomObject] with Success ([bool]) and Message ([string]).
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$AdapterName
    )

    try {
        $adapter = Get-NetAdapter -Name $AdapterName -ErrorAction Stop

        # Remove existing static addresses so DHCP can take over cleanly
        Get-NetIPAddress -InterfaceIndex $adapter.InterfaceIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            Remove-NetIPAddress -Confirm:$false -ErrorAction SilentlyContinue

        # Remove static gateway routes
        Get-NetRoute -InterfaceIndex $adapter.InterfaceIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            Where-Object { $_.DestinationPrefix -eq '0.0.0.0/0' } |
            Remove-NetRoute -Confirm:$false -ErrorAction SilentlyContinue

        # Enable DHCP
        Set-NetIPInterface -InterfaceIndex $adapter.InterfaceIndex `
                           -AddressFamily IPv4 -Dhcp Enabled -ErrorAction Stop

        # Reset DNS to automatic (DHCP-provided)
        Set-DnsClientServerAddress -InterfaceIndex $adapter.InterfaceIndex `
                                   -ResetServerAddresses -ErrorAction SilentlyContinue

        $msg = "Successfully set '$AdapterName' to DHCP."
        Write-AppLog -Message $msg -Level 'INFO'
        return [PSCustomObject]@{ Success = $true; Message = $msg }
    }
    catch {
        $errMsg = "Failed to enable DHCP on '$AdapterName': $($_.Exception.Message)"
        Write-AppLog -Message $errMsg -Level 'ERROR'
        return [PSCustomObject]@{ Success = $false; Message = $errMsg }
    }
}

function Rename-NetworkAdapter {
    <#
    .SYNOPSIS
        Renames a network adapter.
    .PARAMETER CurrentName
        The current adapter name.
    .PARAMETER NewName
        The desired new name.
    .OUTPUTS
        [PSCustomObject] with Success ([bool]) and Message ([string]).
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$CurrentName,

        [Parameter(Mandatory = $true)]
        [string]$NewName
    )

    if ([string]::IsNullOrWhiteSpace($NewName)) {
        return [PSCustomObject]@{ Success = $false; Message = "New adapter name cannot be empty." }
    }

    try {
        Rename-NetAdapter -Name $CurrentName -NewName $NewName -ErrorAction Stop
        $msg = "Renamed adapter '$CurrentName' to '$NewName'."
        Write-AppLog -Message $msg -Level 'INFO'
        return [PSCustomObject]@{ Success = $true; Message = $msg }
    }
    catch {
        $errMsg = "Failed to rename '$CurrentName' to '$NewName': $($_.Exception.Message)"
        Write-AppLog -Message $errMsg -Level 'ERROR'
        return [PSCustomObject]@{ Success = $false; Message = $errMsg }
    }
}

# ============================================================================
# HELPER: Apply one adapter card's configuration
# ============================================================================

function Invoke-ApplyAdapterConfig {
    <#
    .SYNOPSIS
        Reads the controls for a given role index and applies the configuration.
    .PARAMETER RoleIndex
        The 0-based role index (0-5).
    .OUTPUTS
        [PSCustomObject] with Success and Message.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [int]$RoleIndex
    )

    $controls = $script:CardControls[$RoleIndex]
    if (-not $controls) {
        return [PSCustomObject]@{ Success = $false; Message = "No controls found for role index $RoleIndex." }
    }

    # Check if enabled
    if (-not $controls.EnabledCheckBox.Checked) {
        return [PSCustomObject]@{ Success = $true; Message = "Adapter role $RoleIndex is disabled; skipped." }
    }

    # Get the selected physical adapter name
    $adapterName = $controls.AdapterCombo.SelectedItem
    if ([string]::IsNullOrWhiteSpace($adapterName) -or $adapterName -eq '(none)') {
        return [PSCustomObject]@{ Success = $false; Message = "No physical adapter selected for '$($script:AdapterRoles[$RoleIndex].RoleName)'." }
    }

    # DHCP mode?
    if ($controls.DHCPCheckBox.Checked) {
        return Set-AdapterDHCP -AdapterName $adapterName
    }

    # Static IP mode - read values from textboxes (handle placeholder text)
    $ip   = $controls.IPTextBox.Text.Trim()
    $sub  = $controls.SubnetTextBox.Text.Trim()
    $gw   = $controls.GatewayTextBox.Text.Trim()
    $dns1 = $controls.DNS1TextBox.Text.Trim()
    $dns2 = $controls.DNS2TextBox.Text.Trim()

    # Clear placeholder sentinel values
    $placeholders = @('IP Address', 'Subnet Mask', 'Gateway', 'DNS 1', 'DNS 2',
                      'e.g. 10.0.0.10', 'e.g. 255.255.255.0', 'e.g. 10.0.0.1',
                      'e.g. 8.8.8.8', 'e.g. 8.8.4.4')
    if ($ip   -in $placeholders) { $ip   = '' }
    if ($sub  -in $placeholders) { $sub  = '' }
    if ($gw   -in $placeholders) { $gw   = '' }
    if ($dns1 -in $placeholders) { $dns1 = '' }
    if ($dns2 -in $placeholders) { $dns2 = '' }

    # Validate mandatory fields
    if ([string]::IsNullOrWhiteSpace($ip)) {
        return [PSCustomObject]@{ Success = $false; Message = "IP address is required for '$($script:AdapterRoles[$RoleIndex].RoleName)'." }
    }
    if ([string]::IsNullOrWhiteSpace($sub)) {
        return [PSCustomObject]@{ Success = $false; Message = "Subnet mask is required for '$($script:AdapterRoles[$RoleIndex].RoleName)'." }
    }

    return Set-AdapterStaticIP -AdapterName $adapterName `
                               -IPAddress $ip `
                               -SubnetMask $sub `
                               -Gateway $gw `
                               -DNS1 $dns1 `
                               -DNS2 $dns2
}

# ============================================================================
# UI VIEW FUNCTION
# ============================================================================

function New-NetworkView {
    <#
    .SYNOPSIS
        Builds the Network Adapter configuration view inside the given content panel.
    .PARAMETER ContentPanel
        The parent panel that this view populates (provided by the main application shell).
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Panel]$ContentPanel
    )

    $ContentPanel.Controls.Clear()
    $ContentPanel.SuspendLayout()

    # Reset control references
    $script:CardControls = @{}

    # -----------------------------------------------------------------------
    # Layout constants
    # -----------------------------------------------------------------------
    $padding        = 20          # Outer padding from content panel edges
    $cardWidth      = 430         # Width of each adapter card
    $cardHeight     = 295         # Height of each adapter card (compact but room for all fields)
    $cardGapX       = 20          # Horizontal gap between columns
    $cardGapY       = 15          # Vertical gap between rows
    $headerHeight   = 40          # Section header height
    $toolbarY       = 60          # Y position of toolbar
    $toolbarHeight  = 40          # Height of toolbar row
    $gridStartY     = 115         # Y start of the card grid
    $cols           = 2           # Number of columns
    $rows           = 3           # Number of rows

    # Calculate total width needed for the grid
    $gridTotalWidth  = ($cols * $cardWidth) + (($cols - 1) * $cardGapX) + ($padding * 2)
    $gridTotalHeight = $gridStartY + ($rows * $cardHeight) + (($rows - 1) * $cardGapY) + $padding

    # -----------------------------------------------------------------------
    # Scrollable wrapper to contain everything
    # -----------------------------------------------------------------------
    $scrollPanel = New-ScrollPanel -X 0 -Y 0 `
                                   -Width $ContentPanel.ClientSize.Width `
                                   -Height $ContentPanel.ClientSize.Height
    $scrollPanel.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor `
                          [System.Windows.Forms.AnchorStyles]::Bottom -bor `
                          [System.Windows.Forms.AnchorStyles]::Left -bor `
                          [System.Windows.Forms.AnchorStyles]::Right

    # Resize the scroll panel when the content panel resizes
    $ContentPanel.Add_Resize({
        $scrollPanel = $this.Controls[0]
        if ($scrollPanel) {
            $scrollPanel.Size = $this.ClientSize
        }
    })

    # -----------------------------------------------------------------------
    # Section header
    # -----------------------------------------------------------------------
    $sectionHeader = New-SectionHeader -Text 'Network Adapters' `
                                       -X $padding -Y $padding `
                                       -Width ($gridTotalWidth - ($padding * 2))

    $scrollPanel.Controls.Add($sectionHeader)

    # Subtitle
    $subtitle = New-StyledLabel -Text 'Configure IP addresses for 6 network interfaces' `
                                -X ($padding + 2) -Y ($padding + 32) `
                                -FontSize 9 -IsSecondary
    $scrollPanel.Controls.Add($subtitle)

    # -----------------------------------------------------------------------
    # Toolbar row: Detect Adapters, Apply All Changes, Profile selector
    # -----------------------------------------------------------------------
    $btnDetect = New-StyledButton -Text 'Detect Adapters' `
                                  -X $padding -Y $toolbarY `
                                  -Width 140 -Height $toolbarHeight `
                                  -OnClick {
        # Populate adapters into all card combo boxes
        $script:DetectedAdapters = Get-SystemNetworkAdapters

        if ($script:DetectedAdapters.Count -eq 0) {
            [System.Windows.Forms.MessageBox]::Show(
                "No physical network adapters were detected.`n`nEnsure you are running as Administrator on a Windows machine.",
                'DISGUISE BUDDY - Detection',
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
            return
        }

        # Build display list: "AdapterName (Status)"
        $adapterDisplayItems = @('(none)')
        foreach ($a in $script:DetectedAdapters) {
            $adapterDisplayItems += "$($a.Name)"
        }

        # Update each card's adapter combo
        foreach ($roleIdx in $script:CardControls.Keys) {
            $combo = $script:CardControls[$roleIdx].AdapterCombo
            $previousSelection = $combo.SelectedItem
            $combo.Items.Clear()
            foreach ($item in $adapterDisplayItems) {
                $combo.Items.Add($item) | Out-Null
            }

            # Try to auto-match: look for adapter whose name contains the role short name
            $roleName = $script:AdapterRoles[$roleIdx].ShortName
            $matched = $false

            # First try exact previous selection
            if ($previousSelection -and $combo.Items.Contains($previousSelection)) {
                $combo.SelectedItem = $previousSelection
                $matched = $true
            }

            # Then try name matching against role short name
            if (-not $matched) {
                foreach ($a in $script:DetectedAdapters) {
                    if ($a.Name -like "*$roleName*" -or $a.Name -like "*$($script:AdapterRoles[$roleIdx].RoleName)*") {
                        $combo.SelectedItem = $a.Name
                        $matched = $true
                        break
                    }
                }
            }

            # If no match, try by interface index position (adapter at physical slot = role index)
            if (-not $matched -and $roleIdx -lt $script:DetectedAdapters.Count) {
                $combo.SelectedItem = $script:DetectedAdapters[$roleIdx].Name
                $matched = $true
            }

            # Fallback: select "(none)"
            if (-not $matched) {
                $combo.SelectedIndex = 0
            }

            # Update status badge based on adapter status
            $statusBadge = $script:CardControls[$roleIdx].StatusBadge
            $selectedAdapterName = $combo.SelectedItem
            if ($selectedAdapterName -and $selectedAdapterName -ne '(none)') {
                $adapterObj = $script:DetectedAdapters | Where-Object { $_.Name -eq $selectedAdapterName }
                if ($adapterObj -and $adapterObj.Status -eq 'Up') {
                    $statusBadge.Tag = ' Connected '
                    $statusBadge.AccessibleDescription = "$([System.Drawing.Color]::FromArgb(16,185,129).ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                    $statusBadge.Invalidate()
                } else {
                    $statusBadge.Tag = ' Disconnected '
                    $statusBadge.AccessibleDescription = "$([System.Drawing.Color]::FromArgb(239,68,68).ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                    $statusBadge.Invalidate()
                }
            } else {
                $statusBadge.Tag = ' No Adapter '
                $statusBadge.AccessibleDescription = "$($script:Theme.TextMuted.ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                $statusBadge.Invalidate()
            }
        }

        # Also try to populate current IP config for each matched adapter
        foreach ($roleIdx in $script:CardControls.Keys) {
            $combo = $script:CardControls[$roleIdx].AdapterCombo
            $selectedAdapter = $combo.SelectedItem
            if ($selectedAdapter -and $selectedAdapter -ne '(none)') {
                try {
                    $ipConfig = Get-AdapterIPConfiguration -AdapterName $selectedAdapter
                    $controls = $script:CardControls[$roleIdx]

                    if ($ipConfig.DHCPEnabled) {
                        $controls.DHCPCheckBox.Checked = $true
                    } else {
                        $controls.DHCPCheckBox.Checked = $false
                        if ($ipConfig.IPAddress) {
                            $controls.IPTextBox.Text = $ipConfig.IPAddress
                            $controls.IPTextBox.ForeColor = $script:Theme.Text
                        }
                        if ($ipConfig.SubnetMask) {
                            $controls.SubnetTextBox.Text = $ipConfig.SubnetMask
                            $controls.SubnetTextBox.ForeColor = $script:Theme.Text
                        }
                        if ($ipConfig.Gateway) {
                            $controls.GatewayTextBox.Text = $ipConfig.Gateway
                            $controls.GatewayTextBox.ForeColor = $script:Theme.Text
                        }
                        if ($ipConfig.DNS -and $ipConfig.DNS.Count -ge 1) {
                            $controls.DNS1TextBox.Text = $ipConfig.DNS[0]
                            $controls.DNS1TextBox.ForeColor = $script:Theme.Text
                        }
                        if ($ipConfig.DNS -and $ipConfig.DNS.Count -ge 2) {
                            $controls.DNS2TextBox.Text = $ipConfig.DNS[1]
                            $controls.DNS2TextBox.ForeColor = $script:Theme.Text
                        }
                    }
                }
                catch {
                    # Silently continue if we can't read adapter config
                    Write-AppLog -Message "Could not read IP config for '$selectedAdapter': $($_.Exception.Message)" -Level 'WARN'
                }
            }
        }

        [System.Windows.Forms.MessageBox]::Show(
            "Detected $($script:DetectedAdapters.Count) physical adapter(s).`nAdapter dropdowns have been populated and auto-matched.",
            'DISGUISE BUDDY - Detection Complete',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Information
        )
    }
    $scrollPanel.Controls.Add($btnDetect)

    $btnApplyAll = New-StyledButton -Text 'Apply All Changes' `
                                    -X ($padding + 155) -Y $toolbarY `
                                    -Width 150 -Height $toolbarHeight `
                                    -IsPrimary `
                                    -OnClick {
        # Confirmation dialog
        $confirm = [System.Windows.Forms.MessageBox]::Show(
            "This will apply network configuration to all enabled adapters.`n`nAre you sure you want to continue?",
            'DISGUISE BUDDY - Apply All',
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Question
        )
        if ($confirm -ne [System.Windows.Forms.DialogResult]::Yes) { return }

        # Show "Applying..." state on the button
        $btn = $this
        $originalText = $btn.Text
        $btn.Text = 'Applying...'
        $btn.Enabled = $false
        $btn.BackColor = $script:Theme.TextMuted
        $btn.Refresh()

        $results = @()
        $successCount = 0
        $failCount = 0
        $skipCount = 0

        for ($i = 0; $i -lt 6; $i++) {
            $roleName = $script:AdapterRoles[$i].RoleName
            $result = Invoke-ApplyAdapterConfig -RoleIndex $i

            if ($result.Message -like '*skipped*' -or $result.Message -like '*disabled*') {
                $skipCount++
                $results += "  SKIP  $roleName : $($result.Message)"
            } elseif ($result.Success) {
                $successCount++
                $results += "  OK    $roleName : $($result.Message)"
            } else {
                $failCount++
                $results += "  FAIL  $roleName : $($result.Message)"
            }
        }

        # Show success/failure feedback on the button
        if ($failCount -gt 0) {
            $btn.Text = "$failCount Failed"
            $btn.BackColor = $script:Theme.Error
            $btn.ForeColor = [System.Drawing.Color]::White
        } else {
            $btn.Text = 'All Applied'
            $btn.BackColor = $script:Theme.Success
            $btn.ForeColor = [System.Drawing.Color]::White
        }
        $btn.Refresh()
        Start-Sleep -Milliseconds 800

        $summary = "Apply All Results:`n" +
                   "----------------------------`n" +
                   "  Success: $successCount`n" +
                   "  Failed:  $failCount`n" +
                   "  Skipped: $skipCount`n" +
                   "----------------------------`n`n" +
                   ($results -join "`n")

        $icon = if ($failCount -gt 0) {
            [System.Windows.Forms.MessageBoxIcon]::Warning
        } else {
            [System.Windows.Forms.MessageBoxIcon]::Information
        }

        [System.Windows.Forms.MessageBox]::Show(
            $summary,
            'DISGUISE BUDDY - Results',
            [System.Windows.Forms.MessageBoxButtons]::OK,
            $icon
        )

        # Restore button to original state
        $btn.Text = $originalText
        $btn.Enabled = $true
        $btn.BackColor = $script:Theme.Primary
        $btn.ForeColor = [System.Drawing.Color]::White
    }
    $scrollPanel.Controls.Add($btnApplyAll)

    # Profile selector
    $profileLabel = New-StyledLabel -Text 'Profile:' `
                                    -X ($padding + 330) -Y ($toolbarY + 8) `
                                    -FontSize 9.5 -IsSecondary
    $scrollPanel.Controls.Add($profileLabel)

    # Scan for saved profiles in the profiles directory
    $profileItems = @('Default d3 Config')
    $profileDir = Join-Path (Get-AppRootPath) 'profiles'
    if (Test-Path $profileDir) {
        $profileFiles = Get-ChildItem -Path $profileDir -Filter '*.json' -ErrorAction SilentlyContinue
        foreach ($pf in $profileFiles) {
            $profileItems += $pf.BaseName
        }
    }

    $profileCombo = New-StyledComboBox -X ($padding + 395) -Y ($toolbarY + 5) `
                                       -Width 200 `
                                       -Items $profileItems
    $profileCombo.SelectedIndex = 0
    $scrollPanel.Controls.Add($profileCombo)

    # -----------------------------------------------------------------------
    # Build the 6 adapter cards (2 columns x 3 rows)
    # -----------------------------------------------------------------------
    for ($roleIdx = 0; $roleIdx -lt 6; $roleIdx++) {
        $role = $script:AdapterRoles[$roleIdx]

        # Grid position: column = roleIdx % 2, row = [Math]::Floor(roleIdx / 2)
        $col = $roleIdx % $cols
        $row = [Math]::Floor($roleIdx / $cols)

        $cardX = $padding + ($col * ($cardWidth + $cardGapX))
        $cardY = $gridStartY + ($row * ($cardHeight + $cardGapY))

        # --- Card panel ---
        $card = New-StyledPanel -X $cardX -Y $cardY -Width $cardWidth -Height $cardHeight -IsCard
        $card.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor [System.Windows.Forms.AnchorStyles]::Left

        # --- Colored accent bar on the left edge (4px wide, full height) ---
        $accentBar = New-Object System.Windows.Forms.Panel
        $accentBar.Location = New-Object System.Drawing.Point(0, 0)
        $accentBar.Size = New-Object System.Drawing.Size(4, $cardHeight)
        $accentBar.BackColor = [System.Drawing.ColorTranslator]::FromHtml($role.Color)
        $card.Controls.Add($accentBar)

        # ---- Title row: Role name + status badge ----
        $titleLabel = New-Object System.Windows.Forms.Label
        $titleLabel.Text = $role.RoleName
        $titleLabel.Location = New-Object System.Drawing.Point(14, 10)
        $titleLabel.AutoSize = $true
        $titleLabel.Font = New-Object System.Drawing.Font('Segoe UI', 11, [System.Drawing.FontStyle]::Bold)
        $titleLabel.ForeColor = [System.Drawing.ColorTranslator]::FromHtml($role.Color)
        $card.Controls.Add($titleLabel)

        $statusBadge = New-StatusBadge -Text ' No Adapter ' -X 320 -Y 12 -Type 'Info'
        $card.Controls.Add($statusBadge)

        # ---- Row tracking inside card (compact layout) ----
        $innerLeft   = 14         # Left margin for labels
        $inputLeft   = 110        # Left margin for inputs
        $inputWidth  = 180        # Width of text inputs
        $rowH        = 28         # Row height
        $currentY    = 38         # Start Y below title

        # ---- Physical Adapter dropdown ----
        $adapterLabel = New-StyledLabel -Text 'Adapter:' -X $innerLeft -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($adapterLabel)

        $adapterCombo = New-StyledComboBox -X $inputLeft -Y $currentY -Width ($inputWidth + 100) -Items @('(none)')
        $adapterCombo.SelectedIndex = 0

        # When adapter selection changes, update status badge
        $adapterCombo.Tag = $roleIdx
        $adapterCombo.Add_SelectedIndexChanged({
            $rIdx = $this.Tag
            $selectedName = $this.SelectedItem
            $badge = $script:CardControls[$rIdx].StatusBadge

            if ($selectedName -and $selectedName -ne '(none)') {
                $adapterObj = $script:DetectedAdapters | Where-Object { $_.Name -eq $selectedName }
                if ($adapterObj -and $adapterObj.Status -eq 'Up') {
                    $badge.Tag = ' Connected '
                    $badge.AccessibleDescription = "$([System.Drawing.Color]::FromArgb(16,185,129).ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                    $badge.Invalidate()
                } else {
                    $badge.Tag = ' Disconnected '
                    $badge.AccessibleDescription = "$([System.Drawing.Color]::FromArgb(239,68,68).ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                    $badge.Invalidate()
                }
            } else {
                $badge.Tag = ' No Adapter '
                $badge.AccessibleDescription = "$([System.Drawing.Color]::FromArgb(6,182,212).ToArgb())|$([System.Drawing.Color]::White.ToArgb())"
                $badge.Invalidate()
            }
        })
        $card.Controls.Add($adapterCombo)
        $currentY += $rowH + 4

        # ---- IP Address ----
        $ipLabel = New-StyledLabel -Text 'IP Address:' -X $innerLeft -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($ipLabel)

        $defaultIP = if ($role.DefaultIP) { $role.DefaultIP } else { '' }
        $ipTextBox = New-StyledTextBox -X $inputLeft -Y $currentY -Width $inputWidth -PlaceholderText $(
            if ($defaultIP) { $defaultIP } else { 'IP Address' }
        )
        $card.Controls.Add($ipTextBox)

        # Inline validation indicator for IP
        $ipValidLabel = New-Object System.Windows.Forms.Label
        $ipValidLabel.Location = New-Object System.Drawing.Point(($inputLeft + $inputWidth + 5), ($currentY + 4))
        $ipValidLabel.Size = New-Object System.Drawing.Size(20, 20)
        $ipValidLabel.Text = ''
        $ipValidLabel.Font = New-Object System.Drawing.Font('Segoe UI', 9)
        $card.Controls.Add($ipValidLabel)

        # Tooltip provider for validation feedback (shared per card)
        $ipToolTip = New-Object System.Windows.Forms.ToolTip
        $ipToolTip.InitialDelay = 200
        $ipToolTip.AutoPopDelay = 5000

        $ipTextBox.Add_TextChanged({
            $tb = $this
            $validLabel = $tb.Parent.Controls | Where-Object {
                $_.Location.X -eq ($tb.Location.X + $tb.Width + 5) -and
                $_.Location.Y -eq ($tb.Location.Y + 4) -and
                $_ -is [System.Windows.Forms.Label]
            } | Select-Object -First 1
            if ($validLabel) {
                $text = $tb.Text.Trim()
                if ([string]::IsNullOrWhiteSpace($text) -or $text -eq $tb.Tag) {
                    $validLabel.Text = ''
                    $tb.BackColor = $script:Theme.InputBackground
                } elseif (Test-IPAddressFormat -IP $text) {
                    $validLabel.Text = [char]0x2713   # checkmark
                    $validLabel.ForeColor = $script:Theme.Success
                    $tb.BackColor = $script:Theme.InputBackground
                } else {
                    $validLabel.Text = [char]0x2717   # X mark
                    $validLabel.ForeColor = $script:Theme.Error
                    # Tint background to indicate error
                    $tb.BackColor = [System.Drawing.Color]::FromArgb(40, 239, 68, 68)

                    # Determine specific error for tooltip
                    $errMsg = 'Invalid IP address format'
                    $octets = $text.Split('.')
                    if ($octets.Count -eq 4) {
                        $allNumeric = $true
                        foreach ($o in $octets) {
                            if ($o -notmatch '^\d{1,3}$') { $allNumeric = $false; break }
                        }
                        if ($allNumeric) {
                            $firstOctet = [int]$octets[0]
                            if ($firstOctet -eq 0) {
                                $errMsg = 'Addresses starting with 0 are reserved (current network)'
                            } elseif ($firstOctet -eq 127) {
                                $errMsg = 'Loopback range (127.x.x.x) is not allowed for adapters'
                            } elseif ($text -eq '255.255.255.255') {
                                $errMsg = 'Broadcast address is not a valid host address'
                            }
                        }
                    }
                    # Set tooltip on the validation label
                    $ttip = $validLabel.Parent.Controls | Where-Object { $_ -is [System.Windows.Forms.ToolTip] }
                    # Use Tag on label to pass tooltip text for hover
                    $validLabel.Tag = $errMsg
                }
            }
        })
        $currentY += $rowH + 2

        # ---- Subnet Mask ----
        $subLabel = New-StyledLabel -Text 'Subnet:' -X $innerLeft -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($subLabel)

        $defaultSub = if ($role.DefaultSub) { $role.DefaultSub } else { '' }
        $subTextBox = New-StyledTextBox -X $inputLeft -Y $currentY -Width $inputWidth -PlaceholderText $(
            if ($defaultSub) { $defaultSub } else { 'Subnet Mask' }
        )
        $card.Controls.Add($subTextBox)

        # Inline validation indicator for subnet
        $subValidLabel = New-Object System.Windows.Forms.Label
        $subValidLabel.Location = New-Object System.Drawing.Point(($inputLeft + $inputWidth + 5), ($currentY + 4))
        $subValidLabel.Size = New-Object System.Drawing.Size(20, 20)
        $subValidLabel.Text = ''
        $subValidLabel.Font = New-Object System.Drawing.Font('Segoe UI', 9)
        $card.Controls.Add($subValidLabel)

        $subTextBox.Add_TextChanged({
            $tb = $this
            $validLabel = $tb.Parent.Controls | Where-Object {
                $_.Location.X -eq ($tb.Location.X + $tb.Width + 5) -and
                $_.Location.Y -eq ($tb.Location.Y + 4) -and
                $_ -is [System.Windows.Forms.Label]
            } | Select-Object -First 1
            if ($validLabel) {
                $text = $tb.Text.Trim()
                if ([string]::IsNullOrWhiteSpace($text) -or $text -eq $tb.Tag) {
                    $validLabel.Text = ''
                    $tb.BackColor = $script:Theme.InputBackground
                } elseif (Test-SubnetMaskFormat -Mask $text) {
                    $validLabel.Text = [char]0x2713
                    $validLabel.ForeColor = $script:Theme.Success
                    $tb.BackColor = $script:Theme.InputBackground
                } else {
                    $validLabel.Text = [char]0x2717
                    $validLabel.ForeColor = $script:Theme.Error
                    # Tint background to indicate error
                    $tb.BackColor = [System.Drawing.Color]::FromArgb(40, 239, 68, 68)

                    # Determine specific error for tooltip
                    $errMsg = 'Invalid subnet mask format'
                    $octets = $text.Split('.')
                    if ($octets.Count -eq 4) {
                        $allNumeric = $true
                        foreach ($o in $octets) {
                            if ($o -notmatch '^\d{1,3}$') { $allNumeric = $false; break }
                        }
                        if ($allNumeric) {
                            # Check if all octets are valid but mask is non-contiguous
                            $allInRange = $true
                            foreach ($o in $octets) {
                                if ([int]$o -gt 255) { $allInRange = $false; break }
                            }
                            if ($allInRange) {
                                $bin = ''
                                foreach ($o in $octets) { $bin += [Convert]::ToString([int]$o, 2).PadLeft(8, '0') }
                                if ($bin -notmatch '^1+0*$') {
                                    $errMsg = 'Subnet mask is not contiguous (bits must be all 1s then all 0s)'
                                }
                            }
                        }
                    }
                    $validLabel.Tag = $errMsg
                }
            }
        })
        $currentY += $rowH + 2

        # ---- Gateway ----
        $gwLabel = New-StyledLabel -Text 'Gateway:' -X $innerLeft -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($gwLabel)

        $gwTextBox = New-StyledTextBox -X $inputLeft -Y $currentY -Width $inputWidth -PlaceholderText 'Gateway'
        $card.Controls.Add($gwTextBox)
        $currentY += $rowH + 2

        # ---- DNS 1 / DNS 2 on the same row ----
        $dns1Label = New-StyledLabel -Text 'DNS 1:' -X $innerLeft -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($dns1Label)

        $dns1TextBox = New-StyledTextBox -X $inputLeft -Y $currentY -Width 100 -PlaceholderText 'DNS 1'
        $card.Controls.Add($dns1TextBox)

        $dns2Label = New-StyledLabel -Text 'DNS 2:' -X ($inputLeft + 110) -Y ($currentY + 2) -FontSize 9 -IsSecondary
        $card.Controls.Add($dns2Label)

        $dns2TextBox = New-StyledTextBox -X ($inputLeft + 155) -Y $currentY -Width 100 -PlaceholderText 'DNS 2'
        $card.Controls.Add($dns2TextBox)
        $currentY += $rowH + 6

        # ---- DHCP checkbox ----
        $dhcpCheck = New-StyledCheckBox -Text 'DHCP' -X $innerLeft -Y $currentY
        $dhcpCheck.Checked = $role.DefaultDHCP

        # Store references to the fields we need to enable/disable
        # We use the Tag property of the checkbox to hold the role index
        $dhcpCheck.Tag = $roleIdx
        $dhcpCheck.Add_CheckedChanged({
            $rIdx = $this.Tag
            $controls = $script:CardControls[$rIdx]
            $disabled = $this.Checked

            $controls.IPTextBox.Enabled      = -not $disabled
            $controls.SubnetTextBox.Enabled   = -not $disabled
            $controls.GatewayTextBox.Enabled  = -not $disabled
            $controls.DNS1TextBox.Enabled     = -not $disabled
            $controls.DNS2TextBox.Enabled     = -not $disabled

            # Visual feedback: dim the text boxes when DHCP is on
            if ($disabled) {
                $controls.IPTextBox.BackColor     = $script:Theme.SurfaceLight
                $controls.SubnetTextBox.BackColor  = $script:Theme.SurfaceLight
                $controls.GatewayTextBox.BackColor = $script:Theme.SurfaceLight
                $controls.DNS1TextBox.BackColor    = $script:Theme.SurfaceLight
                $controls.DNS2TextBox.BackColor    = $script:Theme.SurfaceLight
            } else {
                $controls.IPTextBox.BackColor     = $script:Theme.InputBackground
                $controls.SubnetTextBox.BackColor  = $script:Theme.InputBackground
                $controls.GatewayTextBox.BackColor = $script:Theme.InputBackground
                $controls.DNS1TextBox.BackColor    = $script:Theme.InputBackground
                $controls.DNS2TextBox.BackColor    = $script:Theme.InputBackground
            }
        })
        $card.Controls.Add($dhcpCheck)

        # ---- Enabled checkbox ----
        $enabledCheck = New-StyledCheckBox -Text 'Enabled' -X ($innerLeft + 100) -Y $currentY
        $enabledCheck.Checked = $true
        $card.Controls.Add($enabledCheck)

        # ---- Apply button for this single card ----
        $applyBtn = New-StyledButton -Text 'Apply' `
                                     -X ($cardWidth - 90) -Y ($currentY - 2) `
                                     -Width 70 -Height 28 `
                                     -IsPrimary `
                                     -OnClick {
            # Determine which role this button belongs to by walking up to the card
            # and finding its index in $script:CardControls
            $btn = $this
            $parentCard = $btn.Parent
            $rIdx = -1
            foreach ($key in $script:CardControls.Keys) {
                if ($script:CardControls[$key].Card -eq $parentCard) {
                    $rIdx = $key
                    break
                }
            }

            if ($rIdx -lt 0) {
                [System.Windows.Forms.MessageBox]::Show(
                    'Could not determine which adapter card this button belongs to.',
                    'Error',
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
                return
            }

            # Show "Applying..." state
            $originalText = $btn.Text
            $btn.Text = 'Applying...'
            $btn.Enabled = $false
            $btn.BackColor = $script:Theme.TextMuted
            $btn.Refresh()

            $roleName = $script:AdapterRoles[$rIdx].RoleName
            $result = Invoke-ApplyAdapterConfig -RoleIndex $rIdx

            if ($result.Success) {
                # Brief success feedback on the button itself
                $btn.Text = 'Done'
                $btn.BackColor = $script:Theme.Success
                $btn.ForeColor = [System.Drawing.Color]::White
                $btn.Refresh()
                Start-Sleep -Milliseconds 800

                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "DISGUISE BUDDY - $roleName",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )
            } else {
                # Brief failure feedback on the button itself
                $btn.Text = 'Failed'
                $btn.BackColor = $script:Theme.Error
                $btn.ForeColor = [System.Drawing.Color]::White
                $btn.Refresh()
                Start-Sleep -Milliseconds 800

                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "DISGUISE BUDDY - $roleName",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning
                )
            }

            # Restore button to original state
            $btn.Text = $originalText
            $btn.Enabled = $true
            $btn.BackColor = $script:Theme.Primary
            $btn.ForeColor = [System.Drawing.Color]::White
        }
        $card.Controls.Add($applyBtn)

        # ---------------------------------------------------------------
        # If DHCP is the default for this role, disable IP fields now
        # ---------------------------------------------------------------
        if ($role.DefaultDHCP) {
            $ipTextBox.Enabled     = $false
            $subTextBox.Enabled    = $false
            $gwTextBox.Enabled     = $false
            $dns1TextBox.Enabled   = $false
            $dns2TextBox.Enabled   = $false
            $ipTextBox.BackColor   = $script:Theme.SurfaceLight
            $subTextBox.BackColor  = $script:Theme.SurfaceLight
            $gwTextBox.BackColor   = $script:Theme.SurfaceLight
            $dns1TextBox.BackColor = $script:Theme.SurfaceLight
            $dns2TextBox.BackColor = $script:Theme.SurfaceLight
        }

        # ---------------------------------------------------------------
        # Store control references for this role
        # ---------------------------------------------------------------
        $script:CardControls[$roleIdx] = @{
            Card            = $card
            StatusBadge     = $statusBadge
            AdapterCombo    = $adapterCombo
            IPTextBox       = $ipTextBox
            SubnetTextBox   = $subTextBox
            GatewayTextBox  = $gwTextBox
            DNS1TextBox     = $dns1TextBox
            DNS2TextBox     = $dns2TextBox
            DHCPCheckBox    = $dhcpCheck
            EnabledCheckBox = $enabledCheck
            ApplyButton     = $applyBtn
        }

        # Add card to scroll panel
        $scrollPanel.Controls.Add($card)
    }

    # -----------------------------------------------------------------------
    # Add the scroll panel to the content panel
    # -----------------------------------------------------------------------
    $ContentPanel.Controls.Add($scrollPanel)
    $ContentPanel.ResumeLayout()
}

# ============================================================
# MODULE: SMBConfig.ps1
# ============================================================
# SMBConfig.ps1 - DISGUISE BUDDY SMB File Sharing Configuration Module
# Manages d3 Projects SMB shares for disguise (d3) media servers.
# Provides backend functions for share management and a Windows Forms UI view.

# ============================================================================
# Backend Functions
# ============================================================================

function Get-D3ProjectShares {
    <#
    .SYNOPSIS
        Lists all current SMB shares on the system.
    .DESCRIPTION
        Retrieves all SMB shares using Get-SmbShare and returns an array of
        simplified objects. The "d3 Projects" share is flagged if found.
    .OUTPUTS
        Array of PSCustomObjects with Name, Path, Description, ShareState, and IsD3Share properties.
    #>
    try {
        $shares = Get-SmbShare -ErrorAction Stop | ForEach-Object {
            [PSCustomObject]@{
                Name        = $_.Name
                Path        = $_.Path
                Description = $_.Description
                ShareState  = $_.ShareState
                IsD3Share   = ($_.Name -eq 'd3 Projects')
            }
        }
        Write-AppLog -Message "Retrieved $($shares.Count) SMB shares from system." -Level 'INFO'
        return $shares
    }
    catch {
        Write-AppLog -Message "Failed to retrieve SMB shares: $_" -Level 'ERROR'
        return @()
    }
}

function Get-SharePermissions {
    <#
    .SYNOPSIS
        Gets the access permissions for a specific SMB share.
    .PARAMETER ShareName
        The name of the share to query.
    .OUTPUTS
        Array of PSCustomObjects with AccountName, AccessControlType, and AccessRight properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$ShareName
    )

    try {
        $access = Get-SmbShareAccess -Name $ShareName -ErrorAction Stop | ForEach-Object {
            [PSCustomObject]@{
                AccountName       = $_.AccountName
                AccessControlType = $_.AccessControlType
                AccessRight       = $_.AccessRight
            }
        }
        Write-AppLog -Message "Retrieved permissions for share '$ShareName': $($access.Count) entries." -Level 'INFO'
        return $access
    }
    catch {
        Write-AppLog -Message "Failed to retrieve permissions for share '$ShareName': $_" -Level 'ERROR'
        return @()
    }
}

function New-D3ProjectShare {
    <#
    .SYNOPSIS
        Creates a new d3 Projects SMB share.
    .DESCRIPTION
        Creates an SMB share at the specified local path with the given name and
        permissions. The local path is created if it does not exist.
    .PARAMETER LocalPath
        The local filesystem path to share.
    .PARAMETER ShareName
        The name of the share (default: "d3 Projects").
    .PARAMETER Permissions
        Permission string in the format "Account:Level" (default: "Administrators:Full").
        Level can be Full, Change, or Read.
    .OUTPUTS
        PSCustomObject with Success (bool) and Message (string) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$LocalPath,

        [string]$ShareName = 'd3 Projects',

        [string]$Permissions = 'Administrators:Full'
    )

    try {
        # Validate path format before any filesystem operations
        $pathValidation = Test-SharePathFormat -Path $LocalPath
        if (-not $pathValidation.IsValid) {
            Write-AppLog -Message "Share path validation failed for '$LocalPath': $($pathValidation.ErrorMessage)" -Level 'WARN'
            return [PSCustomObject]@{
                Success = $false
                Message = "Invalid share path: $($pathValidation.ErrorMessage)"
            }
        }

        # Validate and create path if needed
        if (-not (Test-Path -Path $LocalPath)) {
            Write-AppLog -Message "Path '$LocalPath' does not exist. Creating directory." -Level 'INFO'
            New-Item -Path $LocalPath -ItemType Directory -Force -ErrorAction Stop | Out-Null
        }

        # Parse permission string
        $parts = $Permissions -split ':'
        $account = if ($parts.Count -ge 1) { $parts[0] } else { 'Administrators' }
        $level   = if ($parts.Count -ge 2) { $parts[1] } else { 'Full' }

        # Check if share already exists
        $existingShare = $null
        try {
            $existingShare = Get-SmbShare -Name $ShareName -ErrorAction Stop
        }
        catch {
            # Share does not exist, which is expected
        }

        if ($existingShare) {
            Write-AppLog -Message "Share '$ShareName' already exists. Remove it first to recreate." -Level 'WARN'
            return [PSCustomObject]@{
                Success = $false
                Message = "Share '$ShareName' already exists. Remove it first or update its settings."
            }
        }

        # Create the share with the appropriate access level
        $shareParams = @{
            Name        = $ShareName
            Path        = $LocalPath
            Description = 'd3 Projects shared folder for disguise media server'
            ErrorAction = 'Stop'
        }

        switch ($level) {
            'Full'   { $shareParams['FullAccess']   = $account }
            'Change' { $shareParams['ChangeAccess'] = $account }
            'Read'   { $shareParams['ReadAccess']   = $account }
            default  { $shareParams['FullAccess']   = $account }
        }

        New-SmbShare @shareParams | Out-Null

        Write-AppLog -Message "Successfully created share '$ShareName' at '$LocalPath' with $level access for $account." -Level 'INFO'
        return [PSCustomObject]@{
            Success = $true
            Message = "Share '$ShareName' created successfully at '$LocalPath'."
        }
    }
    catch {
        Write-AppLog -Message "Failed to create share '$ShareName': $_" -Level 'ERROR'
        return [PSCustomObject]@{
            Success = $false
            Message = "Failed to create share: $_"
        }
    }
}

function Remove-D3Share {
    <#
    .SYNOPSIS
        Removes an existing SMB share.
    .PARAMETER ShareName
        The name of the share to remove.
    .OUTPUTS
        PSCustomObject with Success (bool) and Message (string) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$ShareName
    )

    try {
        Remove-SmbShare -Name $ShareName -Force -ErrorAction Stop
        Write-AppLog -Message "Successfully removed share '$ShareName'." -Level 'INFO'
        return [PSCustomObject]@{
            Success = $true
            Message = "Share '$ShareName' has been removed."
        }
    }
    catch {
        Write-AppLog -Message "Failed to remove share '$ShareName': $_" -Level 'ERROR'
        return [PSCustomObject]@{
            Success = $false
            Message = "Failed to remove share '$ShareName': $_"
        }
    }
}

function Set-D3SharePermissions {
    <#
    .SYNOPSIS
        Updates the permissions on an existing SMB share.
    .DESCRIPTION
        Grants the specified access right to the given account on the share.
        Revokes existing access for the account first to avoid conflicts.
    .PARAMETER ShareName
        The name of the share to modify.
    .PARAMETER AccountName
        The account to grant access to (e.g., "Everyone", "Administrators").
    .PARAMETER AccessRight
        The access level: Full, Change, or Read.
    .OUTPUTS
        PSCustomObject with Success (bool) and Message (string) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$ShareName,

        [Parameter(Mandatory = $true)]
        [string]$AccountName,

        [Parameter(Mandatory = $true)]
        [ValidateSet('Full', 'Change', 'Read')]
        [string]$AccessRight
    )

    try {
        # Revoke existing access for the account (ignore errors if no existing access)
        try {
            Revoke-SmbShareAccess -Name $ShareName -AccountName $AccountName -Force -ErrorAction Stop
            Write-AppLog -Message "Revoked existing access for '$AccountName' on '$ShareName'." -Level 'INFO'
        }
        catch {
            # No existing access to revoke; this is acceptable
            Write-AppLog -Message "No existing access to revoke for '$AccountName' on '$ShareName'." -Level 'DEBUG'
        }

        # Grant new access
        Grant-SmbShareAccess -Name $ShareName -AccountName $AccountName -AccessRight $AccessRight -Force -ErrorAction Stop | Out-Null

        Write-AppLog -Message "Granted $AccessRight access to '$AccountName' on share '$ShareName'." -Level 'INFO'
        return [PSCustomObject]@{
            Success = $true
            Message = "Granted $AccessRight access to '$AccountName' on '$ShareName'."
        }
    }
    catch {
        Write-AppLog -Message "Failed to set permissions on '$ShareName': $_" -Level 'ERROR'
        return [PSCustomObject]@{
            Success = $false
            Message = "Failed to set permissions: $_"
        }
    }
}

function Test-SharePathFormat {
    <#
    .SYNOPSIS
        Validates that a share path is a valid local path suitable for SMB sharing.
    .DESCRIPTION
        Checks that the path is not a UNC path (\\server\share), does not contain
        invalid path characters, and appears to be a valid local filesystem path.
    .PARAMETER Path
        The filesystem path to validate.
    .OUTPUTS
        PSCustomObject with IsValid (bool) and ErrorMessage (string) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    if ([string]::IsNullOrWhiteSpace($Path)) {
        return [PSCustomObject]@{ IsValid = $false; ErrorMessage = 'Path cannot be empty.' }
    }

    $trimmed = $Path.Trim()

    # Reject UNC paths - shares must be local paths
    if ($trimmed.StartsWith('\\')) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = 'UNC paths (\\server\share) are not allowed. Share paths must be local (e.g., D:\d3 Projects).'
        }
    }

    # Check for invalid path characters (excluding \ and : which are valid in Windows paths)
    $invalidChars = [System.IO.Path]::GetInvalidPathChars()
    foreach ($ch in $invalidChars) {
        if ($trimmed.Contains($ch)) {
            return [PSCustomObject]@{
                IsValid      = $false
                ErrorMessage = "Path contains an invalid character: '$ch'"
            }
        }
    }

    # Also reject these characters that are invalid in folder names on Windows
    $extraInvalid = @('*', '?', '"', '<', '>', '|')
    foreach ($ch in $extraInvalid) {
        if ($trimmed.Contains($ch)) {
            return [PSCustomObject]@{
                IsValid      = $false
                ErrorMessage = "Path contains an invalid character: '$ch'"
            }
        }
    }

    # Ensure the path looks like a rooted local path (e.g., C:\..., D:\...)
    if (-not [System.IO.Path]::IsPathRooted($trimmed)) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = 'Path must be an absolute local path (e.g., D:\d3 Projects).'
        }
    }

    return [PSCustomObject]@{ IsValid = $true; ErrorMessage = '' }
}

function Test-D3ProjectsPath {
    <#
    .SYNOPSIS
        Validates that a d3 projects path exists and is accessible.
    .PARAMETER Path
        The filesystem path to test.
    .OUTPUTS
        Boolean indicating whether the path exists and is accessible.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    try {
        $exists = Test-Path -Path $Path -ErrorAction Stop
        Write-AppLog -Message "Path test for '$Path': $exists" -Level 'DEBUG'
        return $exists
    }
    catch {
        Write-AppLog -Message "Error testing path '$Path': $_" -Level 'ERROR'
        return $false
    }
}

# ============================================================================
# UI View Function
# ============================================================================

function New-SMBView {
    <#
    .SYNOPSIS
        Creates the SMB File Sharing configuration view.
    .DESCRIPTION
        Builds the complete UI for managing d3 Projects SMB shares, including
        share creation, permissions, and additional share management.
    .PARAMETER ContentPanel
        The parent panel in which to render the view.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Panel]$ContentPanel
    )

    # Clear existing content
    $ContentPanel.Controls.Clear()
    $ContentPanel.SuspendLayout()

    # Create a scrollable container for all content
    $scrollPanel = New-ScrollPanel -X 0 -Y 0 -Width $ContentPanel.Width -Height $ContentPanel.Height

    # ---- Section Header ----
    $header = New-SectionHeader -Text "SMB File Sharing" -X 20 -Y 15 -Width 900
    $scrollPanel.Controls.Add($header)

    $subtitle = New-StyledLabel -Text "Manage d3 Projects and media share access" -X 20 -Y 55 -IsSecondary
    $scrollPanel.Controls.Add($subtitle)

    # ========================================================================
    # Card 1: d3 Projects Share
    # ========================================================================
    $card1 = New-StyledCard -Title "d3 Projects Share" -X 20 -Y 90 -Width 900 -Height 460

    $yPos = 45

    # -- Status badge --
    # Determine whether the d3 Projects share currently exists
    $d3ShareActive = $false
    $d3SharePath = ''
    try {
        $existingShare = Get-SmbShare -Name 'd3 Projects' -ErrorAction Stop
        $d3ShareActive = $true
        $d3SharePath = $existingShare.Path
    }
    catch {
        # Share does not exist
    }

    $statusType = if ($d3ShareActive) { 'Success' } else { 'Error' }
    $statusText = if ($d3ShareActive) { 'ACTIVE' } else { 'INACTIVE' }
    $statusBadge = New-StatusBadge -Text $statusText -X 780 -Y 15 -Type $statusType
    $statusBadge.Name = 'statusBadge'
    $card1.Controls.Add($statusBadge)

    # -- Share name --
    $lblShareName = New-StyledLabel -Text "Share Name:" -X 15 -Y $yPos -IsBold
    $card1.Controls.Add($lblShareName)

    $txtShareName = New-StyledTextBox -X 160 -Y $yPos -Width 350 -PlaceholderText "d3 Projects"
    $txtShareName.Name = 'txtShareName'
    if ($d3ShareActive) {
        $txtShareName.Text = 'd3 Projects'
        $txtShareName.ForeColor = $script:Theme.Text
    }
    $card1.Controls.Add($txtShareName)

    $yPos += 40

    # -- Local path --
    $lblLocalPath = New-StyledLabel -Text "Local Path:" -X 15 -Y $yPos -IsBold
    $card1.Controls.Add($lblLocalPath)

    $txtLocalPath = New-StyledTextBox -X 160 -Y $yPos -Width 350 -PlaceholderText "D:\d3 Projects"
    $txtLocalPath.Name = 'txtLocalPath'
    if ($d3ShareActive -and $d3SharePath) {
        $txtLocalPath.Text = $d3SharePath
        $txtLocalPath.ForeColor = $script:Theme.Text
    }
    $card1.Controls.Add($txtLocalPath)

    # Browse button
    $btnBrowse = New-StyledButton -Text "Browse..." -X 520 -Y $yPos -Width 90 -Height 28 -OnClick {
        $folderDialog = New-Object System.Windows.Forms.FolderBrowserDialog
        $folderDialog.Description = "Select the d3 Projects folder"
        $folderDialog.ShowNewFolderButton = $true

        if ($folderDialog.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
            $pathBox = $this.Parent.Controls['txtLocalPath']
            if ($pathBox) {
                $pathBox.Text = $folderDialog.SelectedPath
                $pathBox.ForeColor = $script:Theme.Text
            }
        }
    }
    $card1.Controls.Add($btnBrowse)

    $yPos += 30

    # -- Current path info --
    if ($d3ShareActive -and $d3SharePath) {
        $lblCurrentPath = New-StyledLabel -Text "Current shared path: $d3SharePath" -X 160 -Y $yPos -IsMuted -FontSize 8.5
        $card1.Controls.Add($lblCurrentPath)
    }

    $yPos += 30

    # -- Share checkbox --
    $chkShareEnabled = New-StyledCheckBox -Text "Share d3 Projects folder" -X 15 -Y $yPos
    $chkShareEnabled.Name = 'chkShareEnabled'
    $chkShareEnabled.Checked = $d3ShareActive
    $card1.Controls.Add($chkShareEnabled)

    $yPos += 40

    # -- Permissions section --
    $lblPermSection = New-StyledLabel -Text "Permissions" -X 15 -Y $yPos -IsBold -FontSize 10.5
    $card1.Controls.Add($lblPermSection)
    $yPos += 28

    # Current permissions display with clear permission type labels
    $permText = "No permissions loaded"
    if ($d3ShareActive) {
        try {
            $perms = Get-SharePermissions -ShareName 'd3 Projects'
            if ($perms -and $perms.Count -gt 0) {
                $permEntries = @()
                foreach ($perm in $perms) {
                    # Map AccessRight to human-readable label
                    $accessLabel = switch ($perm.AccessRight) {
                        'Full'   { 'Full Control' }
                        'Change' { 'Change (Read/Write)' }
                        'Read'   { 'Read Only' }
                        default  { $perm.AccessRight }
                    }
                    $controlLabel = if ($perm.AccessControlType -eq 'Deny') { '[DENY]' } else { '' }
                    $permEntries += "$($perm.AccountName) - $accessLabel $controlLabel".Trim()
                }
                $permText = $permEntries -join '  |  '
            }
        }
        catch {
            $permText = "Unable to retrieve permissions"
        }
    }

    $lblCurrentPerms = New-StyledLabel -Text "Current: $permText" -X 15 -Y $yPos -IsSecondary -FontSize 9 -MaxWidth 860
    $lblCurrentPerms.Name = 'lblCurrentPerms'
    $card1.Controls.Add($lblCurrentPerms)
    $yPos += 30

    # Account dropdown
    $lblAccount = New-StyledLabel -Text "Account:" -X 15 -Y $yPos
    $card1.Controls.Add($lblAccount)

    $cmbAccount = New-StyledComboBox -X 160 -Y $yPos -Width 200 -Items @('Administrators', 'Everyone', 'SYSTEM', 'Authenticated Users')
    $cmbAccount.Name = 'cmbAccount'
    $cmbAccount.SelectedIndex = 0
    $card1.Controls.Add($cmbAccount)

    # Access level dropdown
    $lblAccess = New-StyledLabel -Text "Access:" -X 380 -Y $yPos
    $card1.Controls.Add($lblAccess)

    $cmbAccess = New-StyledComboBox -X 450 -Y $yPos -Width 140 -Items @('Full', 'Change', 'Read')
    $cmbAccess.Name = 'cmbAccess'
    $cmbAccess.SelectedIndex = 0
    $card1.Controls.Add($cmbAccess)

    # Update Permissions button
    $btnUpdatePerms = New-StyledButton -Text "Update Permissions" -X 610 -Y $yPos -Width 150 -Height 28 -OnClick {
        $card = $this.Parent
        $shareName = $card.Controls['txtShareName'].Text
        $account = $card.Controls['cmbAccount'].SelectedItem
        $access = $card.Controls['cmbAccess'].SelectedItem

        if (-not $shareName -or $shareName -eq '') {
            $shareName = 'd3 Projects'
        }
        # Use placeholder fallback
        if ($shareName -eq $card.Controls['txtShareName'].Tag) {
            $shareName = 'd3 Projects'
        }

        if (-not $account -or -not $access) {
            [System.Windows.Forms.MessageBox]::Show(
                "Please select an account and access level.",
                "Missing Selection",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
            return
        }

        # Confirm permission change before applying
        $accessLabel = switch ($access) {
            'Full'   { 'Full Control' }
            'Change' { 'Change (Read/Write)' }
            'Read'   { 'Read Only' }
            default  { $access }
        }
        $confirmPerm = [System.Windows.Forms.MessageBox]::Show(
            "Are you sure you want to change permissions on '$shareName'?`n`nAccount: $account`nAccess: $accessLabel`n`nThis will revoke existing access for '$account' and grant $accessLabel.",
            "Confirm Permission Change",
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Question
        )
        if ($confirmPerm -ne [System.Windows.Forms.DialogResult]::Yes) { return }

        $result = Set-D3SharePermissions -ShareName $shareName -AccountName $account -AccessRight $access

        if ($result.Success) {
            [System.Windows.Forms.MessageBox]::Show(
                $result.Message,
                "Permissions Updated",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
            # Refresh permissions label with clear type labels
            $perms = Get-SharePermissions -ShareName $shareName
            if ($perms -and $perms.Count -gt 0) {
                $permEntries = @()
                foreach ($p in $perms) {
                    $aLabel = switch ($p.AccessRight) {
                        'Full'   { 'Full Control' }
                        'Change' { 'Change (Read/Write)' }
                        'Read'   { 'Read Only' }
                        default  { $p.AccessRight }
                    }
                    $cLabel = if ($p.AccessControlType -eq 'Deny') { '[DENY]' } else { '' }
                    $permEntries += "$($p.AccountName) - $aLabel $cLabel".Trim()
                }
                $card.Controls['lblCurrentPerms'].Text = "Current: $($permEntries -join '  |  ')"
            }
        }
        else {
            [System.Windows.Forms.MessageBox]::Show(
                $result.Message,
                "Permission Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }
    $card1.Controls.Add($btnUpdatePerms)

    $yPos += 45

    # -- Action buttons row --
    $btnApplyShare = New-StyledButton -Text "Apply Share Settings" -X 15 -Y $yPos -Width 180 -Height 35 -IsPrimary -OnClick {
        $card = $this.Parent
        $shareName = $card.Controls['txtShareName'].Text
        $localPath = $card.Controls['txtLocalPath'].Text
        $shareEnabled = $card.Controls['chkShareEnabled'].Checked
        $account = $card.Controls['cmbAccount'].SelectedItem
        $access = $card.Controls['cmbAccess'].SelectedItem

        # Handle placeholder text fallback
        if (-not $shareName -or $shareName -eq $card.Controls['txtShareName'].Tag) {
            $shareName = 'd3 Projects'
        }
        if (-not $localPath -or $localPath -eq $card.Controls['txtLocalPath'].Tag) {
            $localPath = 'D:\d3 Projects'
        }

        if (-not $shareEnabled) {
            [System.Windows.Forms.MessageBox]::Show(
                "The 'Share d3 Projects folder' checkbox is not checked. Enable it to create the share.",
                "Share Disabled",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
            return
        }

        # Validate path format first
        $pathCheck = Test-SharePathFormat -Path $localPath
        if (-not $pathCheck.IsValid) {
            [System.Windows.Forms.MessageBox]::Show(
                "Invalid share path: $($pathCheck.ErrorMessage)",
                "Path Validation Failed",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
            return
        }

        # Validate path exists or offer to create
        if (-not (Test-D3ProjectsPath -Path $localPath)) {
            $createDir = [System.Windows.Forms.MessageBox]::Show(
                "The path '$localPath' does not exist. Create it now?",
                "Path Not Found",
                [System.Windows.Forms.MessageBoxButtons]::YesNo,
                [System.Windows.Forms.MessageBoxIcon]::Question
            )
            if ($createDir -ne [System.Windows.Forms.DialogResult]::Yes) {
                return
            }
        }

        # Build permissions string
        if (-not $account) { $account = 'Administrators' }
        if (-not $access) { $access = 'Full' }
        $permString = "${account}:${access}"

        $result = New-D3ProjectShare -LocalPath $localPath -ShareName $shareName -Permissions $permString

        if ($result.Success) {
            [System.Windows.Forms.MessageBox]::Show(
                $result.Message,
                "Share Created",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
            # Refresh the view
            New-SMBView -ContentPanel $card.Parent.Parent
        }
        else {
            [System.Windows.Forms.MessageBox]::Show(
                $result.Message,
                "Share Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }
    $card1.Controls.Add($btnApplyShare)

    $btnRemoveShare = New-StyledButton -Text "Remove Share" -X 210 -Y $yPos -Width 140 -Height 35 -IsDestructive -OnClick {
        $card = $this.Parent
        $shareName = $card.Controls['txtShareName'].Text
        if (-not $shareName -or $shareName -eq $card.Controls['txtShareName'].Tag) {
            $shareName = 'd3 Projects'
        }

        $confirm = [System.Windows.Forms.MessageBox]::Show(
            "Are you sure you want to remove the share '$shareName'?`n`nThis will stop all network access to this folder. The local files will not be deleted.",
            "Confirm Share Removal",
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )

        if ($confirm -eq [System.Windows.Forms.DialogResult]::Yes) {
            $result = Remove-D3Share -ShareName $shareName
            if ($result.Success) {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Share Removed",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )
                # Refresh the view
                New-SMBView -ContentPanel $card.Parent.Parent
            }
            else {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Removal Error",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
            }
        }
    }
    $card1.Controls.Add($btnRemoveShare)

    $scrollPanel.Controls.Add($card1)

    # ========================================================================
    # Card 2: Additional Shares
    # ========================================================================
    $card2 = New-StyledCard -Title "Additional Shares" -X 20 -Y 570 -Width 900 -Height 360

    # DataGridView showing all system shares
    $dgv = New-StyledDataGridView -X 15 -Y 45 -Width 870 -Height 220
    $dgv.Name = 'dgvShares'
    $dgv.ReadOnly = $true

    # Define columns
    $colName = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colName.Name = 'ShareName'
    $colName.HeaderText = 'Name'
    $colName.FillWeight = 30

    $colPath = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colPath.Name = 'SharePath'
    $colPath.HeaderText = 'Path'
    $colPath.FillWeight = 50

    $colState = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colState.Name = 'ShareState'
    $colState.HeaderText = 'State'
    $colState.FillWeight = 20

    $dgv.Columns.Add($colName) | Out-Null
    $dgv.Columns.Add($colPath) | Out-Null
    $dgv.Columns.Add($colState) | Out-Null

    # Populate the grid with current shares
    try {
        $allShares = Get-D3ProjectShares
        foreach ($share in $allShares) {
            $dgv.Rows.Add($share.Name, $share.Path, $share.ShareState) | Out-Null
        }
    }
    catch {
        Write-AppLog -Message "Could not populate share grid: $_" -Level 'WARN'
    }

    $card2.Controls.Add($dgv)

    # Button row for Additional Shares card
    $btnRefresh = New-StyledButton -Text "Refresh" -X 15 -Y 275 -Width 100 -Height 32 -OnClick {
        $card = $this.Parent
        $grid = $card.Controls['dgvShares']
        $grid.Rows.Clear()
        try {
            $shares = Get-D3ProjectShares
            foreach ($s in $shares) {
                $grid.Rows.Add($s.Name, $s.Path, $s.ShareState) | Out-Null
            }
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show(
                "Failed to refresh shares: $_",
                "Refresh Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }
    $card2.Controls.Add($btnRefresh)

    $btnCreateNew = New-StyledButton -Text "Create New Share" -X 125 -Y 275 -Width 150 -Height 32 -OnClick {
        # Open a dialog form for creating a new share
        $dlg = New-Object System.Windows.Forms.Form
        $dlg.Text = "Create New SMB Share"
        $dlg.Size = New-Object System.Drawing.Size(450, 320)
        $dlg.StartPosition = [System.Windows.Forms.FormStartPosition]::CenterParent
        $dlg.FormBorderStyle = [System.Windows.Forms.FormBorderStyle]::FixedDialog
        $dlg.MaximizeBox = $false
        $dlg.MinimizeBox = $false
        $dlg.BackColor = $script:Theme.Background

        # Share name
        $lblDlgName = New-StyledLabel -Text "Share Name:" -X 15 -Y 20 -IsBold
        $dlg.Controls.Add($lblDlgName)
        $txtDlgName = New-StyledTextBox -X 140 -Y 20 -Width 270 -PlaceholderText "Enter share name"
        $txtDlgName.Name = 'txtDlgName'
        $dlg.Controls.Add($txtDlgName)

        # Local path
        $lblDlgPath = New-StyledLabel -Text "Local Path:" -X 15 -Y 65 -IsBold
        $dlg.Controls.Add($lblDlgPath)
        $txtDlgPath = New-StyledTextBox -X 140 -Y 65 -Width 200 -PlaceholderText "C:\SharedFolder"
        $txtDlgPath.Name = 'txtDlgPath'
        $dlg.Controls.Add($txtDlgPath)

        $btnDlgBrowse = New-StyledButton -Text "Browse..." -X 350 -Y 65 -Width 70 -Height 28 -OnClick {
            $fb = New-Object System.Windows.Forms.FolderBrowserDialog
            $fb.Description = "Select folder to share"
            $fb.ShowNewFolderButton = $true
            if ($fb.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
                $this.Parent.Controls['txtDlgPath'].Text = $fb.SelectedPath
                $this.Parent.Controls['txtDlgPath'].ForeColor = $script:Theme.Text
            }
        }
        $dlg.Controls.Add($btnDlgBrowse)

        # Account
        $lblDlgAccount = New-StyledLabel -Text "Account:" -X 15 -Y 110 -IsBold
        $dlg.Controls.Add($lblDlgAccount)
        $cmbDlgAccount = New-StyledComboBox -X 140 -Y 110 -Width 200 -Items @('Administrators', 'Everyone', 'SYSTEM', 'Authenticated Users')
        $cmbDlgAccount.Name = 'cmbDlgAccount'
        $cmbDlgAccount.SelectedIndex = 0
        $dlg.Controls.Add($cmbDlgAccount)

        # Access level
        $lblDlgAccess = New-StyledLabel -Text "Access Level:" -X 15 -Y 155 -IsBold
        $dlg.Controls.Add($lblDlgAccess)
        $cmbDlgAccess = New-StyledComboBox -X 140 -Y 155 -Width 200 -Items @('Full', 'Change', 'Read')
        $cmbDlgAccess.Name = 'cmbDlgAccess'
        $cmbDlgAccess.SelectedIndex = 0
        $dlg.Controls.Add($cmbDlgAccess)

        # Create button
        $btnDlgCreate = New-StyledButton -Text "Create Share" -X 140 -Y 210 -Width 140 -Height 35 -IsPrimary -OnClick {
            $form = $this.Parent
            $sName = $form.Controls['txtDlgName'].Text
            $sPath = $form.Controls['txtDlgPath'].Text
            $sAccount = $form.Controls['cmbDlgAccount'].SelectedItem
            $sAccess = $form.Controls['cmbDlgAccess'].SelectedItem

            # Handle placeholder text
            if ($sName -eq $form.Controls['txtDlgName'].Tag) { $sName = '' }
            if ($sPath -eq $form.Controls['txtDlgPath'].Tag) { $sPath = '' }

            if (-not $sName -or -not $sPath) {
                [System.Windows.Forms.MessageBox]::Show(
                    "Please enter both a share name and a local path.",
                    "Missing Input",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning
                )
                return
            }

            # Validate path format before creating
            $pathCheck = Test-SharePathFormat -Path $sPath
            if (-not $pathCheck.IsValid) {
                [System.Windows.Forms.MessageBox]::Show(
                    "Invalid share path: $($pathCheck.ErrorMessage)",
                    "Path Validation Failed",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
                return
            }

            $permString = "${sAccount}:${sAccess}"
            $result = New-D3ProjectShare -LocalPath $sPath -ShareName $sName -Permissions $permString

            if ($result.Success) {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Share Created",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )
                $form.DialogResult = [System.Windows.Forms.DialogResult]::OK
                $form.Close()
            }
            else {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Error",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
            }
        }
        $dlg.Controls.Add($btnDlgCreate)

        # Cancel button
        $btnDlgCancel = New-StyledButton -Text "Cancel" -X 290 -Y 210 -Width 100 -Height 35 -OnClick {
            $this.Parent.Close()
        }
        $dlg.Controls.Add($btnDlgCancel)

        # Show the dialog; refresh grid if a share was created
        if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
            $parentCard = $this.Parent
            $grid = $parentCard.Controls['dgvShares']
            $grid.Rows.Clear()
            try {
                $shares = Get-D3ProjectShares
                foreach ($s in $shares) {
                    $grid.Rows.Add($s.Name, $s.Path, $s.ShareState) | Out-Null
                }
            }
            catch {
                Write-AppLog -Message "Failed to refresh SMB shares list: $_" -Level 'WARN'
            }
        }
    }
    $card2.Controls.Add($btnCreateNew)

    $btnRemoveSelected = New-StyledButton -Text "Remove Selected" -X 285 -Y 275 -Width 150 -Height 32 -IsDestructive -OnClick {
        $card = $this.Parent
        $grid = $card.Controls['dgvShares']

        if ($grid.SelectedRows.Count -eq 0) {
            [System.Windows.Forms.MessageBox]::Show(
                "Please select a share to remove.",
                "No Selection",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
            return
        }

        $selectedName = $grid.SelectedRows[0].Cells['ShareName'].Value

        $confirm = [System.Windows.Forms.MessageBox]::Show(
            "Are you sure you want to remove the share '$selectedName'?",
            "Confirm Removal",
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )

        if ($confirm -eq [System.Windows.Forms.DialogResult]::Yes) {
            $result = Remove-D3Share -ShareName $selectedName
            if ($result.Success) {
                # Refresh grid
                $grid.Rows.Clear()
                try {
                    $shares = Get-D3ProjectShares
                    foreach ($s in $shares) {
                        $grid.Rows.Add($s.Name, $s.Path, $s.ShareState) | Out-Null
                    }
                }
                catch {
                    Write-AppLog -Message "Failed to refresh SMB shares after removal: $_" -Level 'WARN'
                }
            }
            else {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Removal Error",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
            }
        }
    }
    $card2.Controls.Add($btnRemoveSelected)

    $scrollPanel.Controls.Add($card2)

    # ========================================================================
    # Card 3: Quick Actions
    # ========================================================================
    $card3 = New-StyledCard -Title "Quick Actions" -X 20 -Y 950 -Width 900 -Height 200

    $hostname = $env:COMPUTERNAME
    if (-not $hostname) {
        try { $hostname = [System.Net.Dns]::GetHostName() } catch { $hostname = 'UNKNOWN' }
    }

    # Test Share Access button
    $btnTestAccess = New-StyledButton -Text "Test Share Access" -X 15 -Y 50 -Width 160 -Height 35 -OnClick {
        $card = $this.Parent
        $statusLabel = $card.Controls['lblQuickStatus']
        $statusLabel.Text = "Testing share access..."
        $statusLabel.ForeColor = $script:Theme.TextSecondary
        $statusLabel.Refresh()

        $hn = $env:COMPUTERNAME
        if (-not $hn) {
            try { $hn = [System.Net.Dns]::GetHostName() } catch { $hn = 'UNKNOWN' }
        }
        $uncPath = "\\$hn\d3 Projects"

        try {
            if (Test-Path -Path $uncPath -ErrorAction Stop) {
                $statusLabel.Text = "Share '$uncPath' is accessible."
                $statusLabel.ForeColor = $script:Theme.Success
            }
            else {
                $statusLabel.Text = "Share '$uncPath' is NOT accessible."
                $statusLabel.ForeColor = $script:Theme.Error
            }
        }
        catch {
            $statusLabel.Text = "Error testing share: $_"
            $statusLabel.ForeColor = $script:Theme.Error
        }
    }
    $card3.Controls.Add($btnTestAccess)

    # Open in Explorer button
    $btnOpenExplorer = New-StyledButton -Text "Open Share in Explorer" -X 190 -Y 50 -Width 180 -Height 35 -OnClick {
        try {
            # Try to find the d3 Projects share path
            $sharePath = $null
            try {
                $shareInfo = Get-SmbShare -Name 'd3 Projects' -ErrorAction Stop
                $sharePath = $shareInfo.Path
            }
            catch {
                $sharePath = 'D:\d3 Projects'
            }

            if (Test-Path -Path $sharePath -ErrorAction SilentlyContinue) {
                Start-Process explorer.exe -ArgumentList $sharePath
            }
            else {
                [System.Windows.Forms.MessageBox]::Show(
                    "The path '$sharePath' does not exist.",
                    "Path Not Found",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning
                )
            }
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show(
                "Failed to open Explorer: $_",
                "Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }
    $card3.Controls.Add($btnOpenExplorer)

    # Copy UNC Path button
    $btnCopyUNC = New-StyledButton -Text "Copy UNC Path" -X 385 -Y 50 -Width 150 -Height 35 -OnClick {
        $hn = $env:COMPUTERNAME
        if (-not $hn) {
            try { $hn = [System.Net.Dns]::GetHostName() } catch { $hn = 'UNKNOWN' }
        }
        $uncPath = "\\$hn\d3 Projects"
        try {
            [System.Windows.Forms.Clipboard]::SetText($uncPath)
            $card = $this.Parent
            $statusLabel = $card.Controls['lblQuickStatus']
            $statusLabel.Text = "Copied to clipboard: $uncPath"
            $statusLabel.ForeColor = $script:Theme.Success
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show(
                "Failed to copy to clipboard: $_",
                "Clipboard Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }
    $card3.Controls.Add($btnCopyUNC)

    # Status area
    $lblQuickStatus = New-StyledLabel -Text "UNC Path: \\$hostname\d3 Projects" -X 15 -Y 100 -IsSecondary -FontSize 9 -MaxWidth 860
    $lblQuickStatus.Name = 'lblQuickStatus'
    $card3.Controls.Add($lblQuickStatus)

    $scrollPanel.Controls.Add($card3)

    # Add scroll panel to content panel
    $ContentPanel.Controls.Add($scrollPanel)
    $ContentPanel.ResumeLayout()
}

# ============================================================
# MODULE: ServerIdentity.ps1
# ============================================================
# ServerIdentity.ps1 - DISGUISE BUDDY Server Identity Configuration Module
# Manages server hostname and system identification for disguise (d3) media servers.
# The hostname is critical for d3Net discovery, UNC paths, and API access.

# ============================================================================
# Backend Functions
# ============================================================================

function Get-ServerHostname {
    <#
    .SYNOPSIS
        Returns the current computer hostname.
    .DESCRIPTION
        Retrieves the hostname using environment variables with a DNS fallback.
    .OUTPUTS
        String containing the current computer hostname.
    #>
    try {
        $hostname = $env:COMPUTERNAME
        if (-not $hostname) {
            $hostname = [System.Net.Dns]::GetHostName()
        }
        Write-AppLog -Message "Retrieved server hostname: $hostname" -Level 'DEBUG'
        return $hostname
    }
    catch {
        Write-AppLog -Message "Failed to retrieve hostname: $_" -Level 'ERROR'
        return 'UNKNOWN'
    }
}

function Set-ServerHostname {
    <#
    .SYNOPSIS
        Changes the computer hostname.
    .DESCRIPTION
        Validates the proposed hostname against Windows NetBIOS naming rules
        and applies the change using Rename-Computer. A restart is required
        for the change to take full effect.
    .PARAMETER NewName
        The new hostname to assign to the computer.
    .OUTPUTS
        PSCustomObject with Success (bool), Message (string), and RestartRequired (bool) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$NewName
    )

    # Validate the hostname first
    $validation = Test-ServerHostname -Name $NewName
    if (-not $validation.IsValid) {
        Write-AppLog -Message "Hostname validation failed for '$NewName': $($validation.ErrorMessage)" -Level 'WARN'
        return [PSCustomObject]@{
            Success         = $false
            Message         = "Invalid hostname: $($validation.ErrorMessage)"
            RestartRequired = $false
        }
    }

    try {
        Rename-Computer -NewName $NewName -Force -ErrorAction Stop
        Write-AppLog -Message "Hostname change to '$NewName' applied successfully. Restart required." -Level 'INFO'
        return [PSCustomObject]@{
            Success         = $true
            Message         = "Hostname will change to '$NewName' after the next restart."
            RestartRequired = $true
        }
    }
    catch {
        Write-AppLog -Message "Failed to change hostname to '$NewName': $_" -Level 'ERROR'
        return [PSCustomObject]@{
            Success         = $false
            Message         = "Failed to change hostname: $_"
            RestartRequired = $false
        }
    }
}

function Test-ServerHostname {
    <#
    .SYNOPSIS
        Validates a proposed hostname against Windows NetBIOS naming rules.
    .DESCRIPTION
        Checks: max 15 chars, alphanumeric + hyphens only, no spaces,
        cannot start or end with a hyphen, must not be empty.
    .PARAMETER Name
        The hostname string to validate.
    .OUTPUTS
        PSCustomObject with IsValid (bool) and ErrorMessage (string) properties.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    # Empty check
    if ([string]::IsNullOrWhiteSpace($Name)) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname cannot be empty."
        }
    }

    # Length check (NetBIOS limit: 15 characters)
    if ($Name.Length -gt 15) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname exceeds 15 characters (NetBIOS limit). Current length: $($Name.Length)."
        }
    }

    # No spaces allowed
    if ($Name -match '\s') {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname cannot contain spaces."
        }
    }

    # Alphanumeric and hyphens only
    if ($Name -notmatch '^[a-zA-Z0-9-]+$') {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname can only contain letters (A-Z), numbers (0-9), and hyphens (-)."
        }
    }

    # Cannot start with a hyphen
    if ($Name.StartsWith('-')) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname cannot start with a hyphen."
        }
    }

    # Cannot end with a hyphen
    if ($Name.EndsWith('-')) {
        return [PSCustomObject]@{
            IsValid      = $false
            ErrorMessage = "Hostname cannot end with a hyphen."
        }
    }

    # All checks passed
    return [PSCustomObject]@{
        IsValid      = $true
        ErrorMessage = ''
    }
}

function Get-ServerSystemInfo {
    <#
    .SYNOPSIS
        Gets system information for display in the Server Identity view.
    .DESCRIPTION
        Queries WMI/CIM for computer system details including hostname,
        domain/workgroup, OS version, uptime, serial number, and model.
    .OUTPUTS
        PSCustomObject with Hostname, Domain, DomainType, OSVersion, Uptime,
        SerialNumber, and Model properties.
    #>
    try {
        $cs = Get-CimInstance -ClassName Win32_ComputerSystem -ErrorAction Stop
        $os = Get-CimInstance -ClassName Win32_OperatingSystem -ErrorAction Stop
        $bios = Get-CimInstance -ClassName Win32_BIOS -ErrorAction Stop

        # Determine domain vs workgroup
        $domainType = if ($cs.PartOfDomain) { 'Domain' } else { 'Workgroup' }
        $domainName = if ($cs.PartOfDomain) { $cs.Domain } else { $cs.Workgroup }

        # Calculate uptime
        $uptime = (Get-Date) - $os.LastBootUpTime
        $uptimeStr = "{0}d {1}h {2}m" -f $uptime.Days, $uptime.Hours, $uptime.Minutes

        $info = [PSCustomObject]@{
            Hostname     = $cs.Name
            Domain       = $domainName
            DomainType   = $domainType
            OSVersion    = "$($os.Caption) ($($os.Version))"
            Uptime       = $uptimeStr
            SerialNumber = $bios.SerialNumber
            Model        = "$($cs.Manufacturer) $($cs.Model)"
        }

        Write-AppLog -Message "Retrieved system info for '$($cs.Name)'." -Level 'DEBUG'
        return $info
    }
    catch {
        Write-AppLog -Message "Failed to retrieve system info: $_" -Level 'ERROR'

        # Return partial info using fallback methods
        $hostname = $env:COMPUTERNAME
        if (-not $hostname) {
            try { $hostname = [System.Net.Dns]::GetHostName() } catch { $hostname = 'UNKNOWN' }
        }

        return [PSCustomObject]@{
            Hostname     = $hostname
            Domain       = 'Unknown'
            DomainType   = 'Unknown'
            OSVersion    = [System.Environment]::OSVersion.VersionString
            Uptime       = 'Unknown'
            SerialNumber = 'Unknown'
            Model        = 'Unknown'
        }
    }
}

# ============================================================================
# UI View Function
# ============================================================================

function New-ServerIdentityView {
    <#
    .SYNOPSIS
        Creates the Server Identity configuration view.
    .DESCRIPTION
        Builds the complete UI for viewing and changing the server hostname,
        displaying system information, and providing naming convention guidance.
    .PARAMETER ContentPanel
        The parent panel in which to render the view.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Panel]$ContentPanel
    )

    # Clear existing content
    $ContentPanel.Controls.Clear()
    $ContentPanel.SuspendLayout()

    # Create a scrollable container for all content
    $scrollPanel = New-ScrollPanel -X 0 -Y 0 -Width $ContentPanel.Width -Height $ContentPanel.Height

    # ---- Section Header ----
    $header = New-SectionHeader -Text "Server Identity" -X 20 -Y 15 -Width 900
    $scrollPanel.Controls.Add($header)

    $subtitle = New-StyledLabel -Text "Manage server hostname and system identification" -X 20 -Y 55 -IsSecondary
    $scrollPanel.Controls.Add($subtitle)

    # Retrieve system information once for use across all cards
    $sysInfo = Get-ServerSystemInfo

    # ========================================================================
    # Card 1: Current Identity
    # ========================================================================
    $card1 = New-StyledCard -Title "Current Identity" -X 20 -Y 90 -Width 900 -Height 300

    # Status badge: Domain-joined vs Workgroup
    $domainStatusType = if ($sysInfo.DomainType -eq 'Domain') { 'Info' } else { 'Warning' }
    $domainStatusText = if ($sysInfo.DomainType -eq 'Domain') { "DOMAIN: $($sysInfo.Domain)" } else { "WORKGROUP: $($sysInfo.Domain)" }
    $domainBadge = New-StatusBadge -Text $domainStatusText -X 680 -Y 15 -Type $domainStatusType
    $card1.Controls.Add($domainBadge)

    # Large hostname display
    $lblHostnameValue = New-StyledLabel -Text $sysInfo.Hostname -X 15 -Y 50 -FontSize 18 -IsBold
    $lblHostnameValue.ForeColor = $script:Theme.Primary
    $card1.Controls.Add($lblHostnameValue)

    $lblHostnameHint = New-StyledLabel -Text "Server Hostname" -X 15 -Y 85 -IsMuted -FontSize 9
    $card1.Controls.Add($lblHostnameHint)

    # System info grid displayed inside a clean sub-panel with aligned columns
    $infoPanel = New-Object System.Windows.Forms.Panel
    $infoPanel.Location = New-Object System.Drawing.Point(15, 110)
    $infoPanel.Size = New-Object System.Drawing.Size(860, 170)
    $infoPanel.BackColor = $script:Theme.Surface

    # Separator line above the info panel
    $infoSep = New-Object System.Windows.Forms.Panel
    $infoSep.Location = New-Object System.Drawing.Point(0, 0)
    $infoSep.Size = New-Object System.Drawing.Size(860, 1)
    $infoSep.BackColor = $script:Theme.Border
    $infoPanel.Controls.Add($infoSep)

    $infoRowHeight = 26
    $infoY = 12

    # Left column: labels at X=10, values at X=130
    $leftLabelX = 10
    $leftValueX = 130
    # Right column: labels at X=440, values at X=560
    $rightLabelX = 440
    $rightValueX = 560

    # Row 1: OS (left), Domain/Workgroup (right)
    $lblOS = New-StyledLabel -Text "OS:" -X $leftLabelX -Y $infoY -IsBold -FontSize 9.5
    $infoPanel.Controls.Add($lblOS)
    $lblOSValue = New-StyledLabel -Text $sysInfo.OSVersion -X $leftValueX -Y $infoY -FontSize 9.5 -MaxWidth 290
    $infoPanel.Controls.Add($lblOSValue)

    $lblDomain = New-StyledLabel -Text "$($sysInfo.DomainType):" -X $rightLabelX -Y $infoY -IsBold -FontSize 9.5
    $infoPanel.Controls.Add($lblDomain)
    $lblDomainValue = New-StyledLabel -Text $sysInfo.Domain -X $rightValueX -Y $infoY -FontSize 9.5 -MaxWidth 280
    $infoPanel.Controls.Add($lblDomainValue)
    $infoY += $infoRowHeight

    # Row 2: Uptime (left), Model (right)
    $lblUptime = New-StyledLabel -Text "Uptime:" -X $leftLabelX -Y $infoY -IsBold -FontSize 9.5
    $infoPanel.Controls.Add($lblUptime)
    $lblUptimeValue = New-StyledLabel -Text $sysInfo.Uptime -X $leftValueX -Y $infoY -FontSize 9.5
    $infoPanel.Controls.Add($lblUptimeValue)

    $lblModel = New-StyledLabel -Text "Model:" -X $rightLabelX -Y $infoY -IsBold -FontSize 9.5
    $infoPanel.Controls.Add($lblModel)
    $lblModelValue = New-StyledLabel -Text $sysInfo.Model -X $rightValueX -Y $infoY -FontSize 9.5 -MaxWidth 280
    $infoPanel.Controls.Add($lblModelValue)
    $infoY += $infoRowHeight

    # Row 3: Serial Number (left - spanning)
    $lblSerial = New-StyledLabel -Text "Serial Number:" -X $leftLabelX -Y $infoY -IsBold -FontSize 9.5
    $infoPanel.Controls.Add($lblSerial)
    $lblSerialValue = New-StyledLabel -Text $sysInfo.SerialNumber -X $leftValueX -Y $infoY -FontSize 9.5
    $infoPanel.Controls.Add($lblSerialValue)

    $card1.Controls.Add($infoPanel)

    $scrollPanel.Controls.Add($card1)

    # ========================================================================
    # Card 2: Change Hostname
    # ========================================================================
    $card2 = New-StyledCard -Title "Change Hostname" -X 20 -Y 410 -Width 900 -Height 450

    $yPos = 45

    # Prominent restart warning panel with distinct visual styling
    $warningPanel = New-Object System.Windows.Forms.Panel
    $warningPanel.Location = New-Object System.Drawing.Point(15, $yPos)
    $warningPanel.Size = New-Object System.Drawing.Size(860, 50)
    $warningPanel.BackColor = [System.Drawing.Color]::FromArgb(50, 245, 158, 11)  # Semi-transparent warning

    # Warning accent bar on the left
    $warningAccent = New-Object System.Windows.Forms.Panel
    $warningAccent.Location = New-Object System.Drawing.Point(0, 0)
    $warningAccent.Size = New-Object System.Drawing.Size(4, 50)
    $warningAccent.BackColor = $script:Theme.Warning
    $warningPanel.Controls.Add($warningAccent)

    # Warning icon/label
    $lblWarningIcon = New-Object System.Windows.Forms.Label
    $lblWarningIcon.Text = [char]0x26A0  # Warning triangle
    $lblWarningIcon.Location = New-Object System.Drawing.Point(14, 6)
    $lblWarningIcon.AutoSize = $true
    $lblWarningIcon.Font = New-Object System.Drawing.Font('Segoe UI', 16)
    $lblWarningIcon.ForeColor = $script:Theme.Warning
    $warningPanel.Controls.Add($lblWarningIcon)

    $lblWarningTitle = New-Object System.Windows.Forms.Label
    $lblWarningTitle.Text = "RESTART REQUIRED"
    $lblWarningTitle.Location = New-Object System.Drawing.Point(44, 5)
    $lblWarningTitle.AutoSize = $true
    $lblWarningTitle.Font = New-Object System.Drawing.Font('Segoe UI', 10, [System.Drawing.FontStyle]::Bold)
    $lblWarningTitle.ForeColor = $script:Theme.Warning
    $warningPanel.Controls.Add($lblWarningTitle)

    $lblWarningDetail = New-Object System.Windows.Forms.Label
    $lblWarningDetail.Text = "Changing the hostname requires a system restart. All active d3Net sessions and UNC share connections will be disrupted."
    $lblWarningDetail.Location = New-Object System.Drawing.Point(44, 26)
    $lblWarningDetail.AutoSize = $false
    $lblWarningDetail.Size = New-Object System.Drawing.Size(800, 18)
    $lblWarningDetail.Font = New-Object System.Drawing.Font('Segoe UI', 8.5)
    $lblWarningDetail.ForeColor = $script:Theme.Text
    $warningPanel.Controls.Add($lblWarningDetail)

    $card2.Controls.Add($warningPanel)

    $yPos += 60

    # Current hostname
    $lblCurrentHost = New-StyledLabel -Text "Current Hostname:" -X 15 -Y $yPos -IsBold
    $card2.Controls.Add($lblCurrentHost)
    $lblCurrentHostValue = New-StyledLabel -Text $sysInfo.Hostname -X 200 -Y $yPos
    $card2.Controls.Add($lblCurrentHostValue)

    $yPos += 38

    # New hostname input
    $lblNewHost = New-StyledLabel -Text "New Hostname:" -X 15 -Y $yPos -IsBold
    $card2.Controls.Add($lblNewHost)

    $txtNewHostname = New-StyledTextBox -X 200 -Y $yPos -Width 300 -PlaceholderText "e.g., MYSHOW-D3-01"
    $txtNewHostname.Name = 'txtNewHostname'
    $card2.Controls.Add($txtNewHostname)

    # Character count label
    $lblCharCount = New-StyledLabel -Text "0/15 characters" -X 510 -Y ($yPos + 4) -IsMuted -FontSize 8.5
    $lblCharCount.Name = 'lblCharCount'
    $card2.Controls.Add($lblCharCount)

    $yPos += 28

    # NetBIOS rules reminder text near the input
    $lblNetBIOSRules = New-StyledLabel -Text "NetBIOS rules: Max 15 chars, A-Z / 0-9 / hyphens only, cannot start or end with hyphen" `
                                       -X 200 -Y $yPos -IsMuted -FontSize 8 -MaxWidth 680
    $lblNetBIOSRules.Name = 'lblNetBIOSRules'
    $card2.Controls.Add($lblNetBIOSRules)

    $yPos += 22

    # Validation feedback label
    $lblValidation = New-StyledLabel -Text "" -X 200 -Y $yPos -FontSize 9 -MaxWidth 680
    $lblValidation.Name = 'lblValidation'
    $card2.Controls.Add($lblValidation)

    # Real-time validation on text change
    $txtNewHostname.Add_TextChanged({
        $card = $this.Parent
        $validationLabel = $card.Controls['lblValidation']
        $charCountLabel = $card.Controls['lblCharCount']
        $rulesLabel = $card.Controls['lblNetBIOSRules']
        $previewPanel = $card.Controls['pnlPreview']
        $inputText = $this.Text

        # Handle placeholder text (do not validate the placeholder)
        if ($inputText -eq $this.Tag) {
            $validationLabel.Text = ''
            $charCountLabel.Text = '0/15 characters'
            $charCountLabel.ForeColor = $script:Theme.TextMuted
            $this.BackColor = $script:Theme.InputBackground
            if ($rulesLabel) { $rulesLabel.ForeColor = $script:Theme.TextMuted }
            if ($previewPanel) { $previewPanel.Visible = $false }
            return
        }

        # Update character count with visual feedback
        $len = $inputText.Length
        $charCountLabel.Text = "$len/15 characters"
        if ($len -gt 15) {
            $charCountLabel.ForeColor = $script:Theme.Error
            $charCountLabel.Font = New-Object System.Drawing.Font('Segoe UI', 8.5, [System.Drawing.FontStyle]::Bold)
        }
        elseif ($len -gt 12) {
            $charCountLabel.ForeColor = $script:Theme.Warning
            $charCountLabel.Font = New-Object System.Drawing.Font('Segoe UI', 8.5, [System.Drawing.FontStyle]::Bold)
        }
        else {
            $charCountLabel.ForeColor = $script:Theme.TextMuted
            $charCountLabel.Font = New-Object System.Drawing.Font('Segoe UI', 8.5)
        }

        if ([string]::IsNullOrWhiteSpace($inputText)) {
            $validationLabel.Text = ''
            $this.BackColor = $script:Theme.InputBackground
            if ($rulesLabel) { $rulesLabel.ForeColor = $script:Theme.TextMuted }
            if ($previewPanel) { $previewPanel.Visible = $false }
            return
        }

        # Check for invalid characters and highlight which ones
        $invalidFound = @()
        foreach ($ch in $inputText.ToCharArray()) {
            if ($ch -notmatch '[a-zA-Z0-9\-]') {
                if ($invalidFound -notcontains $ch) {
                    $invalidFound += $ch
                }
            }
        }

        # Run validation
        $result = Test-ServerHostname -Name $inputText
        if ($result.IsValid) {
            $validationLabel.Text = "[OK] Valid hostname"
            $validationLabel.ForeColor = $script:Theme.Success
            $this.BackColor = $script:Theme.InputBackground
            if ($rulesLabel) { $rulesLabel.ForeColor = $script:Theme.TextMuted }
            if ($previewPanel) { $previewPanel.Visible = $true }
        }
        else {
            # Build detailed error with invalid character callout
            $errText = "[X] $($result.ErrorMessage)"
            if ($invalidFound.Count -gt 0) {
                $badChars = ($invalidFound | ForEach-Object { "'$_'" }) -join ', '
                $errText = "[X] Invalid characters found: $badChars -- Only A-Z, 0-9, and hyphens are allowed."
            }
            $validationLabel.Text = $errText
            $validationLabel.ForeColor = $script:Theme.Error
            # Tint the textbox background to indicate error
            $this.BackColor = [System.Drawing.Color]::FromArgb(40, 239, 68, 68)
            if ($rulesLabel) { $rulesLabel.ForeColor = $script:Theme.Warning }
            if ($previewPanel) { $previewPanel.Visible = $false }
        }

        # Update preview content if valid
        if ($result.IsValid -and $previewPanel) {
            $lblPreviewUNC = $previewPanel.Controls['lblPreviewUNC']
            $lblPreviewD3Net = $previewPanel.Controls['lblPreviewD3Net']
            $lblPreviewAPI = $previewPanel.Controls['lblPreviewAPI']
            if ($lblPreviewUNC)   { $lblPreviewUNC.Text   = "UNC Path:    \\$inputText\d3 Projects" }
            if ($lblPreviewD3Net) { $lblPreviewD3Net.Text = "d3Net Name:  $inputText" }
            if ($lblPreviewAPI)   { $lblPreviewAPI.Text   = "API Access:  http://${inputText}:80/api/..." }
        }
    })

    $yPos += 30

    # Preview Changes section
    $lblPreviewTitle = New-StyledLabel -Text "Preview Changes:" -X 15 -Y $yPos -IsBold -FontSize 10.5
    $card2.Controls.Add($lblPreviewTitle)

    $yPos += 28

    $pnlPreview = New-StyledPanel -X 15 -Y $yPos -Width 860 -Height 100 -IsCard
    $pnlPreview.Name = 'pnlPreview'
    $pnlPreview.Visible = $false

    $lblPreviewUNC = New-StyledLabel -Text "UNC Path:    \\NEWNAME\d3 Projects" -X 10 -Y 10 -FontSize 9.5 -MaxWidth 830
    $lblPreviewUNC.Name = 'lblPreviewUNC'
    $lblPreviewUNC.Font = New-Object System.Drawing.Font('Consolas', 9.5)
    $pnlPreview.Controls.Add($lblPreviewUNC)

    $lblPreviewD3Net = New-StyledLabel -Text "d3Net Name:  NEWNAME" -X 10 -Y 35 -FontSize 9.5 -MaxWidth 830
    $lblPreviewD3Net.Name = 'lblPreviewD3Net'
    $lblPreviewD3Net.Font = New-Object System.Drawing.Font('Consolas', 9.5)
    $pnlPreview.Controls.Add($lblPreviewD3Net)

    $lblPreviewAPI = New-StyledLabel -Text "API Access:  http://NEWNAME:80/api/..." -X 10 -Y 60 -FontSize 9.5 -MaxWidth 830
    $lblPreviewAPI.Name = 'lblPreviewAPI'
    $lblPreviewAPI.Font = New-Object System.Drawing.Font('Consolas', 9.5)
    $pnlPreview.Controls.Add($lblPreviewAPI)

    $card2.Controls.Add($pnlPreview)

    $yPos += 115

    # Apply Hostname Change button
    $btnApplyHostname = New-StyledButton -Text "Apply Hostname Change" -X 15 -Y $yPos -Width 200 -Height 40 -IsPrimary -OnClick {
        $card = $this.Parent
        $newName = $card.Controls['txtNewHostname'].Text

        # Handle placeholder text
        if (-not $newName -or $newName -eq $card.Controls['txtNewHostname'].Tag) {
            [System.Windows.Forms.MessageBox]::Show(
                "Please enter a new hostname.",
                "No Hostname Entered",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
            return
        }

        # Validate before proceeding
        $validation = Test-ServerHostname -Name $newName
        if (-not $validation.IsValid) {
            [System.Windows.Forms.MessageBox]::Show(
                "Invalid hostname: $($validation.ErrorMessage)",
                "Validation Failed",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
            return
        }

        $currentHostname = Get-ServerHostname

        # Confirmation dialog with detailed warning
        $confirmMsg = @"
Are you sure you want to change the hostname?

Current:  $currentHostname
New:      $newName

This change will affect:
  - d3Net discovery name
  - UNC share paths (\\$currentHostname\... will become \\$newName\...)
  - API endpoint addresses
  - Any scripts or configurations referencing this hostname

A RESTART IS REQUIRED for the change to take effect.
All active d3 sessions will be disconnected.
"@

        $confirm = [System.Windows.Forms.MessageBox]::Show(
            $confirmMsg,
            "Confirm Hostname Change",
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )

        if ($confirm -eq [System.Windows.Forms.DialogResult]::Yes) {
            $result = Set-ServerHostname -NewName $newName

            if ($result.Success) {
                $restartMsg = "$($result.Message)`n`nWould you like to restart now?"
                $restartChoice = [System.Windows.Forms.MessageBox]::Show(
                    $restartMsg,
                    "Hostname Changed - Restart Required",
                    [System.Windows.Forms.MessageBoxButtons]::YesNo,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )

                if ($restartChoice -eq [System.Windows.Forms.DialogResult]::Yes) {
                    try {
                        Restart-Computer -Force
                    }
                    catch {
                        [System.Windows.Forms.MessageBox]::Show(
                            "Failed to initiate restart: $_`n`nPlease restart manually.",
                            "Restart Failed",
                            [System.Windows.Forms.MessageBoxButtons]::OK,
                            [System.Windows.Forms.MessageBoxIcon]::Error
                        )
                    }
                }
            }
            else {
                [System.Windows.Forms.MessageBox]::Show(
                    $result.Message,
                    "Hostname Change Failed",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error
                )
            }
        }
    }
    $card2.Controls.Add($btnApplyHostname)

    $scrollPanel.Controls.Add($card2)

    # ========================================================================
    # Card 3: Naming Conventions
    # ========================================================================
    $card3 = New-StyledCard -Title "Naming Conventions" -X 20 -Y 880 -Width 900 -Height 260

    $yPos = 50

    # Info icon-style indicator
    $infoBadge = New-StatusBadge -Text "INFO" -X 820 -Y 15 -Type Info
    $card3.Controls.Add($infoBadge)

    # Recommended format
    $lblRecFormat = New-StyledLabel -Text "Recommended Format" -X 15 -Y $yPos -IsBold -FontSize 10.5
    $card3.Controls.Add($lblRecFormat)
    $yPos += 25

    $lblFormatExample = New-StyledLabel -Text "{SHOW}-{ROLE}-{NUMBER}" -X 15 -Y $yPos -FontSize 11
    $lblFormatExample.Font = New-Object System.Drawing.Font('Consolas', 11, [System.Drawing.FontStyle]::Bold)
    $lblFormatExample.ForeColor = $script:Theme.Accent
    $card3.Controls.Add($lblFormatExample)

    $lblFormatDesc = New-StyledLabel -Text "Example: MYSHOW-D3-01, CONCERT-GX3-02, TOUR24-UDX-01" -X 350 -Y ($yPos + 2) -IsSecondary -FontSize 9.5
    $card3.Controls.Add($lblFormatDesc)
    $yPos += 38

    # Separator line
    $separator = New-Object System.Windows.Forms.Panel
    $separator.Location = New-Object System.Drawing.Point(15, $yPos)
    $separator.Size = New-Object System.Drawing.Size(860, 1)
    $separator.BackColor = $script:Theme.Border
    $card3.Controls.Add($separator)
    $yPos += 15

    # Guidelines list
    $guidelines = @(
        "NetBIOS limit: 15 characters maximum",
        "Use only letters (A-Z), numbers (0-9), and hyphens (-)",
        "Avoid spaces, underscores, and special characters",
        "The hostname is used for d3Net discovery, UNC share paths (\\hostname\d3 Projects\), and API access"
    )

    foreach ($guideline in $guidelines) {
        $bulletLabel = New-StyledLabel -Text $guideline -X 30 -Y $yPos -FontSize 9.5 -MaxWidth 830
        $card3.Controls.Add($bulletLabel)

        # Bullet point marker
        $bulletMarker = New-StyledLabel -Text "`u{2022}" -X 15 -Y $yPos -FontSize 9.5
        $bulletMarker.ForeColor = $script:Theme.Primary
        $card3.Controls.Add($bulletMarker)

        $yPos += 25
    }

    $scrollPanel.Controls.Add($card3)

    # Add scroll panel to content panel
    $ContentPanel.Controls.Add($scrollPanel)
    $ContentPanel.ResumeLayout()
}

# ============================================================
# MODULE: Discovery.ps1
# ============================================================
﻿# Discovery.ps1 - DISGUISE BUDDY Network Discovery and Deployment Module
# Provides functions for scanning networks, discovering disguise (d3) media servers,
# testing connections, retrieving remote server info, and pushing configuration profiles.
# Also provides the New-DeployView UI function for the Network Deploy panel.

# ============================================================================
# Application state is initialized in DisguiseBuddy.ps1 before modules load
# ============================================================================

# ============================================================================
# Backend Functions
# ============================================================================

function Find-DisguiseServers {
    <#
    .SYNOPSIS
        Scans a subnet for disguise (d3) media servers using multiple discovery strategies.
    .DESCRIPTION
        Performs a parallel network scan across a given IP range using:
          1. Async TCP port probes on ports 80 (API) and 873 (rsync)
          2. Ping sweep via Test-Connection
          3. HTTP probe against the disguise REST API at /api/service/system
        Results are aggregated and returned as an array of server descriptor objects.
    .PARAMETER SubnetBase
        The first three octets of the target subnet (e.g. "10.0.0").
    .PARAMETER StartIP
        The starting value for the fourth octet. Default 1.
    .PARAMETER EndIP
        The ending value for the fourth octet. Default 254.
    .PARAMETER TimeoutMs
        Timeout in milliseconds for each TCP connection attempt. Default 200.
    .PARAMETER ProgressCallback
        Optional scriptblock invoked with (currentIP, percentComplete, statusMessage) for progress reporting.
    .OUTPUTS
        Array of PSCustomObjects with properties:
          IPAddress, Hostname, IsDisguise, ResponseTimeMs, Ports, APIVersion
    #>
    [CmdletBinding()]
    param(
        [string]$SubnetBase = "10.0.0",
        [int]$StartIP = 1,
        [int]$EndIP = 254,
        [ValidateRange(50, 5000)]
        [int]$TimeoutMs = 200,
        [scriptblock]$ProgressCallback = $null
    )

    $discoveredServers = [System.Collections.ArrayList]::new()

    # Validate subnet base format (must be three octets like "10.0.0")
    if ($SubnetBase -notmatch '^\d{1,3}\.\d{1,3}\.\d{1,3}$') {
        Write-AppLog -Message "Find-DisguiseServers: Invalid subnet base format '$SubnetBase'. Expected format: 'X.X.X' (e.g. '10.0.0')." -Level 'ERROR'
        return @()
    }
    # Validate each octet is 0-255
    $subnetOctets = $SubnetBase -split '\.'
    foreach ($octet in $subnetOctets) {
        $octetVal = [int]$octet
        if ($octetVal -lt 0 -or $octetVal -gt 255) {
            Write-AppLog -Message "Find-DisguiseServers: Subnet octet out of range (0-255) in '$SubnetBase'." -Level 'ERROR'
            return @()
        }
    }

    # Validate IP range
    if ($StartIP -lt 0 -or $StartIP -gt 255 -or $EndIP -lt 0 -or $EndIP -gt 255) {
        Write-AppLog -Message "Find-DisguiseServers: IP range values must be 0-255. Got StartIP=$StartIP, EndIP=$EndIP." -Level 'ERROR'
        return @()
    }
    if ($StartIP -gt $EndIP) {
        Write-AppLog -Message "Find-DisguiseServers: StartIP ($StartIP) must be less than or equal to EndIP ($EndIP)." -Level 'ERROR'
        return @()
    }

    $totalIPs = $EndIP - $StartIP + 1
    $processedCount = 0

    # Known disguise ports to probe
    $targetPorts = @(80, 873, 9864)

    # -----------------------------------------------------------------------
    # Strategy 1 & 2: Parallel TCP port scan + ping sweep using runspaces
    # -----------------------------------------------------------------------
    $runspacePool = $null
    try {
    # Size the runspace pool to match the workload: no more threads than targets, capped at 50
    $maxThreads = [Math]::Max(1, [Math]::Min(50, $totalIPs))
    $runspacePool = [System.Management.Automation.Runspaces.RunspacePool]::CreateRunspacePool(1, $maxThreads)
    $runspacePool.Open()

    $runspaceJobs = [System.Collections.ArrayList]::new()

    # Scriptblock executed inside each runspace: probes TCP ports and pings the host
    $scanScriptBlock = {
        param(
            [string]$IPAddress,
            [int[]]$Ports,
            [int]$Timeout
        )

        $result = [PSCustomObject]@{
            IPAddress      = $IPAddress
            Hostname       = ''
            IsDisguise     = $false
            ResponseTimeMs = -1
            Ports          = @()
            APIVersion     = $null
            PingSuccess    = $false
        }

        $openPorts = [System.Collections.ArrayList]::new()
        $stopwatch = [System.Diagnostics.Stopwatch]::StartNew()

        # --- TCP Port Scan (async connections) ---
        foreach ($port in $Ports) {
            $tcpClient = $null
            try {
                $tcpClient = New-Object System.Net.Sockets.TcpClient
                # Set send/receive timeouts to prevent lingering connections
                $tcpClient.SendTimeout = $Timeout
                $tcpClient.ReceiveTimeout = $Timeout
                $connectTask = $tcpClient.ConnectAsync($IPAddress, $port)
                $completed = $connectTask.Wait($Timeout)
                if ($completed -and $tcpClient.Connected) {
                    [void]$openPorts.Add($port)
                }
            } catch {
                # Connection failed or timed out - port is closed/filtered
            } finally {
                if ($tcpClient) {
                    $tcpClient.Close()
                    $tcpClient.Dispose()
                }
            }
        }

        $stopwatch.Stop()
        $result.ResponseTimeMs = [int]$stopwatch.Elapsed.TotalMilliseconds

        # --- Ping Sweep ---
        $ping = $null
        try {
            $ping = New-Object System.Net.NetworkInformation.Ping
            $pingReply = $ping.Send($IPAddress, $Timeout)
            if ($pingReply.Status -eq [System.Net.NetworkInformation.IPStatus]::Success) {
                $result.PingSuccess = $true
                # Use ping round-trip time if it is better than TCP timing
                if ($pingReply.RoundtripTime -gt 0) {
                    $result.ResponseTimeMs = [Math]::Min($result.ResponseTimeMs, [int]$pingReply.RoundtripTime)
                }
            }
        } catch {
            # Ping failed - host may still be reachable via TCP
        } finally {
            if ($ping) { $ping.Dispose() }
        }

        # --- Hostname Resolution ---
        try {
            $dnsEntry = [System.Net.Dns]::GetHostEntry($IPAddress)
            $result.Hostname = $dnsEntry.HostName
        } catch {
            $result.Hostname = ''
        }

        $result.Ports = $openPorts.ToArray()

        # If port 80 is open, attempt a quick disguise API probe
        if ($openPorts -contains 80) {
            $httpClient = $null
            try {
                $httpClient = New-Object System.Net.Http.HttpClient
                $httpClient.Timeout = [TimeSpan]::FromMilliseconds($Timeout * 3)
                $apiResponse = $httpClient.GetStringAsync("http://$IPAddress/api/service/system").Result
                if ($apiResponse -match 'hostname|version|d3|disguise') {
                    $result.IsDisguise = $true
                    try {
                        $parsed = $apiResponse | ConvertFrom-Json
                        if ($parsed.version) {
                            $result.APIVersion = $parsed.version
                        } elseif ($parsed.d3VersionString) {
                            $result.APIVersion = $parsed.d3VersionString
                        }
                    } catch {
                        $result.APIVersion = 'Unknown'
                    }
                }
            } catch {
                # API not responding or not a disguise server - expected for non-disguise hosts
            } finally {
                if ($httpClient) { $httpClient.Dispose() }
            }
        }

        return $result
    }

    # Launch a runspace for each IP in the scan range
    for ($i = $StartIP; $i -le $EndIP; $i++) {
        $ip = "$SubnetBase.$i"

        $powershell = [System.Management.Automation.PowerShell]::Create()
        $powershell.RunspacePool = $runspacePool
        [void]$powershell.AddScript($scanScriptBlock)
        [void]$powershell.AddArgument($ip)
        [void]$powershell.AddArgument($targetPorts)
        [void]$powershell.AddArgument($TimeoutMs)

        $handle = $powershell.BeginInvoke()

        [void]$runspaceJobs.Add([PSCustomObject]@{
            PowerShell = $powershell
            Handle     = $handle
            IP         = $ip
        })
    }

    # Collect results from all runspaces
    foreach ($job in $runspaceJobs) {
        try {
            $scanResult = $job.PowerShell.EndInvoke($job.Handle)
            if ($scanResult -and $scanResult.Count -gt 0) {
                $serverInfo = $scanResult[0]
                # Include the server if it has open ports or responded to ping
                if ($serverInfo.Ports.Count -gt 0 -or $serverInfo.PingSuccess) {
                    [void]$discoveredServers.Add($serverInfo)
                }
            }
        } catch {
            Write-AppLog -Message "Error collecting scan result for $($job.IP): $_" -Level 'WARN'
        } finally {
            $job.PowerShell.Dispose()
        }

        $processedCount++
        if ($ProgressCallback) {
            $percentComplete = [int](($processedCount / $totalIPs) * 100)
            try {
                $ProgressCallback.Invoke($job.IP, $percentComplete, "Scanning $($job.IP)...")
            } catch {
                Write-AppLog -Message "Find-DisguiseServers: Progress callback failed for $($job.IP) - $_" -Level 'DEBUG'
            }
        }
    }

    } finally {
        # Clean up the runspace pool even if an exception occurred
        if ($runspacePool) {
            $runspacePool.Close()
            $runspacePool.Dispose()
        }
    }

    # -----------------------------------------------------------------------
    # Strategy 3: For hosts with port 80 open that were not yet identified
    # as disguise servers, do a deeper API check
    # -----------------------------------------------------------------------
    foreach ($server in $discoveredServers) {
        if (-not $server.IsDisguise -and $server.Ports -contains 80) {
            $apiInfo = Get-RemoteServerInfo -IPAddress $server.IPAddress
            if ($null -ne $apiInfo) {
                $server.IsDisguise = $true
                if ($apiInfo.version) {
                    $server.APIVersion = $apiInfo.version
                }
            }
        }
    }

    # Store results in shared app state for cross-view access
    $script:AppState.LastScanResults = $discoveredServers.ToArray()

    Write-AppLog -Message "Network scan complete. Found $($discoveredServers.Count) server(s) on $SubnetBase.x ($StartIP-$EndIP)." -Level 'INFO'

    return $discoveredServers.ToArray()
}

function Test-DisguiseServer {
    <#
    .SYNOPSIS
        Tests whether a specific IP address hosts a disguise (d3) media server.
    .DESCRIPTION
        Performs targeted connectivity checks against a single host:
          - TCP port probes on 80, 873, 9864
          - HTTP GET to the disguise REST API (/api/service/system)
          - Attempt to reach the SMC API
          - Hostname resolution via reverse DNS
    .PARAMETER IPAddress
        The IPv4 address to test.
    .PARAMETER TimeoutMs
        Timeout in milliseconds for each connection attempt. Default 2000.
    .OUTPUTS
        PSCustomObject with properties:
          IPAddress, Hostname, IsDisguise, APIAvailable, SMCAvailable, Ports, DesignerVersion
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$IPAddress,

        [int]$TimeoutMs = 2000
    )

    # Validate that IPAddress is a valid IPv4 address
    $parsedAddr = $null
    if (-not [System.Net.IPAddress]::TryParse($IPAddress, [ref]$parsedAddr) -or
        $parsedAddr.AddressFamily -ne [System.Net.Sockets.AddressFamily]::InterNetwork) {
        Write-AppLog -Message "Test-DisguiseServer: Invalid IPv4 address '$IPAddress'" -Level 'ERROR'
        return [PSCustomObject]@{
            IPAddress       = $IPAddress
            Hostname        = ''
            IsDisguise      = $false
            APIAvailable    = $false
            SMCAvailable    = $false
            Ports           = @()
            DesignerVersion = $null
        }
    }

    $result = [PSCustomObject]@{
        IPAddress       = $IPAddress
        Hostname        = ''
        IsDisguise      = $false
        APIAvailable    = $false
        SMCAvailable    = $false
        Ports           = @()
        DesignerVersion = $null
    }

    $openPorts = [System.Collections.ArrayList]::new()

    # --- TCP Port Probes ---
    $knownPorts = @(80, 873, 9864)
    foreach ($port in $knownPorts) {
        $tcpClient = $null
        try {
            $tcpClient = New-Object System.Net.Sockets.TcpClient
            # Set send/receive timeouts to prevent lingering connections
            $tcpClient.SendTimeout = $TimeoutMs
            $tcpClient.ReceiveTimeout = $TimeoutMs
            $connectTask = $tcpClient.ConnectAsync($IPAddress, $port)
            $completed = $connectTask.Wait($TimeoutMs)
            if ($completed -and $tcpClient.Connected) {
                [void]$openPorts.Add($port)
            }
        } catch {
            Write-AppLog -Message "Test-DisguiseServer: TCP probe to ${IPAddress}:${port} failed - $_" -Level 'DEBUG'
        } finally {
            if ($tcpClient) {
                $tcpClient.Close()
                $tcpClient.Dispose()
            }
        }
    }

    $result.Ports = $openPorts.ToArray()

    # --- Hostname Resolution ---
    try {
        $dnsEntry = [System.Net.Dns]::GetHostEntry($IPAddress)
        $result.Hostname = $dnsEntry.HostName
    } catch {
        $result.Hostname = ''
    }

    # --- Disguise REST API Check (port 80) ---
    if ($openPorts -contains 80) {
        $httpClient = $null
        try {
            $httpClient = New-Object System.Net.Http.HttpClient
            $httpClient.Timeout = [TimeSpan]::FromMilliseconds($TimeoutMs)
            $apiResponse = $httpClient.GetStringAsync("http://$IPAddress/api/service/system").Result

            if ($apiResponse) {
                $result.APIAvailable = $true
                try {
                    $parsed = $apiResponse | ConvertFrom-Json
                    if ($parsed.hostname -or $parsed.version -or $parsed.d3VersionString) {
                        $result.IsDisguise = $true
                        $result.DesignerVersion = if ($parsed.d3VersionString) {
                            $parsed.d3VersionString
                        } elseif ($parsed.version) {
                            $parsed.version
                        } else {
                            'Unknown'
                        }
                    }
                } catch {
                    if ($apiResponse -match 'disguise|d3') {
                        $result.IsDisguise = $true
                    }
                }
            }
        } catch {
            Write-AppLog -Message "Test-DisguiseServer: REST API probe to $IPAddress failed - $_" -Level 'DEBUG'
        } finally {
            if ($httpClient) { $httpClient.Dispose() }
        }
    }

    # --- SMC API Check ---
    # The SMC typically runs on a separate management interface; try the standard API endpoint
    $httpClient = $null
    try {
        $httpClient = New-Object System.Net.Http.HttpClient
        $httpClient.Timeout = [TimeSpan]::FromMilliseconds($TimeoutMs)
        $smcResponse = $httpClient.GetStringAsync("http://$IPAddress/api/networkadapters").Result
        if ($smcResponse) {
            $result.SMCAvailable = $true
            if (-not $result.IsDisguise -and ($smcResponse -match 'adapter|network|interface')) {
                $result.IsDisguise = $true
            }
        }
    } catch {
        Write-AppLog -Message "Test-DisguiseServer: SMC API probe to $IPAddress failed - $_" -Level 'DEBUG'
    } finally {
        if ($httpClient) { $httpClient.Dispose() }
    }

    Write-AppLog -Message "Test-DisguiseServer: $IPAddress - IsDisguise=$($result.IsDisguise), API=$($result.APIAvailable), Ports=$($result.Ports -join ',')" -Level 'INFO'

    return $result
}

function Get-RemoteServerInfo {
    <#
    .SYNOPSIS
        Retrieves detailed system information from a remote disguise server via REST API.
    .DESCRIPTION
        Sends an HTTP GET to http://<IPAddress>/api/service/system and parses the JSON response.
    .PARAMETER IPAddress
        The IPv4 address of the disguise server.
    .OUTPUTS
        Parsed PSCustomObject from the API response, or $null if the request fails.
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$IPAddress
    )

    # Validate IPv4 format before constructing HTTP URL
    $parsedIP = $null
    if (-not ([System.Net.IPAddress]::TryParse($IPAddress, [ref]$parsedIP)) -or
        $parsedIP.AddressFamily -ne [System.Net.Sockets.AddressFamily]::InterNetwork) {
        Write-AppLog -Message "Get-RemoteServerInfo: Rejected non-IPv4 input '$IPAddress'" -Level 'WARN'
        return $null
    }

    $httpClient = $null
    try {
        $httpClient = New-Object System.Net.Http.HttpClient
        $httpClient.Timeout = [TimeSpan]::FromSeconds(5)
        $response = $httpClient.GetStringAsync("http://$IPAddress/api/service/system").Result

        if ($response) {
            $parsed = $response | ConvertFrom-Json
            Write-AppLog -Message "Get-RemoteServerInfo: Successfully retrieved info from $IPAddress" -Level 'INFO'
            return $parsed
        }
    } catch {
        Write-AppLog -Message "Get-RemoteServerInfo: Failed to reach $IPAddress - $_" -Level 'WARN'
    } finally {
        if ($httpClient) { $httpClient.Dispose() }
    }

    return $null
}

function Push-ProfileToServer {
    <#
    .SYNOPSIS
        Pushes a configuration profile to a remote disguise server.
    .DESCRIPTION
        Uses PowerShell remoting (Invoke-Command) to apply the profile settings
        on the target machine. The operation consists of three phases:
          1. Set the server hostname
          2. Configure network adapters (IP, subnet, gateway, DNS)
          3. Configure SMB shares
        Each phase is wrapped in error handling and returns a detailed result.

        NOTE: The actual remote execution commands are structured and ready for
        deployment on a Windows environment. On non-Windows systems, the function
        returns a simulated/framework result.
    .PARAMETER ServerIP
        The IPv4 address of the target disguise server.
    .PARAMETER Profile
        The profile PSCustomObject containing configuration data.
    .PARAMETER Credential
        PSCredential for authenticating against the remote server.
    .OUTPUTS
        PSCustomObject with properties: ServerIP, Success, Steps (array of step results),
        ErrorMessage, Timestamp
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$ServerIP,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Profile,

        [Parameter(Mandatory = $false)]
        [PSCredential]$Credential
    )

    # Validate that ServerIP is a valid IPv4 address to prevent injection
    $ipValid = $false
    try {
        $parsedIP = [System.Net.IPAddress]::None
        $ipValid = [System.Net.IPAddress]::TryParse($ServerIP, [ref]$parsedIP) -and $parsedIP.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork
    } catch { }

    $result = [PSCustomObject]@{
        ServerIP     = $ServerIP
        Success      = $false
        Steps        = [System.Collections.ArrayList]::new()
        ErrorMessage = ''
        Timestamp    = (Get-Date).ToString('yyyy-MM-dd HH:mm:ss')
    }

    if (-not $ipValid) {
        $result.ErrorMessage = "Invalid IPv4 address: '$ServerIP'"
        Write-AppLog -Message "Push-ProfileToServer: Invalid IP address '$ServerIP'" -Level 'ERROR'
        return $result
    }

    Write-AppLog -Message "Push-ProfileToServer: Starting deployment of profile '$($Profile.Name)' to $ServerIP" -Level 'INFO'

    # -----------------------------------------------------------------------
    # Step 1: Set Hostname
    # -----------------------------------------------------------------------
    $hostnameStep = [PSCustomObject]@{
        StepName = 'Set Hostname'
        Success  = $false
        Message  = ''
    }

    try {
        $targetHostname = $Profile.ServerName
        if ([string]::IsNullOrWhiteSpace($targetHostname)) {
            $hostnameStep.Message = 'Skipped - no hostname specified in profile'
            $hostnameStep.Success = $true
        } else {
            # Build the remote command for setting the hostname
            $hostnameScriptBlock = {
                param($NewHostname)
                try {
                    Rename-Computer -NewName $NewHostname -Force -ErrorAction Stop
                    return @{ Success = $true; Message = "Hostname set to '$NewHostname'. Reboot required." }
                } catch {
                    return @{ Success = $false; Message = "Failed to set hostname: $_" }
                }
            }

            # Execute remotely via Invoke-Command
            $invokeParams = @{
                ComputerName = $ServerIP
                ScriptBlock  = $hostnameScriptBlock
                ArgumentList = @($targetHostname)
                ErrorAction  = 'Stop'
            }
            if ($Credential) {
                $invokeParams.Credential = $Credential
            }

            $remoteResult = Invoke-Command @invokeParams
            $hostnameStep.Success = $remoteResult.Success
            $hostnameStep.Message = $remoteResult.Message
        }
    } catch {
        $hostnameStep.Success = $false
        $hostnameStep.Message = "Remote execution failed: $_"
        Write-AppLog -Message "Push-ProfileToServer: Hostname step failed for $ServerIP - $_" -Level 'ERROR'
    }

    [void]$result.Steps.Add($hostnameStep)

    # -----------------------------------------------------------------------
    # Step 2: Configure Network Adapters
    # -----------------------------------------------------------------------
    # If Step 1 failed, log the partial failure but continue to attempt remaining steps
    if (-not $hostnameStep.Success -and $hostnameStep.Message -notmatch '^Skipped') {
        Write-AppLog -Message "Push-ProfileToServer: Step 1 (Hostname) failed for $ServerIP, continuing with remaining steps. Partial failure may require manual cleanup." -Level 'WARN'
    }

    $networkStep = [PSCustomObject]@{
        StepName = 'Configure Network Adapters'
        Success  = $false
        Message  = ''
    }

    try {
        $adapters = $Profile.NetworkAdapters
        if (-not $adapters -or $adapters.Count -eq 0) {
            $networkStep.Message = 'Skipped - no network adapter configuration in profile'
            $networkStep.Success = $true
        } else {
            # Build the remote command for configuring each adapter
            $networkScriptBlock = {
                param($AdapterConfigs)
                $results = @()
                foreach ($adapter in $AdapterConfigs) {
                    try {
                        # Skip disabled, unconfigured, or DHCP adapters
                        if ($adapter.PSObject.Properties['Enabled'] -and $adapter.Enabled -eq $false) {
                            $results += "INFO: $($adapter.AdapterName) - Disabled in profile, skipping"
                            continue
                        }
                        if ([string]::IsNullOrWhiteSpace($adapter.IPAddress)) { continue }
                        if ($adapter.DHCP -eq $true) {
                            $results += "INFO: $($adapter.Role) ($($adapter.AdapterName)) - DHCP enabled, skipping static config"
                            continue
                        }

                        # Find the adapter by AdapterName (matching profile schema)
                        $netAdapter = Get-NetAdapter | Where-Object {
                            $_.Name -eq $adapter.AdapterName
                        } | Select-Object -First 1

                        if (-not $netAdapter) {
                            $results += "WARN: Adapter '$($adapter.AdapterName)' for role '$($adapter.Role)' not found"
                            continue
                        }

                        # Remove existing IP configuration
                        $netAdapter | Remove-NetIPAddress -Confirm:$false -ErrorAction SilentlyContinue
                        $netAdapter | Remove-NetRoute -Confirm:$false -ErrorAction SilentlyContinue

                        # Convert SubnetMask (dotted decimal) to CIDR prefix length
                        $prefixLength = 24  # safe default
                        if ($adapter.SubnetMask) {
                            try {
                                $maskBytes = [System.Net.IPAddress]::Parse($adapter.SubnetMask).GetAddressBytes()
                                $prefixLength = 0
                                foreach ($byte in $maskBytes) {
                                    $bits = [Convert]::ToString($byte, 2).PadLeft(8, '0')
                                    $prefixLength += ($bits.ToCharArray() | Where-Object { $_ -eq '1' }).Count
                                }
                            } catch {
                                $results += "WARN: Invalid subnet mask '$($adapter.SubnetMask)' for $($adapter.AdapterName), using /24"
                            }
                        }

                        # Apply new IP configuration
                        $ipParams = @{
                            InterfaceIndex = $netAdapter.InterfaceIndex
                            IPAddress      = $adapter.IPAddress
                            PrefixLength   = $prefixLength
                            ErrorAction    = 'Stop'
                        }
                        if ($adapter.Gateway) {
                            $ipParams.DefaultGateway = $adapter.Gateway
                        }
                        New-NetIPAddress @ipParams

                        # Build DNS server list from DNS1/DNS2 fields
                        $dnsServers = @()
                        if ($adapter.DNS1) { $dnsServers += $adapter.DNS1 }
                        if ($adapter.DNS2) { $dnsServers += $adapter.DNS2 }
                        if ($dnsServers.Count -gt 0) {
                            Set-DnsClientServerAddress -InterfaceIndex $netAdapter.InterfaceIndex `
                                -ServerAddresses $dnsServers -ErrorAction Stop
                        }

                        $results += "OK: $($adapter.Role) ($($adapter.AdapterName)) -> $($adapter.IPAddress)/$prefixLength"
                    } catch {
                        $results += "ERROR: $($adapter.Role) ($($adapter.AdapterName)) - $($_.Exception.Message)"
                    }
                }
                return @{ Success = ($results | Where-Object { $_ -match '^ERROR:' }).Count -eq 0; Message = ($results -join '; ') }
            }

            $invokeParams = @{
                ComputerName = $ServerIP
                ScriptBlock  = $networkScriptBlock
                ArgumentList = @(, $adapters)
                ErrorAction  = 'Stop'
            }
            if ($Credential) {
                $invokeParams.Credential = $Credential
            }

            $remoteResult = Invoke-Command @invokeParams
            $networkStep.Success = $remoteResult.Success
            $networkStep.Message = $remoteResult.Message
        }
    } catch {
        $networkStep.Success = $false
        $networkStep.Message = "Remote execution failed: $_"
        Write-AppLog -Message "Push-ProfileToServer: Network config step failed for $ServerIP - $_" -Level 'ERROR'
    }

    [void]$result.Steps.Add($networkStep)

    # -----------------------------------------------------------------------
    # Step 3: Configure SMB Shares
    # -----------------------------------------------------------------------
    # If Step 2 failed, log the partial failure but continue to attempt remaining steps
    if (-not $networkStep.Success -and $networkStep.Message -notmatch '^Skipped') {
        Write-AppLog -Message "Push-ProfileToServer: Step 2 (Network) failed for $ServerIP, continuing with remaining steps. Previous network changes may have been partially applied." -Level 'WARN'
    }

    $smbStep = [PSCustomObject]@{
        StepName = 'Configure SMB Shares'
        Success  = $false
        Message  = ''
    }

    try {
        $smbSettings = $Profile.SMBSettings
        if (-not $smbSettings) {
            $smbStep.Message = 'Skipped - no SMB configuration in profile'
            $smbStep.Success = $true
        } else {
            $smbScriptBlock = {
                param($SMBConfig)
                $results = @()
                try {
                    # SMB1 enablement is blocked by security policy (EternalBlue/WannaCry risk)
                    $results += "INFO: SMB protocol version management is handled separately by security policy"

                    # Create or update the d3 Projects share using actual profile schema fields
                    if ($SMBConfig.ShareD3Projects -eq $true -and $SMBConfig.ShareName -and $SMBConfig.ProjectsPath) {
                        try {
                            # Validate ProjectsPath -- block UNC and system paths
                            if ($SMBConfig.ProjectsPath -match '^\\\\') {
                                $results += "ERROR: UNC paths not allowed for ProjectsPath: $($SMBConfig.ProjectsPath)"
                                return @{ Success = $false; Message = ($results -join '; ') }
                            }
                            if ($SMBConfig.ProjectsPath -match '(?i)(system32|\\windows\\|program files)') {
                                $results += "ERROR: System paths not allowed for ProjectsPath: $($SMBConfig.ProjectsPath)"
                                return @{ Success = $false; Message = ($results -join '; ') }
                            }

                            # Ensure the projects directory exists
                            if (-not (Test-Path $SMBConfig.ProjectsPath)) {
                                New-Item -Path $SMBConfig.ProjectsPath -ItemType Directory -Force | Out-Null
                            }

                            # Parse permissions string (format: "Account:Level")
                            # Parse permissions with null safety and case-insensitive comparison
                            $permParts = if ($SMBConfig.SharePermissions) { $SMBConfig.SharePermissions -split ':' } else { @() }
                            $permAccount = if ($permParts.Count -gt 0 -and $permParts[0]) { $permParts[0] } else { 'Administrators' }
                            $permLevel = if ($permParts.Count -gt 1 -and $permParts[1]) { $permParts[1] } else { 'Full' }

                            $existingShare = Get-SmbShare -Name $SMBConfig.ShareName -ErrorAction SilentlyContinue
                            if ($existingShare) {
                                # Path cannot be changed via Set-SmbShare -- remove and recreate if path differs
                                if ($existingShare.Path -ne $SMBConfig.ProjectsPath) {
                                    Remove-SmbShare -Name $SMBConfig.ShareName -Force -ErrorAction Stop
                                    $results += "INFO: Removed existing share (path mismatch: '$($existingShare.Path)' vs '$($SMBConfig.ProjectsPath)')"
                                    # Fall through to New-SmbShare below
                                    $existingShare = $null
                                } else {
                                    # Path matches -- update permissions
                                    if ($permLevel -ieq 'Full') {
                                        Grant-SmbShareAccess -Name $SMBConfig.ShareName -AccountName $permAccount -AccessRight Full -Force -ErrorAction Stop | Out-Null
                                    } elseif ($permLevel -ieq 'Change') {
                                        Grant-SmbShareAccess -Name $SMBConfig.ShareName -AccountName $permAccount -AccessRight Change -Force -ErrorAction Stop | Out-Null
                                    } else {
                                        Grant-SmbShareAccess -Name $SMBConfig.ShareName -AccountName $permAccount -AccessRight Read -Force -ErrorAction Stop | Out-Null
                                    }
                                    $results += "OK: Updated share '$($SMBConfig.ShareName)' permissions ($permAccount`:$permLevel)"
                                }
                            }
                            if (-not $existingShare) {
                                $shareParams = @{
                                    Name        = $SMBConfig.ShareName
                                    Path        = $SMBConfig.ProjectsPath
                                    ErrorAction = 'Stop'
                                }
                                if ($permLevel -ieq 'Full') {
                                    $shareParams.FullAccess = $permAccount
                                } elseif ($permLevel -ieq 'Change') {
                                    $shareParams.ChangeAccess = $permAccount
                                } else {
                                    $shareParams.ReadAccess = $permAccount
                                }
                                New-SmbShare @shareParams
                                $results += "OK: Created share '$($SMBConfig.ShareName)' at '$($SMBConfig.ProjectsPath)' with $permAccount`:$permLevel"
                            }
                        } catch {
                            $results += "ERROR: Share '$($SMBConfig.ShareName)' - $($_.Exception.Message)"
                        }
                    } else {
                        $results += "INFO: d3 Projects sharing not enabled in profile"
                    }
                } catch {
                    $results += "ERROR: SMB configuration - $($_.Exception.Message)"
                }
                return @{
                    Success = ($results | Where-Object { $_ -match '^ERROR:' }).Count -eq 0
                    Message = ($results -join '; ')
                }
            }

            $invokeParams = @{
                ComputerName = $ServerIP
                ScriptBlock  = $smbScriptBlock
                ArgumentList = @($smbSettings)
                ErrorAction  = 'Stop'
            }
            if ($Credential) {
                $invokeParams.Credential = $Credential
            }

            $remoteResult = Invoke-Command @invokeParams
            $smbStep.Success = $remoteResult.Success
            $smbStep.Message = $remoteResult.Message
        }
    } catch {
        $smbStep.Success = $false
        $smbStep.Message = "Remote execution failed: $_"
        Write-AppLog -Message "Push-ProfileToServer: SMB config step failed for $ServerIP - $_" -Level 'ERROR'
    }

    [void]$result.Steps.Add($smbStep)

    # -----------------------------------------------------------------------
    # Aggregate overall success
    # -----------------------------------------------------------------------
    $result.Success = ($result.Steps | Where-Object { -not $_.Success }).Count -eq 0
    if (-not $result.Success) {
        $failedSteps = ($result.Steps | Where-Object { -not $_.Success } | ForEach-Object { "$($_.StepName): $($_.Message)" }) -join '; '
        $succeededSteps = ($result.Steps | Where-Object { $_.Success } | ForEach-Object { $_.StepName }) -join ', '
        $result.ErrorMessage = "Partial deployment failure. Failed: [$failedSteps]"
        if ($succeededSteps) {
            $result.ErrorMessage += " | Succeeded: [$succeededSteps]"
        }
        Write-AppLog -Message "Push-ProfileToServer: Partial failure on $ServerIP - $($result.ErrorMessage)" -Level 'WARN'
    }

    Write-AppLog -Message "Push-ProfileToServer: Deployment to $ServerIP completed. Success=$($result.Success)" -Level 'INFO'

    return $result
}

function Push-ProfileToMultipleServers {
    <#
    .SYNOPSIS
        Pushes a configuration profile to multiple disguise servers in batch.
    .DESCRIPTION
        Iterates over the given list of server IPs, calling Push-ProfileToServer
        for each one. Supports a progress callback for UI updates.
    .PARAMETER ServerIPs
        Array of IPv4 addresses to deploy to.
    .PARAMETER Profile
        The configuration profile to push.
    .PARAMETER Credential
        PSCredential for remote authentication.
    .PARAMETER ProgressCallback
        Optional scriptblock invoked with (serverIP, index, total, result) after each server.
    .OUTPUTS
        Array of PSCustomObjects (one per server), each containing deployment results.
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string[]]$ServerIPs,

        [Parameter(Mandatory = $true)]
        [PSCustomObject]$Profile,

        [Parameter(Mandatory = $false)]
        [PSCredential]$Credential,

        [scriptblock]$ProgressCallback = $null
    )

    $allResults = [System.Collections.ArrayList]::new()
    $totalServers = $ServerIPs.Count
    $currentIndex = 0

    foreach ($ip in $ServerIPs) {
        $currentIndex++

        Write-AppLog -Message "Push-ProfileToMultipleServers: Deploying to $ip ($currentIndex of $totalServers)" -Level 'INFO'

        $pushResult = Push-ProfileToServer -ServerIP $ip -Profile $Profile -Credential $Credential
        [void]$allResults.Add($pushResult)

        if ($ProgressCallback) {
            try {
                $ProgressCallback.Invoke($ip, $currentIndex, $totalServers, $pushResult)
            } catch {
                Write-AppLog -Message "Push-ProfileToMultipleServers: Progress callback failed for $ip ($currentIndex/$totalServers) - $_" -Level 'DEBUG'
            }
        }
    }

    $successCount = ($allResults | Where-Object { $_.Success }).Count
    Write-AppLog -Message "Push-ProfileToMultipleServers: Batch complete. $successCount/$totalServers succeeded." -Level 'INFO'

    return $allResults.ToArray()
}

function Find-DisguiseServersDNSSD {
    <#
    .SYNOPSIS
        Discovers disguise servers on the local network using DNS-SD / mDNS.
    .DESCRIPTION
        disguise servers running r30.4 and later advertise themselves via the
        DNS-SD service type _d3api._tcp.local.  This function:

          1. Tries Resolve-DnsName (if available on the host) to query the PTR
             record for _d3api._tcp.local. on the local mDNS stack.

          2. Falls back to a raw mDNS multicast query -- sends a DNS PTR query
             UDP datagram to the mDNS all-hosts address (224.0.0.251) port 5353
             and collects responses for 3 seconds.

        For each discovered service the function attempts a reverse DNS lookup
        to obtain the server IP address, then returns a list of PSCustomObjects
        compatible with the scan result schema used by Find-DisguiseServers so
        that callers can merge the two result sets without special-casing.

    .OUTPUTS
        Array of PSCustomObjects with properties:
          IPAddress, Hostname, IsDisguise, ResponseTimeMs, Ports, APIVersion
        Returns an empty array if nothing is found or DNS-SD is not available.
    #>
    [CmdletBinding()]
    param()

    Write-AppLog -Message "Find-DisguiseServersDNSSD: Starting DNS-SD discovery for _d3api._tcp.local." -Level 'INFO'

    $discovered = [System.Collections.ArrayList]::new()
    $serviceType = '_d3api._tcp.local.'

    # Helper: convert a service instance hostname / SRV target to an IP address
    function Resolve-ServiceHostToIP {
        param([string]$Hostname)
        if ([string]::IsNullOrWhiteSpace($Hostname)) { return $null }
        try {
            $addresses = [System.Net.Dns]::GetHostAddresses($Hostname) |
                Where-Object { $_.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork }
            $first = $addresses | Select-Object -First 1
            if ($first) { return $first.IPAddressToString }
            return $null
        } catch {
            return $null
        }
    }

    # ----------------------------------------------------------------
    # Strategy 1: Resolve-DnsName (available on Windows 8+ / Server 2012+)
    # ----------------------------------------------------------------
    $usedResolveDnsName = $false
    try {
        # Resolve-DnsName ships with the DnsClient module on modern Windows.
        # -DnsOnly prevents falling back to LLMNR/NetBIOS so it stays pure DNS-SD.
        $ptrRecords = Resolve-DnsName -Name $serviceType -Type PTR -DnsOnly -ErrorAction Stop
        $usedResolveDnsName = $true

        foreach ($ptr in $ptrRecords) {
            # Each PTR answer points to a service instance name, e.g.:
            #   d3-server01._d3api._tcp.local.
            $instanceName = $ptr.NameHost
            if (-not $instanceName) { $instanceName = $ptr.Name }
            if (-not $instanceName) { continue }

            # Attempt to resolve SRV record for the instance to get port + target
            $srvHost  = $null
            $srvPort  = 80
            try {
                $srvRecords = Resolve-DnsName -Name $instanceName -Type SRV -DnsOnly -ErrorAction Stop
                foreach ($srv in $srvRecords) {
                    if ($srv.NameTarget) { $srvHost = $srv.NameTarget }
                    if ($srv.Port -gt 0) { $srvPort = $srv.Port }
                    break
                }
            } catch { }

            # Resolve to IP -- try SRV target first, then instance name directly
            $ipAddress = $null
            if ($srvHost) { $ipAddress = Resolve-ServiceHostToIP -Hostname $srvHost }
            if (-not $ipAddress) { $ipAddress = Resolve-ServiceHostToIP -Hostname $instanceName }

            if ($ipAddress) {
                [void]$discovered.Add([PSCustomObject]@{
                    IPAddress      = $ipAddress
                    Hostname       = if ($srvHost) { $srvHost } else { ($instanceName -replace '\._d3api\._tcp\.local\.$', '') }
                    IsDisguise     = $true
                    ResponseTimeMs = 0
                    Ports          = @($srvPort)
                    APIVersion     = $null
                })
                Write-AppLog -Message "Find-DisguiseServersDNSSD: Found $ipAddress via Resolve-DnsName (instance: $instanceName)" -Level 'INFO'
            }
        }
    } catch {
        Write-AppLog -Message "Find-DisguiseServersDNSSD: Resolve-DnsName not available or failed - $_. Trying raw mDNS fallback." -Level 'DEBUG'
    }

    # ----------------------------------------------------------------
    # Strategy 2: Raw mDNS UDP multicast query (fallback)
    # Sends a standard DNS PTR query to 224.0.0.251:5353 and collects
    # responses for 3 seconds.  Parses enough of the DNS wire format
    # to extract PTR + A record answers.
    # ----------------------------------------------------------------
    if (-not $usedResolveDnsName -or $discovered.Count -eq 0) {
        $udpClient = $null
        try {
            # Build a minimal DNS PTR query packet for _d3api._tcp.local.
            # DNS Message Header (12 bytes) + Question
            $queryBytes = [System.Collections.ArrayList]::new()

            # Transaction ID: 0x1234 (arbitrary, non-zero)
            [void]$queryBytes.Add([byte]0x12)
            [void]$queryBytes.Add([byte]0x34)
            # Flags: Standard Query (0x0000)
            [void]$queryBytes.Add([byte]0x00)
            [void]$queryBytes.Add([byte]0x00)
            # QDCOUNT: 1
            [void]$queryBytes.Add([byte]0x00)
            [void]$queryBytes.Add([byte]0x01)
            # ANCOUNT, NSCOUNT, ARCOUNT: 0
            [void]$queryBytes.Add([byte]0x00); [void]$queryBytes.Add([byte]0x00)
            [void]$queryBytes.Add([byte]0x00); [void]$queryBytes.Add([byte]0x00)
            [void]$queryBytes.Add([byte]0x00); [void]$queryBytes.Add([byte]0x00)

            # QNAME: encode each label of _d3api._tcp.local as length-prefixed string
            foreach ($label in @('_d3api', '_tcp', 'local')) {
                $labelBytes = [System.Text.Encoding]::ASCII.GetBytes($label)
                [void]$queryBytes.Add([byte]$labelBytes.Length)
                foreach ($b in $labelBytes) { [void]$queryBytes.Add($b) }
            }
            [void]$queryBytes.Add([byte]0x00)  # root label terminator

            # QTYPE: PTR (12)
            [void]$queryBytes.Add([byte]0x00); [void]$queryBytes.Add([byte]0x0C)
            # QCLASS: IN (1) with unicast-response bit cleared (mDNS uses QU/QM)
            [void]$queryBytes.Add([byte]0x00); [void]$queryBytes.Add([byte]0x01)

            $queryPacket = $queryBytes.ToArray()

            # Bind to an ephemeral local port, allow reuse (mDNS requirement)
            $udpClient = New-Object System.Net.Sockets.UdpClient
            $udpClient.Client.SetSocketOption(
                [System.Net.Sockets.SocketOptionLevel]::Socket,
                [System.Net.Sockets.SocketOptionName]::ReuseAddress, $true)
            $udpClient.Client.Bind([System.Net.IPEndPoint]::new([System.Net.IPAddress]::Any, 0))
            $udpClient.Client.ReceiveTimeout = 3000  # 3 second collection window

            # Send PTR query to the mDNS multicast group
            $mDNSGroup = [System.Net.IPEndPoint]::new(
                [System.Net.IPAddress]::Parse('224.0.0.251'), 5353)
            [void]$udpClient.Send($queryPacket, $queryPacket.Length, $mDNSGroup)

            Write-AppLog -Message "Find-DisguiseServersDNSSD: mDNS query sent, listening for 3 seconds..." -Level 'DEBUG'

            # Collect response packets for up to 3 seconds
            $responseEndpoint = [System.Net.IPEndPoint]::new([System.Net.IPAddress]::Any, 0)
            $deadline = [System.DateTime]::UtcNow.AddSeconds(3)

            while ([System.DateTime]::UtcNow -lt $deadline) {
                try {
                    $responseBytes = $udpClient.Receive([ref]$responseEndpoint)
                    $senderIP = $responseEndpoint.Address.IPAddressToString

                    # Minimum valid DNS response is 12 bytes (header only)
                    if ($responseBytes.Length -lt 12) { continue }

                    # Check: IS a response (QR bit set in flags byte index 2)
                    $flags = ($responseBytes[2] -shl 8) -bor $responseBytes[3]
                    if (-not ($flags -band 0x8000)) { continue }

                    # Parse answer count
                    $anCount = ($responseBytes[4] -shl 8) -bor $responseBytes[5]
                    if ($anCount -eq 0) { continue }

                    # We found a response -- the sender IS the mDNS responder and its IP
                    # is captured in $senderIP from the UDP endpoint.
                    # Do a basic hostname resolution from the sender IP.
                    $resolvedHostname = ''
                    try {
                        $dnsEntry = [System.Net.Dns]::GetHostEntry($senderIP)
                        $resolvedHostname = $dnsEntry.HostName
                    } catch { }

                    # Deduplicate by IP before adding
                    $alreadyFound = $discovered | Where-Object { $_.IPAddress -eq $senderIP }
                    if (-not $alreadyFound) {
                        [void]$discovered.Add([PSCustomObject]@{
                            IPAddress      = $senderIP
                            Hostname       = $resolvedHostname
                            IsDisguise     = $true
                            ResponseTimeMs = 0
                            Ports          = @(80)
                            APIVersion     = $null
                        })
                        Write-AppLog -Message "Find-DisguiseServersDNSSD: Found $senderIP via raw mDNS multicast" -Level 'INFO'
                    }
                } catch [System.Net.Sockets.SocketException] {
                    # ReceiveTimeout expired -- collection window is done
                    break
                } catch {
                    # Non-fatal parse error on a response packet
                    Write-AppLog -Message "Find-DisguiseServersDNSSD: Packet parse error - $_" -Level 'DEBUG'
                }
            }

        } catch {
            Write-AppLog -Message "Find-DisguiseServersDNSSD: Raw mDNS query failed - $_" -Level 'WARN'
        } finally {
            if ($udpClient) {
                try { $udpClient.Close() } catch { }
                try { $udpClient.Dispose() } catch { }
            }
        }
    }

    $results = $discovered.ToArray()
    Write-AppLog -Message "Find-DisguiseServersDNSSD: Discovery complete. Found $($results.Count) server(s)." -Level 'INFO'
    return $results
}

function Test-NICConsistency {
    <#
    .SYNOPSIS
        Validates that network adapter names are identical across all profiles for each role.
    .DESCRIPTION
        disguise requires adapter names to be IDENTICAL across all servers for sACN/Art-Net
        multicast to work correctly. A mismatch silently breaks DMX output.

        This function groups adapters by Role across all provided profiles, then compares
        the AdapterName values within each role group. Any role where adapter names differ
        between profiles is flagged as a warning.

        If RemoteAdapters is provided (from /api/service/system/networkadapters), the function
        also compares profile expectations against actual remote adapter names.
    .PARAMETER Profiles
        Array of profile objects to compare (each containing a NetworkAdapters array).
    .PARAMETER RemoteAdapters
        Optional array of hashtables with keys: IP (server IP), Adapters (array of adapter
        objects with Name property). Typically sourced from the d3 REST API.
    .OUTPUTS
        Hashtable with keys:
          IsConsistent - [bool] True if all roles have matching adapter names across profiles
          Warnings     - Array of warning hashtables, each with Role, Servers, Names, Message
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [array]$Profiles,

        [Parameter(Mandatory = $false)]
        [array]$RemoteAdapters = @()
    )

    $result = @{
        IsConsistent = $true
        Warnings     = @()
    }

    if ($Profiles.Count -lt 2) {
        Write-AppLog -Message "Test-NICConsistency: Need at least 2 profiles to compare. Got $($Profiles.Count)." -Level 'INFO'
        return $result
    }

    # -----------------------------------------------------------------------
    # Step 1: Group adapters by Role across all profiles
    # -----------------------------------------------------------------------
    # Build a hashtable: Role -> array of @{ ServerName; AdapterName }
    $roleMap = @{}

    foreach ($profile in $Profiles) {
        $serverName = if ($profile.ServerName) { $profile.ServerName } else { $profile.Name }
        $adapters = $profile.NetworkAdapters

        if (-not $adapters) { continue }

        foreach ($adapter in $adapters) {
            $role = $adapter.Role
            if ([string]::IsNullOrWhiteSpace($role)) { continue }
            # Skip adapters that are disabled or have no name configured
            if ($adapter.PSObject.Properties['Enabled'] -and $adapter.Enabled -eq $false) { continue }
            if ([string]::IsNullOrWhiteSpace($adapter.AdapterName)) { continue }

            if (-not $roleMap.ContainsKey($role)) {
                $roleMap[$role] = [System.Collections.ArrayList]::new()
            }

            [void]$roleMap[$role].Add(@{
                ServerName  = $serverName
                AdapterName = $adapter.AdapterName
            })
        }
    }

    # -----------------------------------------------------------------------
    # Step 2: Compare AdapterName values within each role group
    # -----------------------------------------------------------------------
    foreach ($role in $roleMap.Keys) {
        $entries = $roleMap[$role]
        if ($entries.Count -lt 2) { continue }

        $uniqueNames = $entries | ForEach-Object { $_.AdapterName } | Sort-Object -Unique
        if ($uniqueNames.Count -gt 1) {
            $result.IsConsistent = $false

            $serverNames = ($entries | ForEach-Object { $_.ServerName }) -join ', '
            $nameList = ($uniqueNames) -join "', '"

            $warning = @{
                Role    = $role
                Servers = @($entries | ForEach-Object { $_.ServerName })
                Names   = @($uniqueNames)
                Message = "Role '$role' has inconsistent adapter names across servers ($serverNames): '$nameList'"
            }
            $result.Warnings += $warning

            Write-AppLog -Message "Test-NICConsistency: $($warning.Message)" -Level 'WARN'
        }
    }

    # -----------------------------------------------------------------------
    # Step 3: Compare profile expectations against remote adapter names
    # -----------------------------------------------------------------------
    if ($RemoteAdapters -and $RemoteAdapters.Count -gt 0) {
        foreach ($remote in $RemoteAdapters) {
            $remoteIP = $remote.IP
            $remoteAdapterNames = @()
            if ($remote.Adapters) {
                $remoteAdapterNames = $remote.Adapters | ForEach-Object {
                    if ($_.Name) { $_.Name } elseif ($_.name) { $_.name }
                } | Where-Object { $_ }
            }

            if ($remoteAdapterNames.Count -eq 0) { continue }

            # Find profiles that might correspond to this server (match by IP in adapter configs)
            foreach ($profile in $Profiles) {
                $serverName = if ($profile.ServerName) { $profile.ServerName } else { $profile.Name }
                $profileAdapterNames = @()

                if ($profile.NetworkAdapters) {
                    $profileAdapterNames = $profile.NetworkAdapters |
                        Where-Object { -not [string]::IsNullOrWhiteSpace($_.AdapterName) } |
                        ForEach-Object { $_.AdapterName } |
                        Sort-Object -Unique
                }

                foreach ($expectedName in $profileAdapterNames) {
                    if ($remoteAdapterNames -notcontains $expectedName) {
                        $result.IsConsistent = $false
                        $warning = @{
                            Role    = 'RemoteMismatch'
                            Servers = @($serverName, $remoteIP)
                            Names   = @($expectedName)
                            Message = "Profile '$serverName' expects adapter '$expectedName' but it was not found on remote server $remoteIP. Available: $($remoteAdapterNames -join ', ')"
                        }
                        $result.Warnings += $warning
                        Write-AppLog -Message "Test-NICConsistency: $($warning.Message)" -Level 'WARN'
                    }
                }
            }
        }
    }

    if ($result.IsConsistent) {
        Write-AppLog -Message "Test-NICConsistency: All adapter names are consistent across $($Profiles.Count) profile(s)." -Level 'INFO'
    } else {
        Write-AppLog -Message "Test-NICConsistency: Found $($result.Warnings.Count) inconsistency warning(s) across $($Profiles.Count) profile(s)." -Level 'WARN'
    }

    return $result
}

function Invoke-PreFlightCheck {
    <#
    .SYNOPSIS
        Runs a comprehensive pre-show network health check against one or more disguise servers.
    .DESCRIPTION
        For each server IP, performs the following checks:
          1. Ping test (ICMP reachability)
          2. d3 REST API reachable (HTTP GET /api/service/system with 3s timeout)
          3. d3Service running (inferred from API response)
          4. WinRM reachable (Test-WSMan)
          5. SMB share accessible (Test-Path \\server\d3 Projects)
          6. d3Net ports open (TCP 7542, 7543 session sync; 80 API)
          7. Designer version match (compare version strings across all servers)

        Returns structured results with per-server, per-check details. Supports a progress
        callback for UI updates during long-running checks.
    .PARAMETER Servers
        Array of server IP addresses to check.
    .PARAMETER Credential
        Optional PSCredential for WinRM/SMB authentication.
    .PARAMETER ProgressCallback
        Optional scriptblock invoked with (serverIP, checkIndex, totalChecks, checkName) for
        progress reporting. Allows the UI to show per-check progress.
    .OUTPUTS
        Hashtable with keys:
          AllPassed - [bool] True if every check on every server passed
          Results   - Array of per-server result hashtables, each containing Server and Checks
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [array]$Servers,

        [Parameter(Mandatory = $false)]
        [PSCredential]$Credential = $null,

        [Parameter(Mandatory = $false)]
        [scriptblock]$ProgressCallback = $null
    )

    $allResults = @{
        AllPassed = $true
        Results   = @()
    }

    # Collect version strings to compare at the end
    $versionMap = @{}

    $totalServers = $Servers.Count
    $serverIdx = 0

    foreach ($ip in $Servers) {
        $serverIdx++

        # Validate IPv4 format before any network operations
        $parsedPF = $null
        if (-not ([System.Net.IPAddress]::TryParse($ip, [ref]$parsedPF)) -or
            $parsedPF.AddressFamily -ne [System.Net.Sockets.AddressFamily]::InterNetwork) {
            Write-AppLog -Message "Invoke-PreFlightCheck: Skipping non-IPv4 input '$ip'" -Level 'WARN'
            $allResults.Results += @{
                Server = $ip
                Checks = @(@{ Name = 'Validation'; Passed = $false; Message = "Invalid IPv4 format: $ip" })
            }
            $allResults.AllPassed = $false
            continue
        }

        $serverResult = @{
            Server = $ip
            Checks = @()
        }

        $checkNames = @('Ping', 'API', 'd3Service', 'WinRM', 'SMB Share', 'd3Net Ports', 'Designer Version')
        $totalChecks = $checkNames.Count
        $checkIdx = 0

        # -------------------------------------------------------------------
        # Check 1: Ping
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'Ping') } catch {}
        }

        $pingCheck = @{ Name = 'Ping'; Passed = $false; Message = '' }
        try {
            $pingResult = New-Object System.Net.NetworkInformation.Ping
            $reply = $pingResult.Send($ip, 2000)
            if ($reply.Status -eq [System.Net.NetworkInformation.IPStatus]::Success) {
                $pingCheck.Passed = $true
                $pingCheck.Message = "OK ($($reply.RoundtripTime)ms)"
            } else {
                $pingCheck.Message = "Failed: $($reply.Status)"
            }
            $pingResult.Dispose()
        } catch {
            $pingCheck.Message = "Error: $($_.Exception.Message)"
        }
        $serverResult.Checks += $pingCheck

        # -------------------------------------------------------------------
        # Check 2: d3 REST API reachable
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'API') } catch {}
        }

        $apiCheck = @{ Name = 'API'; Passed = $false; Message = '' }
        $apiResponseObj = $null
        $httpClient = $null
        try {
            $httpClient = New-Object System.Net.Http.HttpClient
            $httpClient.Timeout = [TimeSpan]::FromSeconds(3)
            $apiResponseStr = $httpClient.GetStringAsync("http://$ip/api/service/system").Result

            if ($apiResponseStr) {
                $apiResponseObj = $apiResponseStr | ConvertFrom-Json
                $version = $null
                if ($apiResponseObj.d3VersionString) {
                    $version = $apiResponseObj.d3VersionString
                } elseif ($apiResponseObj.version) {
                    $version = $apiResponseObj.version
                }

                if ($version) {
                    $apiCheck.Passed = $true
                    $apiCheck.Message = "v$version"
                    $versionMap[$ip] = $version
                } else {
                    $apiCheck.Passed = $true
                    $apiCheck.Message = "Responded (version unknown)"
                }
            } else {
                $apiCheck.Message = "Empty response"
            }
        } catch {
            $errMsg = $_.Exception.Message
            # Unwrap AggregateException for cleaner messages
            if ($_.Exception.InnerException) {
                $errMsg = $_.Exception.InnerException.Message
            }
            $apiCheck.Message = "Unreachable: $errMsg"
        } finally {
            if ($httpClient) { $httpClient.Dispose() }
        }
        $serverResult.Checks += $apiCheck

        # -------------------------------------------------------------------
        # Check 3: d3Service running (inferred from API response)
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'd3Service') } catch {}
        }

        $serviceCheck = @{ Name = 'd3Service'; Passed = $false; Message = '' }
        if ($apiCheck.Passed) {
            # If the API responded, the d3 service is running
            $serviceCheck.Passed = $true
            $serviceCheck.Message = "Running (API responsive)"
        } else {
            $serviceCheck.Message = "Unknown (API not reachable)"
        }
        $serverResult.Checks += $serviceCheck

        # -------------------------------------------------------------------
        # Check 4: WinRM reachable
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'WinRM') } catch {}
        }

        $winrmCheck = @{ Name = 'WinRM'; Passed = $false; Message = '' }
        try {
            $wsmanParams = @{
                ComputerName = $ip
                ErrorAction  = 'Stop'
            }
            if ($Credential) {
                $wsmanParams.Credential = $Credential
            }
            $wsmanResult = Test-WSMan @wsmanParams
            if ($wsmanResult) {
                $winrmCheck.Passed = $true
                $winrmCheck.Message = "OK"
            } else {
                $winrmCheck.Message = "No response"
            }
        } catch {
            $winrmCheck.Message = "Failed: $($_.Exception.Message)"
        }
        $serverResult.Checks += $winrmCheck

        # -------------------------------------------------------------------
        # Check 5: SMB share accessible
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'SMB Share') } catch {}
        }

        $smbCheck = @{ Name = 'SMB Share'; Passed = $false; Message = '' }
        try {
            $sharePath = "\\$ip\d3 Projects"
            if (Test-Path -Path $sharePath -ErrorAction Stop) {
                $smbCheck.Passed = $true
                $smbCheck.Message = "OK ($sharePath accessible)"
            } else {
                $smbCheck.Message = "Share not found: $sharePath"
            }
        } catch {
            $smbCheck.Message = "Failed: $($_.Exception.Message)"
        }
        $serverResult.Checks += $smbCheck

        # -------------------------------------------------------------------
        # Check 6: d3Net ports open (7542, 7543 session sync; 80 API)
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'd3Net Ports') } catch {}
        }

        $portsCheck = @{ Name = 'd3Net Ports'; Passed = $false; Message = '' }
        $portsToTest = @(80, 7542, 7543)
        $openPorts = [System.Collections.ArrayList]::new()
        $closedPorts = [System.Collections.ArrayList]::new()

        foreach ($port in $portsToTest) {
            $tcpClient = $null
            try {
                $tcpClient = New-Object System.Net.Sockets.TcpClient
                $tcpClient.SendTimeout = 2000
                $tcpClient.ReceiveTimeout = 2000
                $connectTask = $tcpClient.ConnectAsync($ip, $port)
                $completed = $connectTask.Wait(2000)
                if ($completed -and $tcpClient.Connected) {
                    [void]$openPorts.Add($port)
                } else {
                    [void]$closedPorts.Add($port)
                }
            } catch {
                [void]$closedPorts.Add($port)
            } finally {
                if ($tcpClient) {
                    $tcpClient.Close()
                    $tcpClient.Dispose()
                }
            }
        }

        if ($closedPorts.Count -eq 0) {
            $portsCheck.Passed = $true
            $portsCheck.Message = "All ports open ($($openPorts -join ', '))"
        } elseif ($openPorts.Count -gt 0) {
            # Partial pass: some ports open, some closed
            $portsCheck.Passed = $false
            $portsCheck.Message = "Open: $($openPorts -join ', '); Closed: $($closedPorts -join ', ')"
        } else {
            $portsCheck.Message = "All ports closed ($($portsToTest -join ', '))"
        }
        $serverResult.Checks += $portsCheck

        # -------------------------------------------------------------------
        # Check 7: Designer version (placeholder - compared after all servers)
        # -------------------------------------------------------------------
        $checkIdx++
        if ($ProgressCallback) {
            try { $ProgressCallback.Invoke($ip, $checkIdx, $totalChecks, 'Designer Version') } catch {}
        }

        $versionCheck = @{ Name = 'Designer Version'; Passed = $false; Message = '' }
        if ($versionMap.ContainsKey($ip)) {
            $versionCheck.Passed = $true
            $versionCheck.Message = "v$($versionMap[$ip])"
        } else {
            $versionCheck.Message = "Could not determine version (API unavailable)"
        }
        $serverResult.Checks += $versionCheck

        $allResults.Results += $serverResult
    }

    # -----------------------------------------------------------------------
    # Post-processing: Compare designer versions across all servers
    # -----------------------------------------------------------------------
    if ($versionMap.Count -ge 2) {
        $uniqueVersions = $versionMap.Values | Sort-Object -Unique
        if ($uniqueVersions.Count -gt 1) {
            # Version mismatch detected - update the version check for each server
            $versionWarning = "VERSION MISMATCH across servers: $($uniqueVersions -join ' vs ')"
            Write-AppLog -Message "Invoke-PreFlightCheck: $versionWarning" -Level 'WARN'

            foreach ($serverResult in $allResults.Results) {
                $vCheck = $serverResult.Checks | Where-Object { $_.Name -eq 'Designer Version' }
                if ($vCheck -and $versionMap.ContainsKey($serverResult.Server)) {
                    $vCheck.Passed = $false
                    $vCheck.Message = "v$($versionMap[$serverResult.Server]) - MISMATCH ($versionWarning)"
                }
            }
        }
    }

    # -----------------------------------------------------------------------
    # Compute overall pass/fail
    # -----------------------------------------------------------------------
    $allResults.AllPassed = $true
    foreach ($serverResult in $allResults.Results) {
        $failedChecks = $serverResult.Checks | Where-Object { -not $_.Passed }
        if ($failedChecks) {
            $allResults.AllPassed = $false
        }
    }

    $passedCount = ($allResults.Results | Where-Object {
        ($_.Checks | Where-Object { -not $_.Passed }).Count -eq 0
    }).Count
    Write-AppLog -Message "Invoke-PreFlightCheck: Complete. $passedCount/$totalServers server(s) passed all checks." -Level 'INFO'

    return $allResults
}

# ============================================================================
# UI View Function - Network Deploy
# ============================================================================

function New-DeployView {
    <#
    .SYNOPSIS
        Creates the Network Discovery and Deployment view for the DISGUISE BUDDY UI.
    .DESCRIPTION
        Builds a full panel with three cards:
          1. Network Scan - subnet/range inputs, scan and quick-scan buttons, progress
          2. Discovered Servers - DataGridView with server list and actions
          3. Deploy Configuration - profile selection, credentials, deployment controls
    .PARAMETER ContentPanel
        The parent panel to which all controls will be added.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Panel]$ContentPanel
    )

    # Clear any existing controls from the content panel
    $ContentPanel.Controls.Clear()

    # Suspend layout to prevent flicker during UI construction
    $ContentPanel.SuspendLayout()

    # ===================================================================
    # BackgroundWorker for non-blocking network scan (Task 2)
    # ===================================================================
    $scanWorker = New-Object System.ComponentModel.BackgroundWorker
    $scanWorker.WorkerReportsProgress      = $true
    $scanWorker.WorkerSupportsCancellation = $true

    # Create a scrollable container for the entire view
    $scrollContainer = New-ScrollPanel -X 0 -Y 0 -Width $ContentPanel.ClientSize.Width -Height $ContentPanel.ClientSize.Height
    $scrollContainer.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor
                              [System.Windows.Forms.AnchorStyles]::Left -bor
                              [System.Windows.Forms.AnchorStyles]::Right -bor
                              [System.Windows.Forms.AnchorStyles]::Bottom
    $scrollContainer.SuspendLayout()

    # ===================================================================
    # Section Header
    # ===================================================================
    $sectionHeader = New-SectionHeader -Text "Network Deploy" -X 20 -Y 10 -Width 900

    $subtitleLabel = New-StyledLabel -Text "Discover disguise servers and push configurations" `
        -X 20 -Y 48 -FontSize 9 -IsSecondary

    $scrollContainer.Controls.Add($sectionHeader)
    $scrollContainer.Controls.Add($subtitleLabel)

    # ===================================================================
    # Card 1: Network Scan
    # ===================================================================
    $scanCard = New-StyledCard -Title "Network Scan" -X 20 -Y 80 -Width 900 -Height 180

    # --- Row 1: Subnet, IP range, and timeout inputs ---
    $lblSubnet = New-StyledLabel -Text "Subnet:" -X 15 -Y 48 -FontSize 9
    $txtSubnet = New-StyledTextBox -X 75 -Y 45 -Width 120 -PlaceholderText "10.0.0"
    $txtSubnet.Text = "10.0.0"
    $txtSubnet.ForeColor = $script:Theme.Text

    $lblStartIP = New-StyledLabel -Text "Start:" -X 210 -Y 48 -FontSize 9
    $txtStartIP = New-StyledTextBox -X 255 -Y 45 -Width 60
    $txtStartIP.Text = "1"

    $lblEndIP = New-StyledLabel -Text "End:" -X 330 -Y 48 -FontSize 9
    $txtEndIP = New-StyledTextBox -X 370 -Y 45 -Width 60
    $txtEndIP.Text = "254"

    $lblTimeout = New-StyledLabel -Text "Timeout (ms):" -X 450 -Y 48 -FontSize 9
    $txtTimeout = New-StyledTextBox -X 555 -Y 45 -Width 70
    $txtTimeout.Text = "200"

    $scanCard.Controls.AddRange(@($lblSubnet, $txtSubnet, $lblStartIP, $txtStartIP,
                                   $lblEndIP, $txtEndIP, $lblTimeout, $txtTimeout))

    # --- Row 2: Scan buttons, progress bar, status label, and cancel button ---
    $btnScanNetwork = New-StyledButton -Text "Scan Network" -X 15 -Y 90 `
        -Width 140 -Height 35 -IsPrimary

    $btnQuickScan = New-StyledButton -Text "Quick Scan" -X 170 -Y 90 `
        -Width 120 -Height 35

    # Cancel button -- only enabled while a background scan is running
    $btnCancelScan = New-StyledButton -Text "Cancel" -X 305 -Y 90 -Width 80 -Height 35
    $btnCancelScan.Enabled = $false

    # Auto-Discover button -- uses DNS-SD / mDNS to find servers advertising _d3api._tcp.local.
    $btnDNSSD = New-StyledButton -Text "Auto-Discover (DNS-SD)" -X 400 -Y 90 `
        -Width 185 -Height 35

    # Progress bar for scan progress (shifted right to accommodate all buttons)
    $scanProgressBar = New-StyledProgressBar -X 600 -Y 95 -Width 270 -Height 22

    $lblScanStatus = New-StyledLabel -Text "Ready to scan" -X 15 -Y 140 -FontSize 9 -IsMuted
    $lblScanStatus.AutoSize = $false
    $lblScanStatus.Width = 870

    $scanCard.Controls.AddRange(@($btnScanNetwork, $btnQuickScan, $btnCancelScan, $btnDNSSD,
                                   $scanProgressBar, $lblScanStatus))

    $scrollContainer.Controls.Add($scanCard)

    # ===================================================================
    # Card 2: Discovered Servers
    # ===================================================================
    $serversCard = New-StyledCard -Title "Discovered Servers" -X 20 -Y 270 -Width 900 -Height 280

    # DataGridView for the server list
    $dgvServers = New-StyledDataGridView -X 15 -Y 45 -Width 870 -Height 180

    # Collect profile names once for use in the per-row Profile column
    $allProfileNames = @()
    try {
        $allProfileNames = Get-AllProfiles | ForEach-Object { $_.Name }
    } catch {
        Write-AppLog -Message "New-DeployView: Could not pre-load profile names for grid column - $_" -Level 'WARN'
    }

    # Configure columns: Checkbox, IP Address, Hostname, Status, d3 API, Ports, Response Time, Profile
    $colSelect = New-Object System.Windows.Forms.DataGridViewCheckBoxColumn
    $colSelect.HeaderText = ""
    $colSelect.Name = "Select"
    $colSelect.Width = 40
    $colSelect.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colIP = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colIP.HeaderText = "IP Address"
    $colIP.Name = "IPAddress"
    $colIP.Width = 110
    $colIP.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colHostname = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colHostname.HeaderText = "Hostname"
    $colHostname.Name = "Hostname"
    $colHostname.Width = 130
    $colHostname.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colStatus = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colStatus.HeaderText = "Status"
    $colStatus.Name = "Status"
    $colStatus.Width = 80
    $colStatus.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colAPI = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colAPI.HeaderText = "d3 API"
    $colAPI.Name = "D3API"
    $colAPI.Width = 85
    $colAPI.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colPorts = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colPorts.HeaderText = "Ports"
    $colPorts.Name = "Ports"
    $colPorts.Width = 100
    $colPorts.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colResponseTime = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colResponseTime.HeaderText = "ms"
    $colResponseTime.Name = "ResponseTime"
    $colResponseTime.Width = 55
    $colResponseTime.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    # Per-row Profile assignment column (Task 1)
    # DataGridViewComboBoxColumn lets each row pick its own profile.
    $colProfile = New-Object System.Windows.Forms.DataGridViewComboBoxColumn
    $colProfile.HeaderText = "Profile"
    $colProfile.Name = "Profile"
    $colProfile.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::Fill
    $colProfile.DisplayStyleForCurrentCellOnly = $true   # show as text in non-focused cells
    $colProfile.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
    # Add a blank sentinel so rows can have no profile selected
    [void]$colProfile.Items.Add("")
    foreach ($pName in $allProfileNames) {
        [void]$colProfile.Items.Add($pName)
    }

    $dgvServers.Columns.Add($colSelect) | Out-Null
    $dgvServers.Columns.Add($colIP) | Out-Null
    $dgvServers.Columns.Add($colHostname) | Out-Null
    $dgvServers.Columns.Add($colStatus) | Out-Null
    $dgvServers.Columns.Add($colAPI) | Out-Null
    $dgvServers.Columns.Add($colPorts) | Out-Null
    $dgvServers.Columns.Add($colResponseTime) | Out-Null
    $dgvServers.Columns.Add($colProfile) | Out-Null
    $dgvServers.ReadOnly = $false

    # Only the Select (checkbox) and Profile (combobox) columns are user-editable
    foreach ($col in $dgvServers.Columns) {
        if ($col.Name -ne "Select" -and $col.Name -ne "Profile") {
            $col.ReadOnly = $true
        }
    }

    # --- Right-click context menu for the grid ---
    $contextMenu = New-Object System.Windows.Forms.ContextMenuStrip

    $menuViewDetails = New-Object System.Windows.Forms.ToolStripMenuItem
    $menuViewDetails.Text = "View Details"
    $menuViewDetails.Add_Click({
        $selectedRow = $dgvServers.CurrentRow
        if ($selectedRow) {
            $ip = $selectedRow.Cells["IPAddress"].Value
            if ($ip) {
                $lblScanStatus.Text = "Testing $ip..."
                $lblScanStatus.ForeColor = $script:Theme.TextSecondary
                $lblScanStatus.Refresh()

                try {
                    $details = Test-DisguiseServer -IPAddress $ip -TimeoutMs 3000
                    $detailMsg = "Server: $ip`n" +
                                 "Hostname: $($details.Hostname)`n" +
                                 "Is Disguise: $($details.IsDisguise)`n" +
                                 "API Available: $($details.APIAvailable)`n" +
                                 "SMC Available: $($details.SMCAvailable)`n" +
                                 "Open Ports: $($details.Ports -join ', ')`n" +
                                 "Designer Version: $($details.DesignerVersion)"
                    [System.Windows.Forms.MessageBox]::Show($detailMsg, "Server Details - $ip",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                } catch {
                    [System.Windows.Forms.MessageBox]::Show("Failed to get details: $_",
                        "Error", [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
                }

                $lblScanStatus.Text = "Ready"
                $lblScanStatus.ForeColor = $script:Theme.TextMuted
            }
        }
    })

    $menuTestConnection = New-Object System.Windows.Forms.ToolStripMenuItem
    $menuTestConnection.Text = "Test Connection"
    $menuTestConnection.Add_Click({
        $selectedRow = $dgvServers.CurrentRow
        if ($selectedRow) {
            $ip = $selectedRow.Cells["IPAddress"].Value
            if ($ip) {
                $lblScanStatus.Text = "Testing connection to $ip..."
                $lblScanStatus.Refresh()

                try {
                    $testResult = Test-DisguiseServer -IPAddress $ip -TimeoutMs 3000
                    $statusText = if ($testResult.IsDisguise) { "Disguise" } elseif ($testResult.Ports.Count -gt 0) { "Online" } else { "Offline" }
                    $selectedRow.Cells["Status"].Value = $statusText
                    $lblScanStatus.Text = "Connection test to $ip complete: $statusText"
                    $lblScanStatus.ForeColor = $script:Theme.Success
                } catch {
                    $lblScanStatus.Text = "Connection test to $ip failed: $_"
                    $lblScanStatus.ForeColor = $script:Theme.Error
                }
            }
        }
    })

    $menuPushProfile = New-Object System.Windows.Forms.ToolStripMenuItem
    $menuPushProfile.Text = "Push Profile"
    $menuPushProfile.Add_Click({
        $selectedRow = $dgvServers.CurrentRow
        if ($selectedRow) {
            $ip = $selectedRow.Cells["IPAddress"].Value
            # Read the profile from this row's per-row Profile cell (Task 1)
            $rowProfileName = $selectedRow.Cells["Profile"].Value
            if ($ip -and -not [string]::IsNullOrWhiteSpace($rowProfileName)) {
                $confirmResult = [System.Windows.Forms.MessageBox]::Show(
                    "Push profile '$rowProfileName' to $ip?",
                    "Confirm Deployment",
                    [System.Windows.Forms.MessageBoxButtons]::YesNo,
                    [System.Windows.Forms.MessageBoxIcon]::Question)
                if ($confirmResult -eq [System.Windows.Forms.DialogResult]::Yes) {
                    $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] Starting push to $ip...`r`n")
                    try {
                        $profileObj = Get-Profile -Name $rowProfileName
                        if (-not $profileObj) {
                            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] ERROR: Could not load profile '$rowProfileName'`r`n")
                        } else {
                            # Build credentials if provided
                            $cred = $null
                            if (-not $chkCurrentCreds.Checked -and $txtUsername.Text -and $txtPassword.Text) {
                                $secPass = ConvertTo-SecureString $txtPassword.Text -AsPlainText -Force
                                $cred = New-Object System.Management.Automation.PSCredential($txtUsername.Text, $secPass)
                                $secPass = $null
                                $txtPassword.Text = ''
                            }
                            $pushResult = Push-ProfileToServer -ServerIP $ip -Profile $profileObj -Credential $cred
                            foreach ($step in $pushResult.Steps) {
                                $status = if ($step.Success) { 'OK' } else { 'FAIL' }
                                $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   [$status] $($step.StepName): $($step.Message)`r`n")
                            }
                            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] Push to $ip completed.`r`n")
                        }
                    } catch {
                        $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] ERROR: Push failed - $($_.Exception.Message)`r`n")
                    }
                }
            } else {
                [System.Windows.Forms.MessageBox]::Show(
                    "Please assign a profile to this row first (use the Profile column or 'Set All To:' dropdown).",
                    "No Profile Assigned",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            }
        }
    })

    $contextMenu.Items.AddRange(@($menuViewDetails, $menuTestConnection, $menuPushProfile))
    $dgvServers.ContextMenuStrip = $contextMenu

    # --- Buttons below the grid ---
    $btnSelectAll = New-StyledButton -Text "Select All" -X 15 -Y 235 -Width 100 -Height 30
    $btnSelectAll.Add_Click({
        foreach ($row in $dgvServers.Rows) {
            $row.Cells["Select"].Value = $true
        }
        $selectedCount = $dgvServers.Rows.Count
        $lblTargetSummary.Text = "$selectedCount server(s) selected"
    })

    $btnDeselectAll = New-StyledButton -Text "Deselect All" -X 125 -Y 235 -Width 110 -Height 30
    $btnDeselectAll.Add_Click({
        foreach ($row in $dgvServers.Rows) {
            $row.Cells["Select"].Value = $false
        }
        $lblTargetSummary.Text = "0 servers selected"
    })

    $btnRefreshServers = New-StyledButton -Text "Refresh" -X 245 -Y 235 -Width 100 -Height 30
    $btnRefreshServers.Add_Click({
        # Re-populate the grid from the last cached scan results
        if ($script:AppState.LastScanResults -and $script:AppState.LastScanResults.Count -gt 0) {
            $dgvServers.Rows.Clear()
            foreach ($server in $script:AppState.LastScanResults) {
                $statusText = if ($server.IsDisguise) { "Disguise" }
                              elseif ($server.Ports.Count -gt 0) { "Online" }
                              else { "Unreachable" }
                $apiText = if ($server.APIVersion) { $server.APIVersion } else { "N/A" }
                $portsText = if ($server.Ports.Count -gt 0) { $server.Ports -join ", " } else { "None" }
                $responseText = if ($server.ResponseTimeMs -ge 0) { "$($server.ResponseTimeMs) ms" } else { "N/A" }

                # Profile cell starts blank; columns: Select, IP, Hostname, Status, API, Ports, ResponseTime, Profile
                [void]$dgvServers.Rows.Add($false, $server.IPAddress, $server.Hostname,
                                            $statusText, $apiText, $portsText, $responseText, "")
            }
            $lblScanStatus.Text = "Refreshed: $($script:AppState.LastScanResults.Count) server(s)"
            $lblScanStatus.ForeColor = $script:Theme.TextMuted
        }
    })

    $btnViewDetails = New-StyledButton -Text "View Details" -X 355 -Y 235 -Width 120 -Height 30
    $btnViewDetails.Add_Click({
        # Trigger the same action as the context menu "View Details"
        $selectedRow = $dgvServers.CurrentRow
        if ($selectedRow) {
            $ip = $selectedRow.Cells["IPAddress"].Value
            if ($ip) {
                $lblScanStatus.Text = "Testing $ip..."
                $lblScanStatus.Refresh()
                try {
                    $details = Test-DisguiseServer -IPAddress $ip -TimeoutMs 3000
                    $detailMsg = "Server: $ip`n" +
                                 "Hostname: $($details.Hostname)`n" +
                                 "Is Disguise: $($details.IsDisguise)`n" +
                                 "API Available: $($details.APIAvailable)`n" +
                                 "SMC Available: $($details.SMCAvailable)`n" +
                                 "Open Ports: $($details.Ports -join ', ')`n" +
                                 "Designer Version: $($details.DesignerVersion)"
                    [System.Windows.Forms.MessageBox]::Show($detailMsg, "Server Details - $ip",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                } catch {
                    [System.Windows.Forms.MessageBox]::Show("Failed to get details: $_",
                        "Error", [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
                }
                $lblScanStatus.Text = "Ready"
                $lblScanStatus.ForeColor = $script:Theme.TextMuted
            }
        }
    })

    $serversCard.Controls.AddRange(@($dgvServers, $btnSelectAll, $btnDeselectAll,
                                      $btnRefreshServers, $btnViewDetails))

    $scrollContainer.Controls.Add($serversCard)

    # ===================================================================
    # Card 3: Validation Tools (NIC Consistency & Pre-Flight Check)
    # ===================================================================
    $validationCard = New-StyledCard -Title "Validation Tools" -X 20 -Y 560 -Width 900 -Height 105

    $btnValidateNIC = New-StyledButton -Text "Validate NIC Names" -X 15 -Y 45 `
        -Width 180 -Height 35 -IsPrimary

    $btnPreFlight = New-StyledButton -Text "Pre-Flight Check" -X 210 -Y 45 `
        -Width 170 -Height 35

    $lblValidationStatus = New-StyledLabel -Text "Run validation checks before deployment" `
        -X 400 -Y 52 -FontSize 9 -IsMuted
    $lblValidationStatus.AutoSize = $false
    $lblValidationStatus.Width = 480

    $validationCard.Controls.AddRange(@($btnValidateNIC, $btnPreFlight, $lblValidationStatus))
    $scrollContainer.Controls.Add($validationCard)

    # ===================================================================
    # Card 4: Deploy Configuration
    # ===================================================================
    $deployCard = New-StyledCard -Title "Deploy Configuration" -X 20 -Y 675 -Width 900 -Height 250

    # --- "Set All To:" bulk profile setter (Task 1)
    # Selecting a profile here propagates it to every row's Profile cell in one shot.
    # The per-row Profile column remains the authoritative source for deployment.
    $lblProfile = New-StyledLabel -Text "Set All To:" -X 15 -Y 48 -FontSize 9
    # Reuse the already-collected $allProfileNames (gathered when building the grid column)
    $cboProfiles = New-StyledComboBox -X 100 -Y 45 -Width 230 -Items $allProfileNames

    $cboProfiles.Add_SelectedIndexChanged({
        # Bulk-set every row's Profile cell to the selected value
        $bulkProfile = $cboProfiles.SelectedItem
        if (-not [string]::IsNullOrWhiteSpace($bulkProfile)) {
            foreach ($row in $dgvServers.Rows) {
                $row.Cells["Profile"].Value = $bulkProfile
            }
        }
    })

    # --- Target summary label ---
    $lblTargetSummary = New-StyledLabel -Text "0 servers selected" -X 345 -Y 48 -FontSize 9 -IsSecondary

    $deployCard.Controls.AddRange(@($lblProfile, $cboProfiles, $lblTargetSummary))

    # --- Credential section ---
    $lblUsername = New-StyledLabel -Text "Username:" -X 15 -Y 85 -FontSize 9
    $txtUsername = New-StyledTextBox -X 95 -Y 82 -Width 160
    $txtUsername.Text = "Administrator"

    $lblPassword = New-StyledLabel -Text "Password:" -X 270 -Y 85 -FontSize 9
    $txtPassword = New-StyledTextBox -X 345 -Y 82 -Width 160
    $txtPassword.UseSystemPasswordChar = $true

    $chkCurrentCreds = New-StyledCheckBox -Text "Use Current Credentials" -X 525 -Y 83
    $chkCurrentCreds.Add_CheckedChanged({
        $isChecked = $this.Checked
        $txtUsername.Enabled = -not $isChecked
        $txtPassword.Enabled = -not $isChecked
        if ($isChecked) {
            $txtUsername.Text = $env:USERNAME
            $txtPassword.Text = ""
        } else {
            $txtUsername.Text = "Administrator"
        }
    })

    $deployCard.Controls.AddRange(@($lblUsername, $txtUsername, $lblPassword, $txtPassword, $chkCurrentCreds))

    # --- Deploy button ---
    $btnDeploy = New-StyledButton -Text "Deploy to Selected Servers" -X 15 -Y 120 `
        -Width 250 -Height 40 -IsPrimary

    # Deployment progress bar (styled)
    $deployProgressBar = New-StyledProgressBar -X 280 -Y 125 -Width 580 -Height 22

    $deployCard.Controls.AddRange(@($btnDeploy, $deployProgressBar))

    # --- Deployment log (read-only multi-line textbox) ---
    $txtDeployLog = New-Object System.Windows.Forms.TextBox
    $txtDeployLog.Location = New-Object System.Drawing.Point(15, 160)
    $txtDeployLog.Size = New-Object System.Drawing.Size(870, 75)
    $txtDeployLog.Multiline = $true
    $txtDeployLog.ReadOnly = $true
    $txtDeployLog.ScrollBars = [System.Windows.Forms.ScrollBars]::Vertical
    $txtDeployLog.BackColor = $script:Theme.InputBackground
    $txtDeployLog.ForeColor = $script:Theme.TextSecondary
    $txtDeployLog.Font = New-Object System.Drawing.Font('Consolas', 10)
    $txtDeployLog.BorderStyle = [System.Windows.Forms.BorderStyle]::FixedSingle
    $txtDeployLog.Text = "[$(Get-Date -Format 'HH:mm:ss')] Deploy log initialized. Select a profile and target servers to begin.`r`n"

    $deployCard.Controls.Add($txtDeployLog)

    $scrollContainer.Controls.Add($deployCard)

    # ===================================================================
    # Helper: populate the server grid from a results array
    # Used by both scan completion paths.
    # (defined early so validation handlers can reference $populateGrid)

    # ===================================================================
    # Event Handlers - Validate NIC Names Button
    # ===================================================================
    $btnValidateNIC.Add_Click({
        $btnValidateNIC.Enabled = $false
        $lblValidationStatus.Text = "Loading profiles..."
        $lblValidationStatus.ForeColor = $script:Theme.Accent
        $lblValidationStatus.Refresh()
        [System.Windows.Forms.Application]::DoEvents()

        try {
            $profiles = Get-AllProfiles
            if (-not $profiles -or $profiles.Count -lt 2) {
                $lblValidationStatus.Text = "Need at least 2 profiles to compare NIC names. Found $(@($profiles).Count)."
                $lblValidationStatus.ForeColor = $script:Theme.Warning
                $btnValidateNIC.Enabled = $true
                return
            }

            $lblValidationStatus.Text = "Comparing adapter names across $($profiles.Count) profiles..."
            $lblValidationStatus.Refresh()
            [System.Windows.Forms.Application]::DoEvents()

            $nicResult = Test-NICConsistency -Profiles $profiles

            # Build a results message and display in the deploy log
            $timestamp = Get-Date -Format 'HH:mm:ss'
            $txtDeployLog.AppendText("`r`n[$timestamp] === NIC Name Consistency Check ===`r`n")
            $txtDeployLog.AppendText("[$timestamp] Compared $($profiles.Count) profile(s)`r`n")

            if ($nicResult.IsConsistent) {
                $txtDeployLog.AppendText("[$timestamp] PASSED: All adapter names are consistent across profiles.`r`n")
                $lblValidationStatus.Text = "NIC check PASSED: All adapter names consistent across $($profiles.Count) profiles."
                $lblValidationStatus.ForeColor = $script:Theme.Success
            } else {
                $warningCount = $nicResult.Warnings.Count
                $txtDeployLog.AppendText("[$timestamp] WARNING: Found $warningCount inconsistency issue(s):`r`n")
                foreach ($warning in $nicResult.Warnings) {
                    $txtDeployLog.AppendText("[$timestamp]   Role: $($warning.Role)`r`n")
                    $txtDeployLog.AppendText("[$timestamp]     Servers: $($warning.Servers -join ', ')`r`n")
                    $txtDeployLog.AppendText("[$timestamp]     Names: $($warning.Names -join ', ')`r`n")
                    $txtDeployLog.AppendText("[$timestamp]     $($warning.Message)`r`n")
                }
                $lblValidationStatus.Text = "NIC check: $warningCount warning(s) found. See deploy log for details."
                $lblValidationStatus.ForeColor = $script:Theme.Warning

                # Also show a summary MessageBox for immediate visibility
                $summaryLines = @("NIC Name Consistency Check: $warningCount issue(s) found.", "")
                foreach ($warning in $nicResult.Warnings) {
                    $summaryLines += "Role: $($warning.Role)"
                    $summaryLines += "  Servers: $($warning.Servers -join ', ')"
                    $summaryLines += "  Names: $($warning.Names -join ', ')"
                    $summaryLines += ""
                }
                $summaryLines += "Mismatched adapter names will break sACN/Art-Net multicast."
                $summaryLines += "Ensure all servers use identical adapter names for each role."
                [System.Windows.Forms.MessageBox]::Show(
                    ($summaryLines -join "`n"),
                    "NIC Name Inconsistencies Detected",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            }
            $txtDeployLog.AppendText("[$timestamp] === End NIC Check ===`r`n")

        } catch {
            $lblValidationStatus.Text = "NIC validation error: $($_.Exception.Message)"
            $lblValidationStatus.ForeColor = $script:Theme.Error
            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] ERROR: NIC validation failed - $($_.Exception.Message)`r`n")
            Write-AppLog -Message "Validate NIC Names: Error - $_" -Level 'ERROR'
        } finally {
            $btnValidateNIC.Enabled = $true
            $txtDeployLog.ScrollToCaret()
        }
    })

    # ===================================================================
    # Event Handlers - Pre-Flight Check Button
    # ===================================================================
    $btnPreFlight.Add_Click({
        # Collect server IPs from the grid (selected servers, or all if none selected)
        $targetIPs = [System.Collections.ArrayList]::new()
        foreach ($row in $dgvServers.Rows) {
            if ($row.Cells["Select"].Value -eq $true) {
                [void]$targetIPs.Add($row.Cells["IPAddress"].Value)
            }
        }

        # If no servers are selected, use all servers in the grid
        if ($targetIPs.Count -eq 0) {
            foreach ($row in $dgvServers.Rows) {
                $ipVal = $row.Cells["IPAddress"].Value
                if ($ipVal) {
                    [void]$targetIPs.Add($ipVal)
                }
            }
        }

        if ($targetIPs.Count -eq 0) {
            [System.Windows.Forms.MessageBox]::Show(
                "No servers available. Run a network scan first to discover servers.",
                "No Servers",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }

        $btnPreFlight.Enabled = $false
        $btnValidateNIC.Enabled = $false
        $lblValidationStatus.Text = "Running pre-flight checks on $($targetIPs.Count) server(s)..."
        $lblValidationStatus.ForeColor = $script:Theme.Accent
        $lblValidationStatus.Refresh()

        # Build credential if provided
        $credential = $null
        if (-not $chkCurrentCreds.Checked) {
            $username = $txtUsername.Text.Trim()
            $password = $txtPassword.Text
            if (-not [string]::IsNullOrWhiteSpace($username) -and -not [string]::IsNullOrWhiteSpace($password)) {
                $securePassword = ConvertTo-SecureString $password -AsPlainText -Force
                $credential = New-Object System.Management.Automation.PSCredential($username, $securePassword)
            }
            $password = $null
            $txtPassword.Text = ''
        }

        $timestamp = Get-Date -Format 'HH:mm:ss'
        $txtDeployLog.AppendText("`r`n[$timestamp] === Pre-Flight Network Health Check ===`r`n")
        $txtDeployLog.AppendText("[$timestamp] Checking $($targetIPs.Count) server(s)...`r`n")
        $txtDeployLog.Refresh()
        [System.Windows.Forms.Application]::DoEvents()

        try {
            $progressAction = {
                param($serverIP, $checkIdx, $totalChecks, $checkName)
                $lblValidationStatus.Text = "Pre-flight: $serverIP - $checkName ($checkIdx/$totalChecks)"
                $lblValidationStatus.Refresh()
                [System.Windows.Forms.Application]::DoEvents()
            }

            $preFlightResult = Invoke-PreFlightCheck -Servers $targetIPs.ToArray() `
                -Credential $credential -ProgressCallback $progressAction

            # Display results in the deploy log with status indicators
            $totalPassed = 0
            $totalFailed = 0
            $serversWithIssues = 0

            foreach ($serverResult in $preFlightResult.Results) {
                $serverIP = $serverResult.Server
                $failedChecks = @($serverResult.Checks | Where-Object { -not $_.Passed })
                $passedChecks = @($serverResult.Checks | Where-Object { $_.Passed })

                $serverStatus = if ($failedChecks.Count -eq 0) { "ALL PASSED" } else { "$($failedChecks.Count) FAILED" }
                $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] Server: $serverIP [$serverStatus]`r`n")

                foreach ($check in $serverResult.Checks) {
                    $icon = if ($check.Passed) { "[OK]  " } else { "[FAIL]" }
                    $txtDeployLog.AppendText("    $icon $($check.Name): $($check.Message)`r`n")

                    if ($check.Passed) { $totalPassed++ } else { $totalFailed++ }
                }

                if ($failedChecks.Count -gt 0) { $serversWithIssues++ }

                $txtDeployLog.Refresh()
                [System.Windows.Forms.Application]::DoEvents()
            }

            # Summary line
            $totalChecks = $totalPassed + $totalFailed
            $passedServers = $preFlightResult.Results.Count - $serversWithIssues
            $summaryMsg = "Pre-flight: $passedServers/$($preFlightResult.Results.Count) servers passed all checks."
            if ($serversWithIssues -gt 0) {
                $summaryMsg += " $serversWithIssues server(s) have issues."
            }

            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] $summaryMsg`r`n")
            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] === End Pre-Flight Check ===`r`n")

            if ($preFlightResult.AllPassed) {
                $lblValidationStatus.Text = $summaryMsg
                $lblValidationStatus.ForeColor = $script:Theme.Success
            } else {
                $lblValidationStatus.Text = $summaryMsg
                $lblValidationStatus.ForeColor = $script:Theme.Warning
            }

            # Show a summary dialog with the check matrix
            $dialogLines = @($summaryMsg, "")
            foreach ($serverResult in $preFlightResult.Results) {
                $failedChecks = @($serverResult.Checks | Where-Object { -not $_.Passed })
                $status = if ($failedChecks.Count -eq 0) { "PASS" } else { "ISSUES ($($failedChecks.Count))" }
                $dialogLines += "$($serverResult.Server): $status"
                foreach ($check in $serverResult.Checks) {
                    $mark = if ($check.Passed) { "[OK]" } else { "[!!]" }
                    $dialogLines += "  $mark $($check.Name): $($check.Message)"
                }
                $dialogLines += ""
            }

            $dialogIcon = if ($preFlightResult.AllPassed) {
                [System.Windows.Forms.MessageBoxIcon]::Information
            } else {
                [System.Windows.Forms.MessageBoxIcon]::Warning
            }

            [System.Windows.Forms.MessageBox]::Show(
                ($dialogLines -join "`n"),
                "Pre-Flight Check Results",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                $dialogIcon) | Out-Null

        } catch {
            $lblValidationStatus.Text = "Pre-flight error: $($_.Exception.Message)"
            $lblValidationStatus.ForeColor = $script:Theme.Error
            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] ERROR: Pre-flight check failed - $($_.Exception.Message)`r`n")
            Write-AppLog -Message "Pre-Flight Check: Error - $_" -Level 'ERROR'
        } finally {
            $btnPreFlight.Enabled = $true
            $btnValidateNIC.Enabled = $true
            $txtDeployLog.ScrollToCaret()
        }
    })

    # ===================================================================
    # Event Handlers - Scan Network Button
    # ===================================================================
    $populateGrid = {
        param([array]$ScanResults)
        $dgvServers.Rows.Clear()
        foreach ($server in $ScanResults) {
            $statusText   = if ($server.IsDisguise) { "Disguise" }
                            elseif ($server.Ports.Count -gt 0) { "Online" }
                            else { "Unreachable" }
            $apiText      = if ($server.APIVersion) { $server.APIVersion } else { "N/A" }
            $portsText    = if ($server.Ports.Count -gt 0) { $server.Ports -join ", " } else { "None" }
            $responseText = if ($server.ResponseTimeMs -ge 0) { "$($server.ResponseTimeMs) ms" } else { "N/A" }

            # Columns order: Select, IP, Hostname, Status, API, Ports, ResponseTime, Profile
            [void]$dgvServers.Rows.Add($false, $server.IPAddress, $server.Hostname,
                                        $statusText, $apiText, $portsText, $responseText, "")
        }
        # Apply status-based cell colouring
        foreach ($row in $dgvServers.Rows) {
            $statusVal = $row.Cells["Status"].Value
            if ($statusVal -eq "Disguise") {
                $row.Cells["Status"].Style.ForeColor = $script:Theme.Success
                $row.Cells["Status"].Style.Font = New-Object System.Drawing.Font('Segoe UI', 9.5, [System.Drawing.FontStyle]::Bold)
            } elseif ($statusVal -eq "Online") {
                $row.Cells["Status"].Style.ForeColor = $script:Theme.Warning
            }
        }
    }

    # ===================================================================
    # BackgroundWorker events (Task 2)
    # ===================================================================

    # DoWork -- runs on the worker thread.
    # Arguments passed via RunWorkerAsync are available in $e.Argument.
    $scanWorker.Add_DoWork({
        param($sender, $e)
        $scanArgs   = $e.Argument             # hashtable: SubnetBase, StartIP, EndIP, TimeoutMs
        $worker     = $sender               # reference to the BackgroundWorker itself

        $progressCb = {
            param($currentIP, $percentComplete, $statusMessage)
            # Guard against calling ReportProgress after cancellation was acknowledged
            if (-not $worker.CancellationPending) {
                $worker.ReportProgress($percentComplete, $statusMessage)
            }
        }

        try {
            $results = Find-DisguiseServers `
                -SubnetBase  $scanArgs.SubnetBase  `
                -StartIP     $scanArgs.StartIP     `
                -EndIP       $scanArgs.EndIP       `
                -TimeoutMs   $scanArgs.TimeoutMs   `
                -ProgressCallback $progressCb

            if ($worker.CancellationPending) {
                $e.Cancel = $true
                # Return the local partial results (not shared state -- avoids cross-thread race)
                $e.Result = $results
            } else {
                $e.Result = $results
            }
        } catch {
            # Surface the exception to RunWorkerCompleted via e.Error
            throw
        }
    })

    # ProgressChanged -- runs on the UI thread; safe to update controls directly.
    $scanWorker.Add_ProgressChanged({
        param($sender, $e)
        $pct = [Math]::Min(100, [Math]::Max(0, $e.ProgressPercentage))
        $scanProgressBar.Value = $pct
        if ($e.UserState) {
            $lblScanStatus.Text      = $e.UserState
            $lblScanStatus.ForeColor = $script:Theme.Accent
        }
    })

    # RunWorkerCompleted -- runs on the UI thread after DoWork exits (normally, cancelled, or error).
    $scanWorker.Add_RunWorkerCompleted({
        param($sender, $e)

        # Re-enable scan controls
        $btnScanNetwork.Enabled = $true
        $btnQuickScan.Enabled   = $true
        $btnDNSSD.Enabled       = $true
        $btnCancelScan.Enabled  = $false

        if ($e.Cancelled) {
            $scanProgressBar.Value   = 0
            $lblScanStatus.Text      = "Scan cancelled."
            $lblScanStatus.ForeColor = $script:Theme.Warning
            Write-AppLog -Message "Network scan cancelled by user." -Level 'INFO'

            # Show any partial results that were collected before cancellation
            if ($e.Result -and $e.Result.Count -gt 0) {
                & $populateGrid $e.Result
                $lblScanStatus.Text = "Scan cancelled -- showing $($e.Result.Count) partial result(s)."
            }
        } elseif ($e.Error) {
            $lblScanStatus.Text      = "Scan failed: $($e.Error.Message)"
            $lblScanStatus.ForeColor = $script:Theme.Error
            Write-AppLog -Message "Background scan error: $($e.Error)" -Level 'ERROR'
        } else {
            $results = $e.Result
            $script:AppState.LastScanResults = $results

            & $populateGrid $results

            $scanProgressBar.Value   = 100
            $disguiseCount           = ($results | Where-Object { $_.IsDisguise }).Count
            $lblScanStatus.Text      = "Scan complete: Found $($results.Count) host(s), $disguiseCount disguise server(s)"
            $lblScanStatus.ForeColor = $script:Theme.Success
        }
    })

    # ===================================================================
    # Event Handlers - Scan Network Button (now uses BackgroundWorker)
    # ===================================================================
    $btnScanNetwork.Add_Click({
        $subnet  = $txtSubnet.Text.Trim()
        $startIP = 1
        $endIP   = 254
        $timeout = 200

        # Validate and parse inputs
        try { $startIP = [int]$txtStartIP.Text.Trim() } catch { $startIP = 1 }
        try { $endIP   = [int]$txtEndIP.Text.Trim()   } catch { $endIP   = 254 }
        try { $timeout = [int]$txtTimeout.Text.Trim() } catch { $timeout = 200 }

        # Clamp timeout to safe bounds (50ms - 5000ms)
        $timeout = [Math]::Min([Math]::Max(50, $timeout), 5000)

        if ([string]::IsNullOrWhiteSpace($subnet)) { $subnet = "10.0.0" }

        # Validate subnet format
        if ($subnet -notmatch '^\d{1,3}\.\d{1,3}\.\d{1,3}$') {
            $lblScanStatus.Text      = "Invalid subnet format. Use 'X.X.X' (e.g. '10.0.0')."
            $lblScanStatus.ForeColor = $script:Theme.Error
            return
        }

        # Validate IP range
        if ($startIP -lt 0 -or $startIP -gt 255 -or $endIP -lt 0 -or $endIP -gt 255 -or $startIP -gt $endIP) {
            $lblScanStatus.Text      = "Invalid IP range. Start and End must be 0-255, Start <= End."
            $lblScanStatus.ForeColor = $script:Theme.Error
            return
        }

        if ($scanWorker.IsBusy) {
            # Guard against double-start (should not happen because button is disabled)
            return
        }

        # Update UI state for scanning
        $btnScanNetwork.Enabled  = $false
        $btnQuickScan.Enabled    = $false
        $btnDNSSD.Enabled        = $false
        $btnCancelScan.Enabled   = $true
        $lblScanStatus.Text      = "Scanning $subnet.$startIP - $subnet.$endIP ..."
        $lblScanStatus.ForeColor = $script:Theme.Accent
        $scanProgressBar.Value   = 0
        $dgvServers.Rows.Clear()

        # Pack arguments into a hashtable; DoWork receives them via e.Argument
        $scanArgs = @{
            SubnetBase = $subnet
            StartIP    = $startIP
            EndIP      = $endIP
            TimeoutMs  = $timeout
        }

        $scanWorker.RunWorkerAsync($scanArgs)
    })

    # ===================================================================
    # Event Handlers - Cancel Scan Button (Task 2)
    # ===================================================================
    $btnCancelScan.Add_Click({
        if ($scanWorker.IsBusy -and -not $scanWorker.CancellationPending) {
            $scanWorker.CancelAsync()
            $lblScanStatus.Text      = "Cancelling scan..."
            $lblScanStatus.ForeColor = $script:Theme.Warning
            $btnCancelScan.Enabled   = $false   # prevent double-clicks
        }
    })

    # ===================================================================
    # Event Handlers - Quick Scan Button (common IPs only)
    # Quick scan runs synchronously on the UI thread (small target set).
    # ===================================================================
    $btnQuickScan.Add_Click({
        $subnet = $txtSubnet.Text.Trim()
        if ([string]::IsNullOrWhiteSpace($subnet)) { $subnet = "10.0.0" }

        # Validate subnet format (same check as full scan)
        if ($subnet -notmatch '^\d{1,3}\.\d{1,3}\.\d{1,3}$') {
            $lblScanStatus.Text      = "Invalid subnet format. Use 'X.X.X' (e.g. '10.0.0')."
            $lblScanStatus.ForeColor = $script:Theme.Error
            return
        }

        $btnScanNetwork.Enabled  = $false
        $btnQuickScan.Enabled    = $false
        $btnDNSSD.Enabled        = $false
        $btnCancelScan.Enabled   = $false   # quick scan is not cancellable
        $lblScanStatus.Text      = "Quick scan on common IPs..."
        $lblScanStatus.ForeColor = $script:Theme.Accent
        $lblScanStatus.Refresh()
        $scanProgressBar.Value = 0
        $dgvServers.Rows.Clear()

        try {
            # Quick scan targets: common disguise server IPs (low range and .10x, .20x patterns)
            $quickTargets = @(1, 2, 3, 4, 5, 10, 11, 12, 13, 14, 15, 20, 21, 22, 30, 50, 100,
                              101, 102, 103, 104, 105, 110, 150, 200, 201, 210, 250, 251, 252, 253, 254)
            $totalTargets = $quickTargets.Count
            $results = [System.Collections.ArrayList]::new()

            for ($idx = 0; $idx -lt $totalTargets; $idx++) {
                $ip = "$subnet.$($quickTargets[$idx])"
                $lblScanStatus.Text    = "Quick scan: $ip ($($idx + 1)/$totalTargets)"
                $scanProgressBar.Value = [int](($idx / $totalTargets) * 100)
                $scanProgressBar.Refresh()
                $lblScanStatus.Refresh()
                [System.Windows.Forms.Application]::DoEvents()

                try {
                    $testResult = Test-DisguiseServer -IPAddress $ip -TimeoutMs 500
                    if ($testResult.Ports.Count -gt 0) {
                        $serverObj = [PSCustomObject]@{
                            IPAddress      = $testResult.IPAddress
                            Hostname       = $testResult.Hostname
                            IsDisguise     = $testResult.IsDisguise
                            ResponseTimeMs = 0
                            Ports          = $testResult.Ports
                            APIVersion     = $testResult.DesignerVersion
                        }
                        [void]$results.Add($serverObj)
                    }
                } catch {
                    Write-AppLog -Message "Quick scan: Could not test host ${ip}: $_" -Level 'DEBUG'
                }
            }

            # Store results in app state
            $script:AppState.LastScanResults = $results.ToArray()

            # Populate the grid using the shared helper (includes Profile column)
            & $populateGrid $results.ToArray()

            $scanProgressBar.Value   = 100
            $disguiseCount           = ($results | Where-Object { $_.IsDisguise }).Count
            $lblScanStatus.Text      = "Quick scan complete: Found $($results.Count) host(s), $disguiseCount disguise server(s)"
            $lblScanStatus.ForeColor = $script:Theme.Success

        } catch {
            $lblScanStatus.Text      = "Quick scan failed: $_"
            $lblScanStatus.ForeColor = $script:Theme.Error
            Write-AppLog -Message "Quick scan error: $_" -Level 'ERROR'
        } finally {
            $btnScanNetwork.Enabled = $true
            $btnQuickScan.Enabled   = $true
            $btnDNSSD.Enabled       = $true
        }
    })

    # ===================================================================
    # Event Handlers - Auto-Discover (DNS-SD) Button
    # ===================================================================
    $btnDNSSD.Add_Click({
        $btnScanNetwork.Enabled = $false
        $btnQuickScan.Enabled   = $false
        $btnDNSSD.Enabled       = $false

        $lblScanStatus.Text     = "Querying DNS-SD for _d3api._tcp.local. -- please wait..."
        $lblScanStatus.ForeColor = $script:Theme.Accent
        $lblScanStatus.Refresh()
        $scanProgressBar.Value  = 0
        [System.Windows.Forms.Application]::DoEvents()

        try {
            $dnssdResults = Find-DisguiseServersDNSSD

            if ($dnssdResults.Count -eq 0) {
                $lblScanStatus.Text = "No servers found via DNS-SD. Try a subnet scan instead."
                $lblScanStatus.ForeColor = $script:Theme.Warning
                $scanProgressBar.Value = 100
            } else {
                # Merge DNS-SD results with any existing scan results (deduplicate by IP)
                $existingResults = if ($script:AppState.LastScanResults) {
                    [System.Collections.ArrayList]($script:AppState.LastScanResults)
                } else {
                    [System.Collections.ArrayList]::new()
                }

                $mergedCount = 0
                foreach ($dnsServer in $dnssdResults) {
                    $alreadyKnown = $existingResults | Where-Object { $_.IPAddress -eq $dnsServer.IPAddress }
                    if (-not $alreadyKnown) {
                        [void]$existingResults.Add($dnsServer)
                        $mergedCount++
                    } else {
                        # Update IsDisguise flag on the existing entry if not already set
                        $alreadyKnown.IsDisguise = $true
                    }
                }

                # Persist the merged results
                $script:AppState.LastScanResults = $existingResults.ToArray()

                # Repopulate the discovered-servers grid with the merged list
                & $populateGrid $script:AppState.LastScanResults

                $scanProgressBar.Value = 100
                $newCount   = $dnssdResults.Count
                $lblScanStatus.Text = "DNS-SD found $newCount server(s) ($mergedCount new). Grid shows $($script:AppState.LastScanResults.Count) total."
                $lblScanStatus.ForeColor = $script:Theme.Success

                Write-AppLog -Message "DNS-SD discovery: $newCount server(s) found, $mergedCount merged into existing results." -Level 'INFO'
            }
        } catch {
            $lblScanStatus.Text = "DNS-SD discovery failed: $_"
            $lblScanStatus.ForeColor = $script:Theme.Error
            Write-AppLog -Message "DNS-SD discovery error: $_" -Level 'ERROR'
        } finally {
            $btnScanNetwork.Enabled = $true
            $btnQuickScan.Enabled   = $true
            $btnDNSSD.Enabled       = $true
            $btnCancelScan.Enabled  = $false   # DNS-SD is not cancellable
        }
    })

    # ===================================================================
    # Event Handlers - Deploy Button (per-row profiles)
    # ===================================================================
    $btnDeploy.Add_Click({
        # Build the list of selected rows with their per-row profile assignments
        $selectedTargets = [System.Collections.ArrayList]::new()
        foreach ($row in $dgvServers.Rows) {
            if ($row.Cells["Select"].Value -eq $true) {
                [void]$selectedTargets.Add([PSCustomObject]@{
                    IP          = $row.Cells["IPAddress"].Value
                    ProfileName = $row.Cells["Profile"].Value
                })
            }
        }

        if ($selectedTargets.Count -eq 0) {
            [System.Windows.Forms.MessageBox]::Show(
                "No servers selected. Please check the servers you want to deploy to.",
                "No Selection",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }

        # --- Pre-deploy validation: every selected row must have a profile assigned ---
        $missingProfile = $selectedTargets | Where-Object { [string]::IsNullOrWhiteSpace($_.ProfileName) }
        if ($missingProfile.Count -gt 0) {
            $missingList = ($missingProfile | ForEach-Object { $_.IP }) -join "`n"
            [System.Windows.Forms.MessageBox]::Show(
                "The following selected server(s) have no profile assigned.`nAssign a profile in the Profile column (or use 'Set All To:') before deploying.`n`n$missingList",
                "Missing Profile Assignment",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }

        # Build a confirmation summary (show distinct profiles used)
        $summaryLines = $selectedTargets | ForEach-Object { "  $($_.IP)  ->  $($_.ProfileName)" }
        $confirmResult = [System.Windows.Forms.MessageBox]::Show(
            "Deploy to $($selectedTargets.Count) server(s)?`n`n$($summaryLines -join "`n")",
            "Confirm Deployment",
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Question)

        if ($confirmResult -ne [System.Windows.Forms.DialogResult]::Yes) {
            return
        }

        # Build credential object once (shared across all targets)
        $credential = $null
        if (-not $chkCurrentCreds.Checked) {
            $username = $txtUsername.Text.Trim()
            $password = $txtPassword.Text
            if (-not [string]::IsNullOrWhiteSpace($username) -and -not [string]::IsNullOrWhiteSpace($password)) {
                $securePassword = ConvertTo-SecureString $password -AsPlainText -Force
                $credential = New-Object System.Management.Automation.PSCredential($username, $securePassword)
            }
            # Clear plaintext password from memory immediately
            $password = $null
            $txtPassword.Text = ''
        }

        # Disable the deploy button during operation
        $btnDeploy.Enabled = $false
        $deployProgressBar.Value = 0

        $totalServers  = $selectedTargets.Count
        $currentIdx    = 0
        $successCount  = 0
        $lastSuccessProfile = $null

        try {
            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] Starting deployment to $totalServers server(s)...`r`n")
            $txtDeployLog.Refresh()

            foreach ($target in $selectedTargets) {
                $currentIdx++
                $serverIP    = $target.IP
                $profileName = $target.ProfileName

                $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] [$currentIdx/$totalServers] $serverIP <- '$profileName'...`r`n")
                $txtDeployLog.Refresh()
                $deployProgressBar.Value = [int](($currentIdx / $totalServers) * 100)
                $deployProgressBar.Refresh()
                [System.Windows.Forms.Application]::DoEvents()

                # Load this target's specific profile
                $profileObj = $null
                try {
                    $profileObj = Get-Profile -Name $profileName
                } catch {
                    $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   ERROR: Could not load profile '$profileName': $_`r`n")
                    $txtDeployLog.Refresh()
                    continue
                }

                if (-not $profileObj) {
                    $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   ERROR: Profile '$profileName' not found.`r`n")
                    $txtDeployLog.Refresh()
                    continue
                }

                try {
                    $pushParams = @{
                        ServerIP = $serverIP
                        Profile  = $profileObj
                    }
                    if ($credential) {
                        $pushParams.Credential = $credential
                    }

                    $pushResult = Push-ProfileToServer @pushParams

                    foreach ($step in $pushResult.Steps) {
                        $stepStatus = if ($step.Success) { "OK" } else { "FAILED" }
                        $txtDeployLog.AppendText("    $($step.StepName): $stepStatus - $($step.Message)`r`n")
                    }

                    if ($pushResult.Success) {
                        $successCount++
                        $lastSuccessProfile = $profileObj.Name
                        $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   $serverIP: Deployment SUCCEEDED`r`n")
                    } else {
                        $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   $serverIP: Deployment FAILED - $($pushResult.ErrorMessage)`r`n")
                    }
                } catch {
                    $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')]   $serverIP: EXCEPTION - $_`r`n")
                }

                $txtDeployLog.Refresh()
                [System.Windows.Forms.Application]::DoEvents()
            }

            $deployProgressBar.Value = 100
            $txtDeployLog.AppendText("[$(Get-Date -Format 'HH:mm:ss')] Deployment complete: $successCount/$totalServers succeeded.`r`n")
            $txtDeployLog.AppendText("------------------------------------------------------------`r`n")

            # Track the last successfully deployed profile in app state
            if ($lastSuccessProfile) {
                $script:AppState.LastAppliedProfile = $lastSuccessProfile
            }
        } finally {
            $btnDeploy.Enabled = $true
        }
    })

    # ===================================================================
    # Update target summary when checkbox values change in the grid
    # ===================================================================
    $dgvServers.Add_CellValueChanged({
        param($sender, $e)
        if ($e.ColumnIndex -eq 0) {
            # Checkbox column changed - recalculate selected count
            $selectedCount = 0
            foreach ($row in $dgvServers.Rows) {
                if ($row.Cells["Select"].Value -eq $true) {
                    $selectedCount++
                }
            }
            $lblTargetSummary.Text = "$selectedCount server(s) selected"
        }
    })

    # Ensure cell value changes are committed immediately (needed for checkbox and combobox columns)
    $dgvServers.Add_CurrentCellDirtyStateChanged({
        if ($dgvServers.IsCurrentCellDirty) {
            $dgvServers.CommitEdit([System.Windows.Forms.DataGridViewDataErrorContexts]::Commit)
        }
    })

    # Suppress DataError events from the Profile combobox column.
    # WinForms fires DataError when a cell value is not in the column's Items list
    # (e.g., the empty string sentinel we use as the "no profile" state).
    # We handle this gracefully at deploy time, so the built-in error dialog is unwanted.
    $dgvServers.Add_DataError({
        param($sender, $e)
        # Only suppress errors from the Profile combobox column; let others surface normally.
        if ($e.ColumnIndex -ge 0 -and $dgvServers.Columns[$e.ColumnIndex].Name -eq "Profile") {
            $e.ThrowException = $false
        }
    })

    # ===================================================================
    # Add the scroll container to the content panel
    # ===================================================================
    $scrollContainer.ResumeLayout($true)
    $ContentPanel.Controls.Add($scrollContainer)

    # Expose key controls for keyboard shortcut support (F5, Ctrl+Enter)
    $script:DeployViewActions = @{
        ScanButton   = $btnScanNetwork
        DeployButton = $btnDeploy
    }

    # Resize handler to keep scroll container matched to content panel
    $ContentPanel.Add_Resize({
        $sc = $this.Controls[0]
        if ($sc) { $sc.Size = $this.ClientSize }
    })

    # Resume layout now that all controls have been added
    $ContentPanel.ResumeLayout($true)
}

# ============================================================
# MODULE: Dashboard.ps1
# ============================================================
# Dashboard.ps1 - DISGUISE BUDDY Dashboard Overview Module
# Provides the New-DashboardView function which builds the main Dashboard panel
# displaying quick status cards, network overview, recent profiles, and quick actions.

# ============================================================================
# Application state is initialized in DisguiseBuddy.ps1 before modules load
# ============================================================================

# ============================================================================
# Helper Functions (private to this module)
# ============================================================================

# Get-ServerHostname removed — use Get-ServerHostname from ServerIdentity.ps1 instead

function Get-ActiveAdapterCount {
    <#
    .SYNOPSIS
        Returns a formatted string showing active vs total adapter count.
        Gracefully handles non-Windows systems.
    #>
    try {
        $allAdapters = Get-NetAdapter -ErrorAction Stop
        $activeAdapters = $allAdapters | Where-Object { $_.Status -eq 'Up' }
        $totalCount = $allAdapters.Count
        $activeCount = @($activeAdapters).Count
        return "$activeCount / $totalCount Active"
    } catch {
        return "N/A"
    }
}

function Get-ActiveShareCount {
    <#
    .SYNOPSIS
        Returns the count of non-default SMB shares.
        Gracefully handles non-Windows systems.
    #>
    try {
        $shares = Get-SmbShare -ErrorAction Stop |
            Where-Object { $_.Name -notmatch '^\$|^IPC\$|^ADMIN\$|^C\$|^D\$' }
        return "$(@($shares).Count) Shares"
    } catch {
        return "N/A"
    }
}

function Get-AdapterSummaryData {
    <#
    .SYNOPSIS
        Returns an array of adapter summary objects for the network overview table.
        Each object has: Role, InterfaceAlias, IPAddress, Status.
        Falls back to placeholder data on non-Windows systems.
    #>

    # Define the 6 standard disguise adapter roles
    $roles = @(
        @{ Role = "d3Net";    Color = "Purple" },
        @{ Role = "sACN";     Color = "Orange" },
        @{ Role = "Media";    Color = "Green" },
        @{ Role = "NDI";      Color = "Cyan" },
        @{ Role = "Control";  Color = "Blue" },
        @{ Role = "100G";     Color = "Gray" }
    )

    $summaryData = [System.Collections.ArrayList]::new()

    try {
        $adapters = Get-NetAdapter -ErrorAction Stop
        $ipConfigs = Get-NetIPAddress -AddressFamily IPv4 -ErrorAction Stop

        foreach ($roleEntry in $roles) {
            $roleName = $roleEntry.Role
            # Try to find an adapter whose name or description matches the role
            $matchedAdapter = $adapters | Where-Object {
                $_.Name -match $roleName -or $_.InterfaceDescription -match $roleName
            } | Select-Object -First 1

            if ($matchedAdapter) {
                $ipInfo = $ipConfigs | Where-Object { $_.InterfaceIndex -eq $matchedAdapter.InterfaceIndex } |
                    Select-Object -First 1
                $ipAddr = if ($ipInfo) { $ipInfo.IPAddress } else { "No IP" }
                $status = $matchedAdapter.Status

                [void]$summaryData.Add([PSCustomObject]@{
                    Role    = $roleName
                    Color   = $roleEntry.Color
                    IP      = $ipAddr
                    Status  = $status
                })
            } else {
                [void]$summaryData.Add([PSCustomObject]@{
                    Role    = $roleName
                    Color   = $roleEntry.Color
                    IP      = "Not Configured"
                    Status  = "N/A"
                })
            }
        }
    } catch {
        # Non-Windows or Get-NetAdapter not available: return placeholder data
        foreach ($roleEntry in $roles) {
            [void]$summaryData.Add([PSCustomObject]@{
                Role    = $roleEntry.Role
                Color   = $roleEntry.Color
                IP      = "Not Configured"
                Status  = "N/A"
            })
        }
    }

    return $summaryData.ToArray()
}

function Get-DisguiseServerDetails {
    <#
    .SYNOPSIS
        Queries a discovered disguise server's REST API and returns a structured
        summary of version, NIC status, GPU outputs, and project list.
    .DESCRIPTION
        Makes up to four sequential HTTP GET calls against the disguise REST API:
          GET /api/service/system              -> version
          GET /api/service/system/networkadapters -> NIC status
          GET /api/service/system/gpuoutputs   -> GPU output count
          GET /api/service/system/projects     -> project names/count

        All calls use a 3-second timeout. On any failure the relevant field is
        returned as "Unavailable" so callers never have to null-guard.
    .PARAMETER IPAddress
        The IPv4 address of the target disguise server.
    .PARAMETER Port
        The HTTP port on which the disguise REST API is listening. Defaults to 80.
    .OUTPUTS
        PSCustomObject with properties:
          IPAddress, Version, NICEnabled, NICDisconnected, GPUOutputs,
          ProjectCount, ProjectNames, APIReachable
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$IPAddress,

        [int]$Port = 80
    )

    # Validate IPv4 format and octet bounds to prevent SSRF via crafted hostnames/URLs
    $parsedIP = $null
    if (-not ([System.Net.IPAddress]::TryParse($IPAddress, [ref]$parsedIP)) -or
        $parsedIP.AddressFamily -ne [System.Net.Sockets.AddressFamily]::InterNetwork) {
        Write-AppLog -Message "Get-DisguiseServerDetails: Rejected non-IPv4 input '$IPAddress'" -Level 'WARN'
        return [PSCustomObject]@{
            IPAddress       = $IPAddress
            Version         = 'Invalid IP'
            NICEnabled      = 'N/A'
            NICDisconnected = 'N/A'
            GPUOutputs      = 'N/A'
            ProjectCount    = 'N/A'
            ProjectNames    = @()
            APIReachable    = $false
        }
    }

    # Build the base URL once — use the discovered port, not a hardcoded 80
    $baseUrl = if ($Port -eq 80) { "http://$IPAddress" } else { "http://$IPAddress`:$Port" }

    $result = [PSCustomObject]@{
        IPAddress      = $IPAddress
        Version        = 'Unavailable'
        NICEnabled     = 'Unavailable'
        NICDisconnected = 'Unavailable'
        GPUOutputs     = 'Unavailable'
        ProjectCount   = 'Unavailable'
        ProjectNames   = @()
        APIReachable   = $false
    }

    $httpClient = $null
    try {
        $httpClient = New-Object System.Net.Http.HttpClient
        $httpClient.Timeout = [TimeSpan]::FromSeconds(3)

        # ----------------------------------------------------------------
        # 1. System info — version
        # ----------------------------------------------------------------
        try {
            $sysJson = $httpClient.GetStringAsync("$baseUrl/api/service/system").Result
            $sysData = $sysJson | ConvertFrom-Json
            # disguise API returns d3VersionString or version depending on release
            $ver = if ($sysData.d3VersionString) {
                $sysData.d3VersionString
            } elseif ($sysData.version) {
                $sysData.version
            } else {
                'Unknown'
            }
            $result.Version = $ver
            $result.APIReachable = $true
        } catch {
            Write-AppLog -Message "Get-DisguiseServerDetails: /api/service/system failed for $IPAddress - $_" -Level 'DEBUG'
        }

        # ----------------------------------------------------------------
        # 2. Network adapters — enabled count and disconnected list
        # ----------------------------------------------------------------
        try {
            $nicJson = $httpClient.GetStringAsync("$baseUrl/api/service/system/networkadapters").Result
            $nicData = $nicJson | ConvertFrom-Json

            # The API may return a top-level array or an object with an adapters key
            $adapters = if ($nicData -is [System.Array]) {
                $nicData
            } elseif ($nicData.adapters) {
                $nicData.adapters
            } elseif ($nicData.networkAdapters) {
                $nicData.networkAdapters
            } else {
                @()
            }

            $enabledAdapters  = @($adapters | Where-Object { $_.enabled -eq $true -or $_.Enabled -eq $true })
            # Disconnected = enabled but no link / status indicates no cable
            $disconnected = @($adapters | Where-Object {
                ($_.enabled -eq $true -or $_.Enabled -eq $true) -and
                ($_.connected -eq $false -or $_.Connected -eq $false -or
                 $_.linkStatus -eq 'Down' -or $_.LinkStatus -eq 'Down' -or
                 $_.status -ieq 'Disconnected')
            })

            $result.NICEnabled     = $enabledAdapters.Count
            $result.NICDisconnected = $disconnected.Count
        } catch {
            Write-AppLog -Message "Get-DisguiseServerDetails: /api/service/system/networkadapters failed for $IPAddress - $_" -Level 'DEBUG'
        }

        # ----------------------------------------------------------------
        # 3. GPU outputs — count of active outputs
        # ----------------------------------------------------------------
        try {
            $gpuJson = $httpClient.GetStringAsync("$baseUrl/api/service/system/gpuoutputs").Result
            $gpuData = $gpuJson | ConvertFrom-Json

            $outputs = if ($gpuData -is [System.Array]) {
                $gpuData
            } elseif ($gpuData.outputs) {
                $gpuData.outputs
            } elseif ($gpuData.gpuOutputs) {
                $gpuData.gpuOutputs
            } else {
                @()
            }

            $activeOutputs = @($outputs | Where-Object {
                $_.active -eq $true -or $_.Active -eq $true -or
                $_.enabled -eq $true -or $_.Enabled -eq $true
            })
            $result.GPUOutputs = if ($activeOutputs.Count -gt 0) {
                $activeOutputs.Count
            } else {
                # If no "active" property, treat total count as active
                @($outputs).Count
            }
        } catch {
            Write-AppLog -Message "Get-DisguiseServerDetails: /api/service/system/gpuoutputs failed for $IPAddress - $_" -Level 'DEBUG'
        }

        # ----------------------------------------------------------------
        # 4. Projects — count and names
        # ----------------------------------------------------------------
        try {
            $projJson = $httpClient.GetStringAsync("$baseUrl/api/service/system/projects").Result
            $projData = $projJson | ConvertFrom-Json

            $projects = if ($projData -is [System.Array]) {
                $projData
            } elseif ($projData.projects) {
                $projData.projects
            } else {
                @()
            }

            $result.ProjectCount = @($projects).Count
            $result.ProjectNames = @($projects | ForEach-Object {
                if ($_.name) { $_.name }
                elseif ($_.projectName) { $_.projectName }
                elseif ($_ -is [string]) { $_ }
                else { $_.ToString() }
            })
        } catch {
            Write-AppLog -Message "Get-DisguiseServerDetails: /api/service/system/projects failed for $IPAddress - $_" -Level 'DEBUG'
        }

    } catch {
        Write-AppLog -Message "Get-DisguiseServerDetails: HttpClient init failed for $IPAddress - $_" -Level 'WARN'
    } finally {
        if ($httpClient) { $httpClient.Dispose() }
    }

    return $result
}

function Get-RecentProfilesList {
    <#
    .SYNOPSIS
        Returns the 5 most recently modified profiles, sorted by date descending.
    #>
    try {
        $allProfiles = Get-AllProfiles
        if ($allProfiles -and $allProfiles.Count -gt 0) {
            # Sort by Modified date if the property exists, otherwise by Name
            $sorted = $allProfiles | Sort-Object -Property {
                if ($_.Modified) { [datetime]$_.Modified } else { [datetime]::MinValue }
            } -Descending | Select-Object -First 5
            return $sorted
        }
    } catch {
        Write-AppLog -Message "Dashboard: Could not load profiles - $_" -Level 'WARN'
    }
    return @()
}

# ============================================================================
# UI View Function - Dashboard
# ============================================================================

function New-DashboardView {
    <#
    .SYNOPSIS
        Creates the Dashboard overview panel for DISGUISE BUDDY.
    .DESCRIPTION
        Builds the main Dashboard view with:
          - Row 1: Four quick-status cards (hostname, active profile, adapters, SMB shares)
          - Row 2: Network Overview (left) and Recent Profiles (right)
          - Row 3: Quick Actions bar
        Reads live system data where available, gracefully falling back to "N/A" on
        non-Windows platforms.
    .PARAMETER ContentPanel
        The parent panel to populate with dashboard controls.
    #>
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Panel]$ContentPanel
    )

    # Clear any existing controls from the content panel
    $ContentPanel.Controls.Clear()

    # Create a scrollable container for the entire dashboard
    $scrollContainer = New-ScrollPanel -X 0 -Y 0 -Width $ContentPanel.Width -Height $ContentPanel.Height
    $scrollContainer.Anchor = [System.Windows.Forms.AnchorStyles]::Top -bor
                              [System.Windows.Forms.AnchorStyles]::Left -bor
                              [System.Windows.Forms.AnchorStyles]::Right -bor
                              [System.Windows.Forms.AnchorStyles]::Bottom

    # ===================================================================
    # Section Header with Refresh Button
    # ===================================================================
    $sectionHeader = New-SectionHeader -Text "Dashboard" -X 20 -Y 10 -Width 900

    $subtitleLabel = New-StyledLabel -Text "DISGUISE BUDDY - Server Configuration Manager" `
        -X 20 -Y 48 -FontSize 9 -IsSecondary

    # Refresh button in the header area
    $btnRefreshDashboard = New-StyledButton -Text ([char]0x21BB + " Refresh") -X 820 -Y 10 `
        -Width 100 -Height 30
    $btnRefreshDashboard.Add_Click({
        try {
            Write-AppLog -Message "Dashboard: Refreshing all data" -Level 'INFO'
            Set-ActiveView -ViewName 'Dashboard'
        } catch {
            Write-AppLog -Message "Dashboard: Refresh failed - $_" -Level 'WARN'
        }
    })

    $scrollContainer.Controls.Add($sectionHeader)
    $scrollContainer.Controls.Add($subtitleLabel)
    $scrollContainer.Controls.Add($btnRefreshDashboard)

    # ===================================================================
    # Row 1: Quick Status Cards (4 cards in a row)
    # ===================================================================
    $cardY = 80
    $cardWidth = 215
    $cardHeight = 100
    $cardSpacing = 10
    $cardStartX = 20

    # --- Gather live data ---
    $currentHostname = Get-ServerHostname
    $activeProfile = if ($script:AppState.LastAppliedProfile) { $script:AppState.LastAppliedProfile } else { "None" }
    $adapterCount = Get-ActiveAdapterCount
    $shareCount = Get-ActiveShareCount

    # --- Card 1: Server Name ---
    $card1 = New-StyledCard -Title "Server Name" -X $cardStartX -Y $cardY `
        -Width $cardWidth -Height $cardHeight -AccentColor $script:Theme.Accent

    $hostnameStatusBadge = New-StatusBadge -Text "LIVE" -X 150 -Y 15 -Type 'Success'
    $card1.Controls.Add($hostnameStatusBadge)

    $lblHostnameValue = New-StyledLabel -Text $currentHostname -X 15 -Y 50 -FontSize 14 -IsBold -MaxWidth ($cardWidth - 30)
    $card1.Controls.Add($lblHostnameValue)

    $scrollContainer.Controls.Add($card1)

    # --- Card 2: Active Profile ---
    $card2X = $cardStartX + $cardWidth + $cardSpacing
    $card2 = New-StyledCard -Title "Active Profile" -X $card2X -Y $cardY `
        -Width $cardWidth -Height $cardHeight -AccentColor $script:Theme.Primary

    $profileBadgeType = if ($activeProfile -eq "None") { 'Info' } else { 'Success' }
    $profileBadgeText  = if ($activeProfile -eq "None") { 'NONE' } else { 'ACTIVE' }
    $profileStatusBadge = New-StatusBadge -Text $profileBadgeText `
        -X 150 -Y 15 -Type $profileBadgeType
    $card2.Controls.Add($profileStatusBadge)

    $lblProfileValue = New-StyledLabel -Text $activeProfile -X 15 -Y 50 -FontSize 12 -IsBold -MaxWidth ($cardWidth - 30)
    $card2.Controls.Add($lblProfileValue)

    $scrollContainer.Controls.Add($card2)

    # --- Card 3: Network Adapters ---
    $card3X = $card2X + $cardWidth + $cardSpacing
    $card3 = New-StyledCard -Title "Network Adapters" -X $card3X -Y $cardY `
        -Width $cardWidth -Height $cardHeight -AccentColor $script:Theme.Success

    $adapterBadgeType = if ($adapterCount -eq "N/A") { 'Warning' } else { 'Success' }
    $adapterBadgeText  = if ($adapterCount -eq "N/A") { 'N/A' }    else { 'ACTIVE' }
    $adapterStatusBadge = New-StatusBadge -Text $adapterBadgeText `
        -X 150 -Y 15 -Type $adapterBadgeType
    $card3.Controls.Add($adapterStatusBadge)

    $lblAdapterValue = New-StyledLabel -Text $adapterCount -X 15 -Y 50 -FontSize 12 -IsBold -MaxWidth ($cardWidth - 30)
    $card3.Controls.Add($lblAdapterValue)

    $scrollContainer.Controls.Add($card3)

    # --- Card 4: SMB Shares ---
    $card4X = $card3X + $cardWidth + $cardSpacing
    $card4 = New-StyledCard -Title "SMB Shares" -X $card4X -Y $cardY `
        -Width $cardWidth -Height $cardHeight -AccentColor $script:Theme.Warning

    $shareBadgeType = if ($shareCount -eq "N/A") { 'Warning' } else { 'Info' }
    $shareBadgeText  = if ($shareCount -eq "N/A") { 'N/A' }    else { 'ACTIVE' }
    $shareStatusBadge = New-StatusBadge -Text $shareBadgeText `
        -X 150 -Y 15 -Type $shareBadgeType
    $card4.Controls.Add($shareStatusBadge)

    $lblShareValue = New-StyledLabel -Text $shareCount -X 15 -Y 50 -FontSize 12 -IsBold -MaxWidth ($cardWidth - 30)
    $card4.Controls.Add($lblShareValue)

    $scrollContainer.Controls.Add($card4)

    # ===================================================================
    # Row 2: Two-column layout
    # ===================================================================
    $row2Y = $cardY + $cardHeight + 20  # 200
    $colWidth = 440
    $colHeight = 300
    $colSpacing = 20

    # --- Left Column: Network Overview ---
    $networkCard = New-StyledCard -Title "Network Overview" -X 20 -Y $row2Y `
        -Width $colWidth -Height $colHeight

    # Build the adapter summary table using a DataGridView
    $adapterData = Get-AdapterSummaryData

    $dgvAdapters = New-StyledDataGridView -X 15 -Y 45 -Width ($colWidth - 30) -Height 200

    # Columns: Status dot (color), Role, IP Address, Status badge
    $colDot = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colDot.HeaderText = ""
    $colDot.Name = "StatusDot"
    $colDot.Width = 30
    $colDot.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colRole = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colRole.HeaderText = "Role"
    $colRole.Name = "Role"
    $colRole.Width = 100
    $colRole.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colAdapterIP = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colAdapterIP.HeaderText = "IP Address"
    $colAdapterIP.Name = "IPAddress"
    $colAdapterIP.Width = 140
    $colAdapterIP.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::None

    $colAdapterStatus = New-Object System.Windows.Forms.DataGridViewTextBoxColumn
    $colAdapterStatus.HeaderText = "Status"
    $colAdapterStatus.Name = "Status"
    $colAdapterStatus.AutoSizeMode = [System.Windows.Forms.DataGridViewAutoSizeColumnMode]::Fill

    $dgvAdapters.Columns.Add($colDot) | Out-Null
    $dgvAdapters.Columns.Add($colRole) | Out-Null
    $dgvAdapters.Columns.Add($colAdapterIP) | Out-Null
    $dgvAdapters.Columns.Add($colAdapterStatus) | Out-Null
    $dgvAdapters.ReadOnly = $true

    # Populate adapter rows
    foreach ($adapter in $adapterData) {
        $dotChar = [char]0x25CF  # Unicode filled circle
        $rowIndex = $dgvAdapters.Rows.Add($dotChar, $adapter.Role, $adapter.IP, $adapter.Status)

        # Color the status dot based on adapter role color
        $dotColor = switch ($adapter.Color) {
            "Blue"   { $script:Theme.Accent }
            "Purple" { $script:Theme.Primary }
            "Green"  { $script:Theme.Success }
            "Cyan"   { $script:Theme.Accent }
            "Orange" { $script:Theme.Warning }
            "Gray"   { $script:Theme.TextMuted }
            default  { $script:Theme.TextSecondary }
        }
        $dgvAdapters.Rows[$rowIndex].Cells["StatusDot"].Style.ForeColor = $dotColor
        $dgvAdapters.Rows[$rowIndex].Cells["StatusDot"].Style.Font = New-Object System.Drawing.Font('Segoe UI', 12)

        # Color the status cell
        if ($adapter.Status -eq 'Up') {
            $dgvAdapters.Rows[$rowIndex].Cells["Status"].Style.ForeColor = $script:Theme.Success
        } elseif ($adapter.Status -eq 'N/A') {
            $dgvAdapters.Rows[$rowIndex].Cells["Status"].Style.ForeColor = $script:Theme.TextMuted
        } else {
            $dgvAdapters.Rows[$rowIndex].Cells["Status"].Style.ForeColor = $script:Theme.Error
        }
    }

    $networkCard.Controls.Add($dgvAdapters)

    # "Configure" button at the bottom of the network card
    $btnConfigureNetwork = New-StyledButton -Text "Configure" -X 15 -Y 258 `
        -Width 120 -Height 30 -IsPrimary
    $btnConfigureNetwork.Add_Click({
        try {
            Set-ActiveView -ViewName 'Network'
        } catch {
            Write-AppLog -Message "Dashboard: Navigate to Network failed - $_" -Level 'WARN'
        }
    })
    $networkCard.Controls.Add($btnConfigureNetwork)

    $scrollContainer.Controls.Add($networkCard)

    # --- Right Column: Recent Profiles ---
    $profilesCardX = 20 + $colWidth + $colSpacing  # 480
    $profilesCard = New-StyledCard -Title "Recent Profiles" -X $profilesCardX -Y $row2Y `
        -Width $colWidth -Height $colHeight

    # Fetch recent profiles
    $recentProfiles = Get-RecentProfilesList

    # Build profile list entries - each entry gets name, description, date, and a Quick Apply button
    $entryY = 48
    $entryHeight = 46
    $maxEntries = 5

    if ($recentProfiles.Count -eq 0) {
        $lblNoProfiles = New-StyledLabel -Text "No profiles found. Create one in the Profiles view." `
            -X 15 -Y $entryY -FontSize 9 -IsMuted -MaxWidth ($colWidth - 40)
        $profilesCard.Controls.Add($lblNoProfiles)
    } else {
        $entryIndex = 0
        foreach ($profile in $recentProfiles) {
            if ($entryIndex -ge $maxEntries) { break }

            $currentEntryY = $entryY + ($entryIndex * $entryHeight)

            # Profile name (bold)
            $profileName = if ($profile.Name) { $profile.Name } else { "Unnamed" }
            $lblName = New-StyledLabel -Text $profileName -X 15 -Y $currentEntryY -FontSize 10 -IsBold
            $profilesCard.Controls.Add($lblName)

            # Profile description and modified date (secondary text on the same line)
            $description = if ($profile.Description) { $profile.Description } else { "" }
            $modified = if ($profile.Modified) {
                try { (Get-Date $profile.Modified).ToString('MM/dd/yyyy') } catch { "" }
            } else { "" }
            $secondaryText = if ($description -and $modified) {
                "$description - $modified"
            } elseif ($description) {
                $description
            } elseif ($modified) {
                "Modified: $modified"
            } else {
                ""
            }

            if ($secondaryText) {
                $lblDesc = New-StyledLabel -Text $secondaryText -X 15 -Y ($currentEntryY + 20) `
                    -FontSize 8.5 -IsMuted -MaxWidth ($colWidth - 140)
                $profilesCard.Controls.Add($lblDesc)
            }

            # Quick Apply button for each profile entry
            $btnQuickApply = New-StyledButton -Text "Quick Apply" `
                -X ($colWidth - 115) -Y $currentEntryY -Width 95 -Height 28
            # Store the profile name in the button's Tag so the click handler can reference it
            $btnQuickApply.Tag = $profileName
            $btnQuickApply.Add_Click({
                $targetProfileName = $this.Tag
                try {
                    $profileToApply = Get-Profile -Name $targetProfileName
                    if ($profileToApply) {
                        # Apply-FullProfile shows its own confirmation dialog and results summary
                        $applyResult = Apply-FullProfile -Profile $profileToApply
                        if ($applyResult) {
                            Write-AppLog -Message "Dashboard: Quick Apply - profile '$targetProfileName' applied successfully" -Level 'INFO'
                        } else {
                            Write-AppLog -Message "Dashboard: Quick Apply - profile '$targetProfileName' had errors" -Level 'WARN'
                        }
                        # Always refresh to show updated status
                        Set-ActiveView -ViewName 'Dashboard'
                    } else {
                        [System.Windows.Forms.MessageBox]::Show(
                            "Profile '$targetProfileName' could not be loaded.",
                            "Error",
                            [System.Windows.Forms.MessageBoxButtons]::OK,
                            [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
                    }
                } catch {
                    [System.Windows.Forms.MessageBox]::Show(
                        "Error applying profile: $_",
                        "Error",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
                    Write-AppLog -Message "Dashboard: Quick Apply failed - $_" -Level 'ERROR'
                }
            })
            $profilesCard.Controls.Add($btnQuickApply)

            # Separator line between entries (except after the last one)
            if ($entryIndex -lt [Math]::Min($recentProfiles.Count, $maxEntries) - 1) {
                $separator = New-Object System.Windows.Forms.Panel
                $separator.Location = New-Object System.Drawing.Point(15, ($currentEntryY + $entryHeight - 4))
                $separator.Size = New-Object System.Drawing.Size(($colWidth - 30), 1)
                $separator.BackColor = $script:Theme.Border
                $profilesCard.Controls.Add($separator)
            }

            $entryIndex++
        }
    }

    # "Manage Profiles" button at the bottom of the profiles card
    $btnManageProfiles = New-StyledButton -Text "Manage Profiles" -X 15 -Y 258 `
        -Width 140 -Height 30 -IsPrimary
    $btnManageProfiles.Add_Click({
        try {
            Set-ActiveView -ViewName 'Profiles'
        } catch {
            Write-AppLog -Message "Dashboard: Navigate to Profiles failed - $_" -Level 'WARN'
        }
    })
    $profilesCard.Controls.Add($btnManageProfiles)

    $scrollContainer.Controls.Add($profilesCard)

    # ===================================================================
    # Row 3: Quick Actions
    # ===================================================================
    $row3Y = $row2Y + $colHeight + 20  # 520
    $actionsCard = New-StyledCard -Title "Quick Actions" -X 20 -Y $row3Y `
        -Width 920 -Height 80

    # Action buttons positioned in a horizontal row
    $actionBtnY = 40
    $actionBtnHeight = 30
    $actionBtnSpacing = 15

    # --- Button: Scan Network ---
    $btnActionScan = New-StyledButton -Text "Scan Network" -X 15 -Y $actionBtnY `
        -Width 140 -Height $actionBtnHeight -IsPrimary
    $btnActionScan.Add_Click({
        try {
            Set-ActiveView -ViewName 'Deploy'
        } catch {
            Write-AppLog -Message "Dashboard: Navigate to Deploy failed - $_" -Level 'WARN'
        }
    })
    $actionsCard.Controls.Add($btnActionScan)

    # --- Button: Capture Current Config ---
    $btnActionCapture = New-StyledButton -Text "Capture Current Config" `
        -X (15 + 140 + $actionBtnSpacing) -Y $actionBtnY `
        -Width 185 -Height $actionBtnHeight
    $btnActionCapture.Add_Click({
        try {
            $captureName = "Capture_$(Get-Date -Format 'yyyyMMdd_HHmmss')"
            $newProfile = New-DefaultProfile -Name $captureName -Description "Auto-captured from $(Get-ServerHostname)"

            # Attempt to populate adapter data from the live system
            try {
                $liveAdapters = Get-NetAdapter -ErrorAction Stop
                $liveIPs = Get-NetIPAddress -AddressFamily IPv4 -ErrorAction Stop
                $adapterIndex = 0
                foreach ($adapter in $liveAdapters | Select-Object -First 6) {
                    $ipInfo = $liveIPs | Where-Object { $_.InterfaceIndex -eq $adapter.InterfaceIndex } |
                        Select-Object -First 1
                    if ($newProfile.NetworkAdapters -and $adapterIndex -lt $newProfile.NetworkAdapters.Count) {
                        $newProfile.NetworkAdapters[$adapterIndex].InterfaceAlias = $adapter.Name
                        $newProfile.NetworkAdapters[$adapterIndex].IPAddress = if ($ipInfo) { $ipInfo.IPAddress } else { '' }
                        $prefixLen = if ($ipInfo) { $ipInfo.PrefixLength } else { 24 }
                        $newProfile.NetworkAdapters[$adapterIndex].SubnetMask = Convert-PrefixToSubnetMask -PrefixLength $prefixLen
                    }
                    $adapterIndex++
                }
            } catch {
                # Non-Windows or adapter query failed - profile keeps defaults
                Write-AppLog -Message "Dashboard: Adapter capture failed (expected on non-Windows) - $_" -Level 'DEBUG'
            }

            $newProfile.ServerName = Get-ServerHostname
            Save-Profile -Profile $newProfile

            [System.Windows.Forms.MessageBox]::Show(
                "Current configuration captured as '$captureName'.",
                "Capture Complete",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null

            Write-AppLog -Message "Dashboard: Configuration captured as '$captureName'" -Level 'INFO'
        } catch {
            [System.Windows.Forms.MessageBox]::Show(
                "Failed to capture configuration: $_",
                "Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
            Write-AppLog -Message "Dashboard: Capture failed - $_" -Level 'ERROR'
        }
    })
    $actionsCard.Controls.Add($btnActionCapture)

    # --- Button: Apply Last Profile ---
    $btnActionApplyLast = New-StyledButton -Text "Apply Last Profile" `
        -X (15 + 140 + $actionBtnSpacing + 185 + $actionBtnSpacing) -Y $actionBtnY `
        -Width 155 -Height $actionBtnHeight
    $btnActionApplyLast.Add_Click({
        $lastProfile = $script:AppState.LastAppliedProfile
        if ([string]::IsNullOrWhiteSpace($lastProfile)) {
            [System.Windows.Forms.MessageBox]::Show(
                "No profile has been applied yet. Use the Profiles view to select one.",
                "No Profile",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            return
        }

        try {
            $profileObj = Get-Profile -Name $lastProfile
            if ($profileObj) {
                # Apply-FullProfile shows its own confirmation dialog and results summary
                $applyResult = Apply-FullProfile -Profile $profileObj
                if ($applyResult) {
                    Write-AppLog -Message "Dashboard: Re-applied last profile '$lastProfile' successfully" -Level 'INFO'
                } else {
                    Write-AppLog -Message "Dashboard: Re-apply of '$lastProfile' had errors" -Level 'WARN'
                }
                # Always refresh to show updated status
                Set-ActiveView -ViewName 'Dashboard'
            } else {
                [System.Windows.Forms.MessageBox]::Show(
                    "Profile '$lastProfile' was not found. It may have been deleted.",
                    "Profile Not Found",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            }
        } catch {
            [System.Windows.Forms.MessageBox]::Show(
                "Error loading profile: $_",
                "Error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
    })
    $actionsCard.Controls.Add($btnActionApplyLast)

    # --- Button: Manage Shares ---
    $btnActionShares = New-StyledButton -Text "Manage Shares" `
        -X (15 + 140 + $actionBtnSpacing + 185 + $actionBtnSpacing + 155 + $actionBtnSpacing) -Y $actionBtnY `
        -Width 140 -Height $actionBtnHeight
    $btnActionShares.Add_Click({
        try {
            Set-ActiveView -ViewName 'SMB'
        } catch {
            Write-AppLog -Message "Dashboard: Navigate to SMB failed - $_" -Level 'WARN'
        }
    })
    $actionsCard.Controls.Add($btnActionShares)

    # --- Button: Open d3 Projects ---
    $btnActionOpenD3 = New-StyledButton -Text "Open d3 Projects" `
        -X (15 + 140 + $actionBtnSpacing + 185 + $actionBtnSpacing + 155 + $actionBtnSpacing + 140 + $actionBtnSpacing) -Y $actionBtnY `
        -Width 150 -Height $actionBtnHeight
    $btnActionOpenD3.Add_Click({
        # Common d3 project folder locations
        $d3Paths = @(
            "C:\Program Files\d3 Technologies",
            "C:\d3 Projects",
            "D:\d3 Projects",
            "$env:USERPROFILE\Documents\d3 Projects"
        )

        $foundPath = $null
        foreach ($path in $d3Paths) {
            if (Test-Path -Path $path -ErrorAction SilentlyContinue) {
                $foundPath = $path
                break
            }
        }

        if ($foundPath) {
            try {
                Start-Process "explorer.exe" -ArgumentList $foundPath -ErrorAction Stop
                Write-AppLog -Message "Dashboard: Opened d3 Projects folder at $foundPath" -Level 'INFO'
            } catch {
                [System.Windows.Forms.MessageBox]::Show(
                    "Failed to open folder: $_",
                    "Error",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
            }
        } else {
            [System.Windows.Forms.MessageBox]::Show(
                "Could not find a d3 Projects folder.`nSearched:`n$($d3Paths -join "`n")",
                "Folder Not Found",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
        }
    })
    $actionsCard.Controls.Add($btnActionOpenD3)

    $scrollContainer.Controls.Add($actionsCard)

    # ===================================================================
    # Row 4: Fleet Status
    # Shows live data from discovered disguise servers' REST APIs.
    # Only rendered when $script:AppState.LastScanResults contains servers
    # with IsDisguise = $true.
    # ===================================================================
    $fleetHeaderY = $row3Y + 80 + 20   # below Quick Actions card (height 80)

    $fleetSectionHeader = New-SectionHeader -Text "Fleet Status" -X 20 -Y $fleetHeaderY -Width 900
    $scrollContainer.Controls.Add($fleetSectionHeader)

    # Identify disguise servers from the last scan
    $disguiseServers = @()
    if ($script:AppState.LastScanResults) {
        $disguiseServers = @($script:AppState.LastScanResults | Where-Object { $_.IsDisguise -eq $true })
    }

    $fleetContentY = $fleetHeaderY + 50  # below the section header

    if ($disguiseServers.Count -eq 0) {
        # No servers known — show a helpful prompt
        $lblNoFleet = New-StyledLabel `
            -Text "No disguise servers discovered yet. Run a Scan Network or Auto-Discover (DNS-SD) from the Network Deploy view." `
            -X 20 -Y $fleetContentY -FontSize 9 -IsMuted -MaxWidth 880
        $scrollContainer.Controls.Add($lblNoFleet)

        # Scan Network shortcut button
        $btnGoScan = New-StyledButton -Text "Go to Network Deploy" `
            -X 20 -Y ($fleetContentY + 30) -Width 180 -Height 30
        $btnGoScan.Add_Click({
            try { Set-ActiveView -ViewName 'Deploy' } catch {
                Write-AppLog -Message "Dashboard: Navigate to Deploy failed - $_" -Level 'WARN'
            }
        })
        $scrollContainer.Controls.Add($btnGoScan)
    } else {
        # Status label shown while querying servers (updated by the Refresh logic)
        $lblFleetStatus = New-StyledLabel -Text "Loading fleet data..." `
            -X 20 -Y $fleetContentY -FontSize 9 -IsMuted
        $scrollContainer.Controls.Add($lblFleetStatus)

        # "Refresh Fleet" button — re-queries all known servers
        $btnRefreshFleet = New-StyledButton -Text ([char]0x21BB + " Refresh Fleet") `
            -X 820 -Y ($fleetHeaderY + 5) -Width 120 -Height 28
        $scrollContainer.Controls.Add($btnRefreshFleet)

        # Container panel for the server cards, laid out in a wrapping row
        $fleetCardsY = $fleetContentY + 22
        $fleetCardWidth  = 285
        $fleetCardHeight = 165
        $fleetCardSpacingX = 15
        $fleetCardSpacingY = 15
        $fleetCardsPerRow = 3
        $fleetStartX = 20

        # We keep a reference to each server card panel so we can rebuild them on refresh
        $fleetCardPanels = [System.Collections.ArrayList]::new()

        # Helper scriptblock: given a server descriptor, query its API and build/update the card
        $buildFleetCard = {
            param(
                [PSCustomObject]$ServerScanResult,
                [System.Windows.Forms.Panel]$CardPanel
            )

            # Determine which port to use — prefer discovered port 80, else fallback
            $apiPort = 80
            if ($ServerScanResult.Ports -and ($ServerScanResult.Ports -contains 80)) {
                $apiPort = 80
            } elseif ($ServerScanResult.Ports -and $ServerScanResult.Ports.Count -gt 0) {
                $apiPort = $ServerScanResult.Ports[0]
            }

            $details = Get-DisguiseServerDetails -IPAddress $ServerScanResult.IPAddress -Port $apiPort

            # Left accent border: green = API responsive, red = unreachable
            $accentColor = if ($details.APIReachable) { $script:Theme.Success } else { $script:Theme.Error }
            $existingAccent = $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetAccent' }
            if ($existingAccent) {
                $existingAccent.BackColor = $accentColor
            }

            # Update all the stat labels — they are stored by Name on the card panel
            $hostname = if ($ServerScanResult.Hostname -and $ServerScanResult.Hostname -ne '') {
                $ServerScanResult.Hostname
            } else {
                $ServerScanResult.IPAddress
            }

            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetHostname' } |
                ForEach-Object { $_.Text = $hostname }
            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetIP' } |
                ForEach-Object { $_.Text = $ServerScanResult.IPAddress }
            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetVersion' } |
                ForEach-Object { $_.Text = "Version: $($details.Version)" }

            $nicText = if ($details.NICEnabled -eq 'Unavailable') {
                "NICs: Unavailable"
            } elseif ($details.NICDisconnected -gt 0) {
                "NICs: $($details.NICEnabled) enabled ($($details.NICDisconnected) disconnected)"
            } else {
                "NICs: $($details.NICEnabled) enabled"
            }
            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetNIC' } |
                ForEach-Object {
                    $_.Text = $nicText
                    $_.ForeColor = if ($details.NICDisconnected -gt 0 -and $details.NICDisconnected -ne 'Unavailable') {
                        $script:Theme.Warning
                    } else {
                        $script:Theme.TextSecondary
                    }
                }

            $gpuText = if ($details.GPUOutputs -eq 'Unavailable') {
                "GPU Outputs: Unavailable"
            } else {
                "GPU Outputs: $($details.GPUOutputs) active"
            }
            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetGPU' } |
                ForEach-Object { $_.Text = $gpuText }

            $projText = if ($details.ProjectCount -eq 'Unavailable') {
                "Projects: Unavailable"
            } elseif ($details.ProjectCount -eq 0) {
                "Projects: None"
            } elseif ($details.ProjectNames.Count -gt 0) {
                $namePreview = ($details.ProjectNames | Select-Object -First 2) -join ', '
                if ($details.ProjectCount -gt 2) { $namePreview += "..." }
                "Projects: $($details.ProjectCount) ($namePreview)"
            } else {
                "Projects: $($details.ProjectCount)"
            }
            $CardPanel.Controls | Where-Object { $_.Name -eq 'FleetProj' } |
                ForEach-Object { $_.Text = $projText }

            $CardPanel.Refresh()
        }

        # Build an empty card shell for each disguise server (populated below / on refresh)
        $serverIndex = 0
        foreach ($srv in $disguiseServers) {
            $col = $serverIndex % $fleetCardsPerRow
            $row = [Math]::Floor($serverIndex / $fleetCardsPerRow)

            $cx = $fleetStartX + $col * ($fleetCardWidth + $fleetCardSpacingX)
            $cy = $fleetCardsY + $row * ($fleetCardHeight + $fleetCardSpacingY)

            # Use the raw Panel (not New-StyledCard) so we can paint our own accent border
            $srvCard = New-Object System.Windows.Forms.Panel
            $srvCard.Location = New-Object System.Drawing.Point($cx, $cy)
            $srvCard.Size = New-Object System.Drawing.Size($fleetCardWidth, $fleetCardHeight)
            $srvCard.BackColor = $script:Theme.CardBackground

            # Rounded border paint handler (matches New-StyledCard style)
            $srvCard.Add_Paint({
                param($sender, $e)
                $borderPen = New-Object System.Drawing.Pen($script:Theme.Border, 1)
                $rect = New-Object System.Drawing.Rectangle(0, 0, ($sender.Width - 1), ($sender.Height - 1))
                $e.Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
                $radius = 6
                $path = New-Object System.Drawing.Drawing2D.GraphicsPath
                $path.AddArc($rect.X, $rect.Y, $radius, $radius, 180, 90)
                $path.AddArc(($rect.Right - $radius), $rect.Y, $radius, $radius, 270, 90)
                $path.AddArc(($rect.Right - $radius), ($rect.Bottom - $radius), $radius, $radius, 0, 90)
                $path.AddArc($rect.X, ($rect.Bottom - $radius), $radius, $radius, 90, 90)
                $path.CloseFigure()
                $e.Graphics.DrawPath($borderPen, $path)
                $borderPen.Dispose()
                $path.Dispose()
            })

            # Left accent stripe (4px, colored by API reachability after query)
            $srvAccent = New-Object System.Windows.Forms.Panel
            $srvAccent.Name = 'FleetAccent'
            $srvAccent.Location = New-Object System.Drawing.Point(0, 0)
            $srvAccent.Size = New-Object System.Drawing.Size(4, $fleetCardHeight)
            $srvAccent.BackColor = $script:Theme.TextMuted  # neutral until queried
            $srvCard.Controls.Add($srvAccent)

            # Hostname label (bold, truncated)
            $lblSrvHostname = New-StyledLabel -Text "..." -X 12 -Y 12 -FontSize 10 -IsBold -MaxWidth ($fleetCardWidth - 20)
            $lblSrvHostname.Name = 'FleetHostname'
            $srvCard.Controls.Add($lblSrvHostname)

            # IP address subtitle
            $lblSrvIP = New-StyledLabel -Text $srv.IPAddress -X 12 -Y 32 -FontSize 8.5 -IsMuted
            $lblSrvIP.Name = 'FleetIP'
            $srvCard.Controls.Add($lblSrvIP)

            # Separator line
            $srvSep = New-Object System.Windows.Forms.Panel
            $srvSep.Location = New-Object System.Drawing.Point(12, 53)
            $srvSep.Size = New-Object System.Drawing.Size(($fleetCardWidth - 24), 1)
            $srvSep.BackColor = $script:Theme.Border
            $srvCard.Controls.Add($srvSep)

            # Version row
            $lblSrvVer = New-StyledLabel -Text "Version: ..." -X 12 -Y 62 -FontSize 8.5 -IsSecondary -MaxWidth ($fleetCardWidth - 20)
            $lblSrvVer.Name = 'FleetVersion'
            $srvCard.Controls.Add($lblSrvVer)

            # NIC row
            $lblSrvNIC = New-StyledLabel -Text "NICs: ..." -X 12 -Y 82 -FontSize 8.5 -IsSecondary -MaxWidth ($fleetCardWidth - 20)
            $lblSrvNIC.Name = 'FleetNIC'
            $srvCard.Controls.Add($lblSrvNIC)

            # GPU row
            $lblSrvGPU = New-StyledLabel -Text "GPU Outputs: ..." -X 12 -Y 102 -FontSize 8.5 -IsSecondary -MaxWidth ($fleetCardWidth - 20)
            $lblSrvGPU.Name = 'FleetGPU'
            $srvCard.Controls.Add($lblSrvGPU)

            # Projects row
            $lblSrvProj = New-StyledLabel -Text "Projects: ..." -X 12 -Y 122 -FontSize 8.5 -IsSecondary -MaxWidth ($fleetCardWidth - 20)
            $lblSrvProj.Name = 'FleetProj'
            $srvCard.Controls.Add($lblSrvProj)

            [void]$fleetCardPanels.Add([PSCustomObject]@{
                Panel  = $srvCard
                Server = $srv
            })

            $scrollContainer.Controls.Add($srvCard)
            $serverIndex++
        }

        # ---------------------------------------------------------------
        # Populate the cards — query servers sequentially with DoEvents()
        # so the UI remains responsive.
        # ---------------------------------------------------------------
        $totalFleet = $fleetCardPanels.Count
        $queryIndex = 0
        foreach ($cardEntry in $fleetCardPanels) {
            $queryIndex++
            $lblFleetStatus.Text = "Querying server $queryIndex of $totalFleet ($($cardEntry.Server.IPAddress))..."
            $lblFleetStatus.Refresh()
            [System.Windows.Forms.Application]::DoEvents()

            try {
                & $buildFleetCard -ServerScanResult $cardEntry.Server -CardPanel $cardEntry.Panel
            } catch {
                Write-AppLog -Message "Dashboard Fleet: Query failed for $($cardEntry.Server.IPAddress) - $_" -Level 'WARN'
            }

            [System.Windows.Forms.Application]::DoEvents()
        }

        $lblFleetStatus.Text = "Fleet status updated - $totalFleet server(s) queried"
        $lblFleetStatus.ForeColor = $script:Theme.Success

        # ---------------------------------------------------------------
        # Refresh Fleet click handler — re-runs the query loop
        # ---------------------------------------------------------------
        $btnRefreshFleet.Add_Click({
            $totalRefresh = $fleetCardPanels.Count
            $refreshIndex = 0
            foreach ($cardEntry in $fleetCardPanels) {
                $refreshIndex++
                $lblFleetStatus.Text = "Refreshing server $refreshIndex of $totalRefresh ($($cardEntry.Server.IPAddress))..."
                $lblFleetStatus.ForeColor = $script:Theme.Accent
                $lblFleetStatus.Refresh()
                [System.Windows.Forms.Application]::DoEvents()

                try {
                    & $buildFleetCard -ServerScanResult $cardEntry.Server -CardPanel $cardEntry.Panel
                } catch {
                    Write-AppLog -Message "Dashboard Fleet Refresh: failed for $($cardEntry.Server.IPAddress) - $_" -Level 'WARN'
                }

                [System.Windows.Forms.Application]::DoEvents()
            }

            $lblFleetStatus.Text = "Fleet status refreshed - $totalRefresh server(s)"
            $lblFleetStatus.ForeColor = $script:Theme.Success
        })
    }

    # ===================================================================
    # Add the scroll container to the content panel
    # ===================================================================
    $ContentPanel.Controls.Add($scrollContainer)
}

# ============================================================
# ENTRY POINT: DisguiseBuddy.ps1
# ============================================================
# DisguiseBuddy.ps1 - DISGUISE BUDDY Server Configuration Manager
# Main application entry point
# Version 1.0

#Requires -Version 5.1

# ============================================================================
# PRIVILEGE CHECK
# ============================================================================

# Check for Administrator privileges before proceeding
$currentPrincipal = [Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()
if (-not $currentPrincipal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Add-Type -AssemblyName System.Windows.Forms
    [System.Windows.Forms.MessageBox]::Show(
        "DISGUISE BUDDY requires Administrator privileges.`n`nPlease right-click PowerShell and choose 'Run as Administrator', then relaunch the application.",
        "Insufficient Privileges",
        [System.Windows.Forms.MessageBoxButtons]::OK,
        [System.Windows.Forms.MessageBoxIcon]::Error
    ) | Out-Null
    exit 1
}

# ============================================================================
# INITIALIZATION
# ============================================================================

# Load Windows Forms and Drawing assemblies
Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing

# Enable visual styles for modern look
[System.Windows.Forms.Application]::EnableVisualStyles()
[System.Windows.Forms.Application]::SetCompatibleTextRenderingDefault($false)

# Set DPI awareness for high-DPI displays
try {
    Add-Type -TypeDefinition @"
    using System;
    using System.Runtime.InteropServices;
    public class DPIAware {
        [DllImport("user32.dll")]
        public static extern bool SetProcessDPIAware();
    }
"@
    [DPIAware]::SetProcessDPIAware() | Out-Null
} catch {
    # Non-critical - continue without DPI awareness
}

# ============================================================================
# APPLICATION STATE (initialize before modules so they can reference it)
# ============================================================================

$script:AppState = @{
    LastAppliedProfile = ''
    LastScanResults    = @()
    CurrentView        = 'Dashboard'
}

# Holds references to action buttons exposed by the active view for keyboard shortcuts.
# New-DeployView populates this; Set-ActiveView clears it on view change.
$script:DeployViewActions = $null

# ============================================================================
# DOT-SOURCE MODULES (order matters: Theme -> UIComponents -> everything else)
# ============================================================================


# Foundation modules (must load first)

# Feature modules (order doesn't matter)

Write-AppLog -Message 'DISGUISE BUDDY starting up' -Level 'INFO'

# ============================================================================
# MAIN FORM
# ============================================================================

$mainForm = New-Object System.Windows.Forms.Form
$mainForm.Text = 'DISGUISE BUDDY - Server Configuration Manager'
$mainForm.Size = New-Object System.Drawing.Size(1280, 850)
$mainForm.MinimumSize = New-Object System.Drawing.Size(1100, 700)
$mainForm.StartPosition = [System.Windows.Forms.FormStartPosition]::CenterScreen
$mainForm.BackColor = $script:Theme.Background
$mainForm.ForeColor = $script:Theme.Text
$mainForm.Font = New-Object System.Drawing.Font('Segoe UI', 10)

# Remove default Windows title bar style for a cleaner look
$mainForm.FormBorderStyle = [System.Windows.Forms.FormBorderStyle]::Sizable

# Set application icon (if available)
try {
    $iconPath = Join-Path $PSScriptRoot 'icon.ico'
    if (Test-Path $iconPath) {
        $mainForm.Icon = New-Object System.Drawing.Icon($iconPath)
    }
} catch { }

# ============================================================================
# NAVIGATION SIDEBAR (Left Panel - 250px)
# ============================================================================

$navPanel = New-Object System.Windows.Forms.Panel
$navPanel.Dock = [System.Windows.Forms.DockStyle]::Left
$navPanel.Width = 250
$navPanel.BackColor = $script:Theme.NavBackground
$navPanel.Padding = New-Object System.Windows.Forms.Padding(0)

# --- App title/logo area at top of nav ---
$logoPanel = New-Object System.Windows.Forms.Panel
$logoPanel.Dock = [System.Windows.Forms.DockStyle]::Top
$logoPanel.Height = 80
$logoPanel.BackColor = $script:Theme.NavBackground
$logoPanel.Padding = New-Object System.Windows.Forms.Padding(15, 15, 15, 10)

$appTitleLabel = New-Object System.Windows.Forms.Label
$appTitleLabel.Text = 'DISGUISE BUDDY'
$appTitleLabel.Font = New-Object System.Drawing.Font('Segoe UI', 14, [System.Drawing.FontStyle]::Bold)
$appTitleLabel.ForeColor = $script:Theme.Primary
$appTitleLabel.Location = New-Object System.Drawing.Point(15, 15)
$appTitleLabel.AutoSize = $true
$logoPanel.Controls.Add($appTitleLabel)

$appSubtitleLabel = New-Object System.Windows.Forms.Label
$appSubtitleLabel.Text = 'Server Configuration Manager'
$appSubtitleLabel.Font = New-Object System.Drawing.Font('Segoe UI', 8.5)
$appSubtitleLabel.ForeColor = $script:Theme.TextMuted
$appSubtitleLabel.Location = New-Object System.Drawing.Point(15, 45)
$appSubtitleLabel.AutoSize = $true
$logoPanel.Controls.Add($appSubtitleLabel)

$navPanel.Controls.Add($logoPanel)

# --- Separator line under logo ---
$navSeparator = New-Object System.Windows.Forms.Panel
$navSeparator.Dock = [System.Windows.Forms.DockStyle]::Top
$navSeparator.Height = 1
$navSeparator.BackColor = $script:Theme.Border
$navPanel.Controls.Add($navSeparator)

# --- Navigation buttons container ---
$navButtonsPanel = New-Object System.Windows.Forms.Panel
$navButtonsPanel.Dock = [System.Windows.Forms.DockStyle]::Fill
$navButtonsPanel.BackColor = $script:Theme.NavBackground
$navButtonsPanel.Padding = New-Object System.Windows.Forms.Padding(0, 10, 0, 0)
$navPanel.Controls.Add($navButtonsPanel)

# --- Theme toggle at bottom of nav ---
$navBottomPanel = New-Object System.Windows.Forms.Panel
$navBottomPanel.Dock = [System.Windows.Forms.DockStyle]::Bottom
$navBottomPanel.Height = 90
$navBottomPanel.BackColor = $script:Theme.NavBackground

$themeToggleBtn = New-Object System.Windows.Forms.Button
$themeToggleBtn.Text = 'Toggle Theme'
$themeToggleBtn.Location = New-Object System.Drawing.Point(15, 10)
$themeToggleBtn.Size = New-Object System.Drawing.Size(220, 30)
$themeToggleBtn.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
$themeToggleBtn.FlatAppearance.BorderSize = 1
$themeToggleBtn.FlatAppearance.BorderColor = $script:Theme.Border
$themeToggleBtn.BackColor = $script:Theme.NavBackground
$themeToggleBtn.ForeColor = $script:Theme.TextMuted
$themeToggleBtn.Font = New-Object System.Drawing.Font('Segoe UI', 8.5)
$themeToggleBtn.Cursor = [System.Windows.Forms.Cursors]::Hand

$versionLabel = New-Object System.Windows.Forms.Label
$versionLabel.Text = 'v1.0 | disguise Configuration Tool'
$versionLabel.Font = New-Object System.Drawing.Font('Segoe UI', 7.5)
$versionLabel.ForeColor = $script:Theme.TextMuted
$versionLabel.Location = New-Object System.Drawing.Point(15, 50)
$versionLabel.AutoSize = $true

$navBottomPanel.Controls.Add($themeToggleBtn)
$navBottomPanel.Controls.Add($versionLabel)
$navPanel.Controls.Add($navBottomPanel)

# ============================================================================
# CONTENT PANEL (Right side - fills remaining space)
# ============================================================================

$contentPanel = New-Object System.Windows.Forms.Panel
$contentPanel.Dock = [System.Windows.Forms.DockStyle]::Fill
$contentPanel.BackColor = $script:Theme.Background
$contentPanel.Padding = New-Object System.Windows.Forms.Padding(20)

# ============================================================================
# NAVIGATION BUTTON CREATION
# ============================================================================

# Navigation item definitions: Name, DisplayText, Unicode symbol
# The & prefix enables Alt+letter WinForms access keys.
# Chosen accelerators (all unique): D, P, N, M, S, E
$navItems = @(
    @{ Name = 'Dashboard';      Display = '&Dashboard';          Symbol = [char]0x229E }  # ⊞ grid       | Alt+D
    @{ Name = 'Profiles';       Display = '&Profiles';           Symbol = [char]0x2261 }  # ≡ list       | Alt+P
    @{ Name = 'Network';        Display = '&Network Adapters';   Symbol = [char]0x2295 }  # ⊕ connection | Alt+N
    @{ Name = 'SMB';            Display = 'S&MB Sharing';        Symbol = [char]0x22A1 }  # ⊡ folder     | Alt+M
    @{ Name = 'ServerIdentity'; Display = '&Server Identity';    Symbol = [char]0x2299 }  # ⊙ server     | Alt+S
    @{ Name = 'Deploy';         Display = 'D&eploy';             Symbol = [char]0x21E2 }  # ⇢ deploy     | Alt+E
)

# Store nav buttons for state management
$script:NavButtons = @{}

# Function to create a navigation button
function New-NavButton {
    param(
        [string]$Name,
        [string]$DisplayText,
        [char]$Symbol,
        [int]$YPosition
    )

    $btn = New-Object System.Windows.Forms.Button
    $btn.Text = "  $Symbol  $DisplayText"
    $btn.TextAlign = [System.Drawing.ContentAlignment]::MiddleLeft
    $btn.Location = New-Object System.Drawing.Point(0, $YPosition)
    $btn.Size = New-Object System.Drawing.Size(250, 42)
    $btn.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
    $btn.FlatAppearance.BorderSize = 0
    $btn.FlatAppearance.MouseOverBackColor = $script:Theme.NavHover
    $btn.BackColor = $script:Theme.NavBackground
    $btn.ForeColor = $script:Theme.TextSecondary
    $btn.Font = New-Object System.Drawing.Font('Segoe UI', 10)
    $btn.Cursor = [System.Windows.Forms.Cursors]::Hand
    $btn.Tag = $Name

    # Hover effects
    $btn.Add_MouseEnter({
        if ($this.Tag -ne $script:AppState.CurrentView) {
            $this.BackColor = $script:Theme.NavHover
            $this.ForeColor = $script:Theme.Text
        }
    })
    $btn.Add_MouseLeave({
        if ($this.Tag -ne $script:AppState.CurrentView) {
            $this.BackColor = $script:Theme.NavBackground
            $this.ForeColor = $script:Theme.TextSecondary
        }
    })

    return $btn
}

# Create navigation buttons
$yPos = 5
foreach ($item in $navItems) {
    $navBtn = New-NavButton -Name $item.Name -DisplayText $item.Display -Symbol $item.Symbol -YPosition $yPos
    $script:NavButtons[$item.Name] = $navBtn
    $navButtonsPanel.Controls.Add($navBtn)
    $yPos += 44
}

# ============================================================================
# VIEW SWITCHING LOGIC
# ============================================================================

function Set-ActiveView {
    param([string]$ViewName)

    # Clear any view-specific action references before loading a new view
    $script:DeployViewActions = $null

    # Update visual state of nav buttons
    foreach ($key in $script:NavButtons.Keys) {
        $btn = $script:NavButtons[$key]
        if ($key -eq $ViewName) {
            # Active button styling
            $btn.BackColor = $script:Theme.NavActive
            $btn.ForeColor = [System.Drawing.Color]::White
            $btn.Font = New-Object System.Drawing.Font('Segoe UI', 10, [System.Drawing.FontStyle]::Bold)
        } else {
            # Inactive button styling
            $btn.BackColor = $script:Theme.NavBackground
            $btn.ForeColor = $script:Theme.TextSecondary
            $btn.Font = New-Object System.Drawing.Font('Segoe UI', 10)
        }
    }

    # Update state
    $script:AppState.CurrentView = $ViewName

    # Load the requested view into the content panel
    $contentPanel.SuspendLayout()
    $contentPanel.Controls.Clear()

    # Create an inner panel that respects padding
    $innerPanel = New-Object System.Windows.Forms.Panel
    $innerPanel.Dock = [System.Windows.Forms.DockStyle]::Fill
    $innerPanel.BackColor = $script:Theme.Background
    $innerPanel.AutoScroll = $true
    $contentPanel.Controls.Add($innerPanel)

    switch ($ViewName) {
        'Dashboard'      { New-DashboardView -ContentPanel $innerPanel }
        'Profiles'       { New-ProfilesView -ContentPanel $innerPanel }
        'Network'        { New-NetworkView -ContentPanel $innerPanel }
        'SMB'            { New-SMBView -ContentPanel $innerPanel }
        'ServerIdentity' { New-ServerIdentityView -ContentPanel $innerPanel }
        'Deploy'         { New-DeployView -ContentPanel $innerPanel }
    }

    $contentPanel.ResumeLayout()

    Write-AppLog -Message "Switched to view: $ViewName" -Level 'DEBUG'
}

# Wire up click events for each nav button
foreach ($key in $script:NavButtons.Keys) {
    $btn = $script:NavButtons[$key]
    $btn.Add_Click({
        Set-ActiveView -ViewName $this.Tag
    })
}

# ============================================================================
# THEME TOGGLE
# ============================================================================

$themeToggleBtn.Add_Click({
    if ($script:Theme -eq $script:DarkTheme) {
        Set-AppTheme -ThemeName 'Light'
    } else {
        Set-AppTheme -ThemeName 'Dark'
    }

    # Recursively update all controls in the form with new theme colors
    Update-ControlTheme -Control $mainForm

    # Re-apply nav-specific colors that Update-ControlTheme can't infer from Tags
    $navPanel.BackColor = $script:Theme.NavBackground
    $logoPanel.BackColor = $script:Theme.NavBackground
    $appTitleLabel.ForeColor = $script:Theme.Primary
    $appSubtitleLabel.ForeColor = $script:Theme.TextMuted
    $navSeparator.BackColor = $script:Theme.Border
    $navButtonsPanel.BackColor = $script:Theme.NavBackground
    $navBottomPanel.BackColor = $script:Theme.NavBackground
    $themeToggleBtn.BackColor = $script:Theme.NavBackground
    $themeToggleBtn.ForeColor = $script:Theme.TextMuted
    $themeToggleBtn.FlatAppearance.BorderColor = $script:Theme.Border
    $versionLabel.ForeColor = $script:Theme.TextMuted

    # Re-render current view to rebuild all content with new theme
    Set-ActiveView -ViewName $script:AppState.CurrentView

    Write-AppLog -Message "Theme toggled to: $(Get-AppThemeName)" -Level 'INFO'
})

# ============================================================================
# FORM ASSEMBLY
# ============================================================================

# Add panels to form (order matters for docking)
$mainForm.Controls.Add($contentPanel)  # Fill - must be added first
$mainForm.Controls.Add($navPanel)      # Left dock

# ============================================================================
# KEYBOARD SHORTCUTS
# ============================================================================

# Enable the form to intercept key events before child controls handle them
$mainForm.KeyPreview = $true

# Global key handler
# Ctrl+1..6  : navigate to views in order
# F5         : refresh/scan (scan if on Deploy view, otherwise reload current view)
# Ctrl+Enter : trigger deploy (Deploy view only)
# Escape     : close any open modal dialog
$mainForm.Add_KeyDown({
    param($sender, $e)

    $view = $script:AppState.CurrentView

    switch ($e.KeyCode) {

        # --- Ctrl+1 through Ctrl+6 : navigate to views ---
        ([System.Windows.Forms.Keys]::D1) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'Dashboard'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }
        ([System.Windows.Forms.Keys]::D2) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'Profiles'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }
        ([System.Windows.Forms.Keys]::D3) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'Network'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }
        ([System.Windows.Forms.Keys]::D4) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'SMB'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }
        ([System.Windows.Forms.Keys]::D5) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'ServerIdentity'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }
        ([System.Windows.Forms.Keys]::D6) {
            if ($e.Control) {
                Set-ActiveView -ViewName 'Deploy'
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }

        # --- F5 : scan (Deploy view) or refresh current view ---
        ([System.Windows.Forms.Keys]::F5) {
            if ($view -eq 'Deploy' -and $script:DeployViewActions -and $script:DeployViewActions.ScanButton -and $script:DeployViewActions.ScanButton.Enabled) {
                $script:DeployViewActions.ScanButton.PerformClick()
            } else {
                Set-ActiveView -ViewName $view
            }
            $e.Handled = $true
            $e.SuppressKeyPress = $true
        }

        # --- Ctrl+Enter : trigger deploy (Deploy view only) ---
        ([System.Windows.Forms.Keys]::Return) {
            if ($e.Control -and $view -eq 'Deploy' -and $script:DeployViewActions -and $script:DeployViewActions.DeployButton -and $script:DeployViewActions.DeployButton.Enabled) {
                $script:DeployViewActions.DeployButton.PerformClick()
                $e.Handled = $true
                $e.SuppressKeyPress = $true
            }
        }

        # --- Escape : close any open modal (SendKeys approach) ---
        ([System.Windows.Forms.Keys]::Escape) {
            # Let Escape propagate naturally — WinForms modal dialogs handle it
            # via their CancelButton or DialogResult. Nothing to do here unless
            # a non-standard popup is open.
        }
    }
})

# ============================================================================
# STARTUP
# ============================================================================

# Load saved theme preference (if any) before rendering the first view
Load-ThemePreference

# Apply loaded theme to all existing controls before the first view render
$mainForm.BackColor = $script:Theme.Background
$mainForm.ForeColor = $script:Theme.Text
$navPanel.BackColor = $script:Theme.NavBackground
$logoPanel.BackColor = $script:Theme.NavBackground
$appTitleLabel.ForeColor = $script:Theme.Primary
$appSubtitleLabel.ForeColor = $script:Theme.TextMuted
$navSeparator.BackColor = $script:Theme.Border
$navButtonsPanel.BackColor = $script:Theme.NavBackground
$navBottomPanel.BackColor = $script:Theme.NavBackground
$themeToggleBtn.BackColor = $script:Theme.NavBackground
$themeToggleBtn.ForeColor = $script:Theme.TextMuted
$themeToggleBtn.FlatAppearance.BorderColor = $script:Theme.Border
$versionLabel.ForeColor = $script:Theme.TextMuted
$contentPanel.BackColor = $script:Theme.Background

# Update nav buttons with loaded theme
foreach ($key in $script:NavButtons.Keys) {
    $btn = $script:NavButtons[$key]
    $btn.BackColor = $script:Theme.NavBackground
    $btn.ForeColor = $script:Theme.TextSecondary
    $btn.FlatAppearance.MouseOverBackColor = $script:Theme.NavHover
}

# Load default view
Set-ActiveView -ViewName 'Dashboard'

# Handle form closing
$mainForm.Add_FormClosing({
    Write-AppLog -Message 'DISGUISE BUDDY shutting down' -Level 'INFO'
})

# Handle resize for responsive layout
$mainForm.Add_Resize({
    # Re-render current view on significant resize
    if ($mainForm.WindowState -ne [System.Windows.Forms.FormWindowState]::Minimized) {
        # Views will auto-adjust via docking/anchoring
    }
})

Write-AppLog -Message 'DISGUISE BUDDY initialized successfully' -Level 'INFO'

# ============================================================================
# RUN APPLICATION
# ============================================================================

[System.Windows.Forms.Application]::Run($mainForm)
